INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('adam', 'Adam', 2024, 'completed', 0, 1, 2, '{"name":"Adam","slug":"adam","age":22,"diagnosis":"Cerebral Palsy, Hydrocephalus & mild intellectual disability","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2024,"status":"completed","bio":"Adam is a young adult who has defied the odds and turned his challenges into triumphs. Born with Hydrocephalus and cerebral palsy, Adam has never let his wheelchair-bound condition define him. Instead, he has embraced life with an unyielding spirit and an infectious zest.\n\nBilingual and highly active, Adam''s accomplishments are as diverse as they are impressive. He is a skilled horseback rider, a tennis player, a swimmer, and even a scuba diver. His determination and discipline have also earned him a green belt in martial arts. Adam''s academic journey is equally inspiring. He attended the IDEAL program at Georgia State University, where he successfully earned his degree. Today, he continues to contribute to the university community through his work at the Center for Leadership and Disabilities. \n\nBorn a twin, Adam''s radiant personality shines as brightly as the sun he loves so much. His exceptional social skills and his innate ability to uplift everyone around him make him a cherished presence. Adam is truly a blessing to those who know him, and his loved ones eagerly anticipate his continued success and the achievement of his goals.","quote":"\"His exceptional social skills and his innate ability to uplift everyone around him make him a cherished presence.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/adam/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/adam/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/adam/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/adam/photo-03