INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('aidan-and-brendan', 'Aidan & Brendan', 2022, 'completed', 0, 2, 1, '{"name":"Aidan & Brendan","slug":"aidan-and-brendan","age":15,"diagnosis":"Autism","roomTypes":["Dream Bedroom"],"year":2022,"status":"completed","bio":"\"Born at 28 weeks, the twins have differing degrees of Autism.\"\n\nIn addition to school and therapy, the boys enjoy traditional favorite past times. Aidan loves Pokemon, Toystory, and Minecraft. He loves learning about the weather; but, he finds great comfort in his favorite weighted blanket when thunderstorms roll around. Like so many teen boys, Brendan is a UGA fan, \"Go Dawgs!\" and loves to play golf. You can also find him enjoying the perennial favorites, Wheel of Fortune and Jeopardy, on evening TV. Both boys share in the excitement of Christmas as we all know Santa knows no age.\n\nA dream bedroom makeover will maximize the space and make it comfortable for young men -- Sunshine On A Ranney Day''s specialty.","quote":"\"Born at 28 weeks, the twins have differing degrees of Autism.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aidan-and-brendan/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aidan-and-brendan/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aidan-and-brendan/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aidan-and-brendan/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aidan-and-brendan/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aidan-and-brendan/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aidan-and-brendan/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aidan-and-brendan/photo-07/public","alt":""}],"photoCount":7,"videoUrl":"https://youtu.be/nJdRnGjQWT4","photographer":null,"partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/jc-logo-final/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/rooms-to-go/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/five-star-painting/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bin-there-dump-that/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/reliable-heatingair/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pear-tree-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/iframe-media/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"18fab7bbf2869fd41817bf81157d48e2","childCount":2,"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('aj', 'AJ', 2014, 'completed', 0, 1, 1, '{"name":"AJ","slug":"aj","year":2014,"status":"completed","bio":"Meet A.J. With a smile that will warm your heart, this young man is happy under almost any circumstance! He and his family have already overcome many challenges; but, will truly benefit from a remodel that will make their day to day routine a lot easier.   A.J. was diagnosed with Cerebral Palsy at an early age. His communication is very limited, but he enjoys listening to music.  His quality of life depends on therapeutic services and medical care including the administration of daily breathing treatments to manage his asthma.  He is unable to walk, stand or sit up on his own and requires significant assistance in every facet of his life.  However, A.J. and his family don’t let these obstacles get in their way!    Although A.J.’s room is average sized, he requires specialized equipment that takes up quite a bit of space, which leaves limited availability to maneuver his wheelchair.  His wheelchair cannot fit into the narrow bathroom and it is difficult for his parents to lift him into the tub comfortably.  Due to his fused spine, great care must be taken when lifting and supporting his fragile, lengthy body onto the toilet or into the tub.  This endeavor has been quite difficult for his adoptive parents Patricia (age 65) and Henry (age 70). Despite how strenuous this level of assistance is on them, they make sure his every need is met and treasure the opportunity to care for him.   Patricia and Henry have fostered ten children over the years and came to love and care for A.J. as an infant. He and his five siblings are the joy of their lives and they continue to dedicate themselves to making him shine and reach his maximum potential.   SOARD has partnered with Dream House for Kids to renovate the family’s home to make it easier to care for A.J. This remodel will provide them with a handicap accessible bathroom, a ramp from the kitchen to the living room to make mobility in this split level home easier, and new flooring in the kitchen and hallway that was damaged by his wheelchair.  In addition, A.J. will get his very own dream bedroom where he can play, listen to his music and smile!   Join us in sharing his special moment at the reveal of his newly remodeled home on February 1, 2014 in College Park, Georgia.","quote":"Meet A.J. With a smile that will warm your heart, this young man is happy under almost any circumstance! He and his family have already overcome many challenges; but, will truly benefit from a remodel that will make their day to day routine a lot easier.   A.J. was diagnosed with Cerebral Palsy at a","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aj/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aj/hero/public","alt":"AJ makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aj/photo-02/public","alt":"AJ makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aj/photo-03/public","alt":"AJ makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aj/photo-04/public","alt":"AJ makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aj/photo-05/public","alt":"AJ makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aj/photo-06/public","alt":"AJ makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/aj/photo-07/public","alt":"AJ makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/545ab68d-2c4c-4e34-be38-de3c0a7c1800/full","source":"wix-migration","wixNumber":10},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('alejandro', 'Alejandro', 2020, 'completed', 0, 1, 2, '{"name":"Alejandro","slug":"alejandro","age":15,"diagnosis":"Duchenne Muscular Dystrophy","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2020,"status":"completed","bio":"Having been diagnosed with Duchenne Muscular Dystrophy when he was six years old, he has been able to overcome many challenges.\n\nThere is no more deserving teen than Alejandro. He approaches all challenges with great effort and courage. Alejandro has been very cooperative with all of his treatments since day one as well as participating in various research and clinical trials to help the scientific community find treatments and better care for boys with Duchenne Muscular Dystrophy. At home, Alejandro likes to play video games with his brother and friends and loves movie nights with his family. Like most teens, he enjoys relaxing in his room, listening to music. He plans on going to college and getting a degree in Endangered Species Biology. \n\nA \"Dream Bedroom\" and an accessible bathroom will provide Alejandro with the independence teens crave and keep him motivated as he works toward his dream of becoming a scientist.","quote":"Having been diagnosed with Duchenne Muscular Dystrophy when he was six years old, he has been able to overcome many challenges.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alejandro/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alejandro/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alejandro/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alejandro/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alejandro/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alejandro/photo-05/publi