INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('amanda-caleb-and-isaac', 'Amanda, Caleb & Isaac', 2023, 'completed', 0, 3, 2, '{"name":"Amanda, Caleb & Isaac","slug":"amanda-caleb-and-isaac","age":10,"diagnosis":"Amanda","roomTypes":["Accessible Bathroom","Therapy Room"],"year":2023,"status":"completed","bio":"Amanda, Caleb & Isaac come from a family of eight! Sunshine on a Ranney Day''s plans to create an accessible bathroom and therapy room for them will impact all three in different and wonderful ways.\n\nAmanda is 19 years old and was born in China. She was born with spina bifida which causes her to be paralyzed from the waist down. She has been with her family since she was 13 years old and is such a joy! She uses a wheelchair and other medical equipment and has had many major surgeries since she''s been home. Amanda loves reading, anime, art and is very talented with drawing. She is also very excited to start her first job soon. A handicap accessible bathroom will be such a blessing to her!\n\nCaleb is 10 years old and was born with congenital CMV and calcifications on his brain. He was adopted at 4 weeks old and he is such a cutie pie. He has severe autism and loves to quote books, movies and especially nursery rhymes. Singing, swinging and swimming are his very favorite activities. Everyone who meets Caleb falls in love with him. He is funny, sweet and silly. He will enjoy a new playroom/therapy room so very much.\n\nIsaac is 10 and was born with Pallister Killian Syndrome which is a rare genetic disorder that affects the 12th chromosome. He was adopted at 5 months old when he was discharged from the NICU. He is blind, deaf and intellectually he is still their baby. He is an absolute JOY to his family. Isaac''s smile can melt a heart of stone! His laughter echoes through their home reminding his family that there is joy all around us if we just open the eyes of our hearts to see it! He loves swinging, lights, vibrating toys, and being held and tickled. He also utilizes a wheelchair and because of his size, an accessible shower is going to be the most amazing gift to him and to his parents. He will also love and enjoy the new therapy room!","quote":"\"Sunshine on a Ranney Day''s plans to create an accessible bathroom and therapy room for them will impact all three in different and wonderful ways.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amanda-caleb-and-isaac/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amanda-caleb-and-isaac/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amanda-caleb-and-isaac/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amanda-caleb-and-isaac/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amanda-caleb-and-isaac/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amanda-caleb-and-isaac/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amanda-caleb-and-isaac/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amanda-caleb-and-isaac/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amanda-caleb-and-isaac/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amanda-caleb-and-isaac/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amanda-caleb-and-isaac/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amanda-caleb-and-isaac/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amanda-caleb-and-isaac/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amanda-caleb-and-isaac/photo-13/public","alt":""},{"url":"https://imagedeliv