INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('amari', 'Amari', 2025, 'completed', 0, 1, 2, '{"name":"Amari","slug":"amari","age":10,"diagnosis":"Paralysis from waist down and amputation of leg","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2025,"status":"completed","bio":"Amari is a bright and energetic 10-year-old with a huge love for sports. He enjoys playing flag football, shooting hoops, watching WWE, and hanging out with friends in his neighborhood. His energy is contagious, and his competitive spirit lights up every field and court he''s on.\n\nOne morning on the way to school, what started as an ordinary drive turned into a moment that changed everything. A car traveling the wrong way struck Amari and his father head-on. The accident left Amari with serious injuries, including paralysis and the loss of his right leg. Since that day, Amari and his family have been adjusting to a new way of life as he learns to navigate the world in a wheelchair.\n\nSunshine on a Ranney Day is honored to be part of Amari''s journey. SOARD will transforming Amari''s home into a space that supports his growth and independence, complete with a wheelchair-accessible bathroom, widened doorways, and a dream bedroom. This renovation is more than construction, it''s the foundation for Amari''s continued growth, independence, and endless possibilities ahead.","quote":null,"heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amari/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amari/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amari/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amari/hero/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amari/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amari/photo-04/publi