INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('amir', 'Amir', 2021, 'completed', 0, 1, 2, '{"name":"Amir","slug":"amir","age":5,"diagnosis":"Ohtahara Syndrome (Epilepsy)","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2021,"status":"completed","bio":"He is non-verbal, non-mobile has respiratory problems, and vision limitations, and still requires the same care as any five-year-old.\n\nHe is non-verbal, non-mobile has respiratory problems, and vision limitations, and still requires the same care as any five-year-old. For most kids, bath time is bonding time and a relaxing way to end the day, but for Amir''s parents, it has become treacherous. It takes both parents to maneuver him safely from his chair to the tub, and bathroom use requires the removal of his permanent tracheostomy as well. Despite his limitations, Amir is able to attend school and uses switch devices to communicate. Due to his wheelchair and numerous medical devices, his current room and bathroom make day-to-day care a considerable struggle. \n\nA safe bathroom and a bedroom designed with Amir''s sensory requirements may be just the thing needed for him to end each day with a big smile.","quote":"He is non-verbal, non-mobile has respiratory problems, and vision limitations, and still requires the same care as any five-year-old.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amir/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amir/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amir/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amir/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amir/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amir/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt