INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('arion', 'Arion', 2020, 'completed', 0, 1, 2, '{"name":"Arion","slug":"arion","age":11,"diagnosis":"Cerebral Palsy, Visually Impaired","roomTypes":["Accessible Bathroom","Wheelchair Ramp"],"year":2020,"status":"completed","bio":"In addition to living with Cerebral Palsy, he has ROP, Retinopathy of prematurity, causing visual impairment.\n\nLike many families with pre-teens, Arion''s family is always \"running around,\" but instead of sports and scouts, his days include frequent visits to a GI Doctor, a lung doctor, a psychiatrist, an eye doctor, speech therapy, OT, PT, and Hippo Therapy. He also goes to school four days a week and receives some homebound services. When returning home, from a busy day, they are challenged with safely getting Arion up the step and into their home. Things are complicated, even further, when it is time to transfer Arion to a bath. The chair doesn''t fit through the bathroom door. Arion has grown to a size that makes transferring to their small tub dangerous for both him and his mom.\n\nArion loves music, and when someone sings to him, as well as cars and toys that make noise and music. A modified entry and an accessible bathroom will make for a safer home. It will reduce the risk of injury and eliminate physical stress on his parents and caregivers. With a better quality of life for the whole family there will be more time to sing and enjoy music with Arion.","quote":"In addition to living with Cerebral Palsy, he has ROP, Retinopathy of prematurity, causing visual impairment.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/arion/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/arion/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/arion/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/arion/photo-03/p