INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('axel', 'Axel', 2026, 'in-progress', 0, 1, 2, '{"name":"Axel","slug":"axel","age":11,"diagnosis":"Cerebral Palsy with Dystonia","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2026,"status":"in-progress","bio":"Born prematurely at just 28 weeks, Axel was later diagnosed with cerebral palsy with dystonia, a neurological movement disorder that causes painful, involuntary muscle contractions. These constant contractions make controlled movement extremely difficult and impact every aspect of his daily life. Axel lives with ongoing pain, and recently underwent major hip surgery that included the placement of a pump to deliver pain medication directly to the affected area, an important step in helping manage his discomfort. Axel''s parents work hard to take care of him, taking opposite shifts in the housekeeping department at Northside hospital, to make sure one is home with Axel at all times.\n\nBecause his bedroom and bathroom are not wheelchair accessible, Axel is unable to move independently within those spaces. As a result, he must sleep in his parents'' room, separated from his twin brother, Angelo, something that limits both his independence and their ability to simply be kids together.\n\nDespite these challenges, Axel is a bright and spirited pre-teen. He loves to sing, spin joyfully in his wheelchair, which he skillfully controls with his head, and watch HGTV. (He''ll quickly tell you he has strong opinions about good design!)","quote":null,"heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/axel/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jackson/photo-01/public","alt":""}],"photoCount":1,"videoUrl":null,"photographer":null,"partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/wyp/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('ayden', 'Ayden', 2017, 'completed', 0, 1, 1, '{"name":"Ayden","slug":"ayden","year":2017,"status":"completed","bio":"Sunshine on a Ranney Day is over the moon to be able to partner with Telemundo Atlanta for the 4th year to bring a very special boy a spectacular makeover!  This handsome ten-year old with the contagious, radiant smile is Ayden.  At birth he was a tiny bundle of joy who was developing as expected until April 22, 2007.  He was just five months old when he suffered an anoxic brain injury during a seizure in the early morning.  Ayden was transported to the hospital where he spent the next month.  This event changed his fate and his future.  Ayden was placed in an induced coma to decrease the constant seizure activity in his brain.  Due to the tragic neurological damage, he was left with permanent deficits including loss of all of his motor skills, cortical visual impairment and decreased muscle tone.  Despite this devastating experience and his physical limitations, he continues to inspire others and bring joy to this world.  Ayden has delightful spirit and he is enthusiastic when he is around others. He shows his happiness by laughing and making cheerful vocalizations.  Anyone who encounters him is affected by his beautiful light and cannot resist smiling back!  What a treasure. Ayden LOVES the ocean.  His family has taken him to Florida twice to swim with the Dolphins and it''s one of his favorite things to do.  The magic of the experience is uplifting and blissful. To accommodate Ayden’s growing needs and make caring for him easier, he received a dream bedroom and wheelchair accessible bathroom.  The design incorporated the things he loves most and spread a little sunshine throughout his home.  ","quote":"Sunshine on a Ranney Day is over the moon to be able to partner with Telemundo Atlanta for the 4th year to bring a very special boy a spectacular makeover!  This handsome ten-year old with the contagious, radiant smile is Ayden.  At birth he was a tiny bundle of joy who was developing as expected un","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/hero/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amir/photo-33/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ayden/photo-03/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-41/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/anna/hero/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sofia/hero/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/hero/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-42/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-46/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ayden/photo-13/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ayden/photo-14/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ayden/photo-15/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ayden/photo-16/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/angel/photo-61/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ayden/photo-18/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ayden/photo-19/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ayden/photo-20/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ayden/photo-21/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ayden/photo-22/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ayden/photo-23/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ayden/photo-24/public","alt":"Ayden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ayden/photo-25/public","alt":"Ayden makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/bfce39e9-d0ab-4ba4-160b-dfe733fa9600/full","source":"wix-migration","wixNumber":59},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('ben', 'Ben', 2017, 'completed', 0, 1, 2, '{"name":"Ben","slug":"ben","age":8,"diagnosis":"Myelomeningocele Spina Bifida, Club Foot, Congenital Verticle Talus","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2017,"status":"completed","bio":"Meet Ben, the beneficiary of the next SOARD dream room makeover.  He is quite a brilliant young man and incredibly handsome.  This remarkable young man is only 8 and regardless of the challenges he faces, he has accomplished many goals and acquired great talents that many of us as adults have still not attained.\n\nBen is the fourth child in the family.  He was born with Myelomeningocele, which is the most serious form of Spina Bifida. This is a rare birth defect in which the spinal cord and spinal canal do not fuse together or close before birth.  This defect leaves the space open with a thin membrane covering it and this sac contains cerebrospinal fluid.  This can lead to hydrocephalus as well.  Ben experienced this and required a shunt placed shortly after birth.  In addition to Myelomeningocele, Ben was born with a club foot and congenital vertical talus also known as rocker bottom foot.\n\nBen gets around in his wheelchair, which enhances his need for speed.  This speed racer is extremely adventurous, loves the great outdoors and enjoys exploring the world around him.\n\nHis differences do not create barriers he can''t overcome.  He loves to swim, water ski, snow ski, play wheelchair basketball, go hiking on his dad''s back and participate in  track and field events. Ben raced at the Track and Field Junior Nationals Competition this past summer.  Not only is he a sports champion, but also plays the piano and violin.  This second grader is exceptionally multitalented and has a great sense of humor, too.\n\nBen delights in telling jokes, dances to the Crazy Frog Pandora station, enjoys science experiments and reading, especially Encyclopedia Brown and fact books. He loves Geography and one day hopes to be a Biologist. \n\nThis young man exudes excellence and charm.  His determination and drive are rolling him toward a bright and esteemed future.  We are ecstatically working on his renovations and anxiously looking forward to seeing his bright smile!","quote":"\"He loves to swim, water ski, snow ski, play wheelchair basketball, go hiking on his dad''s back and participate in\\u00a0 track and field events.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-19/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-20/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-21/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-22/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-23/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-24/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-25/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-26/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-27/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-28/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ben/photo-29/public","alt":""}],"photoCount":29,"videoUrl":"https://youtu.be/sSlS_nIUoBg","photographer":"Niki Murphy Photography","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cambria/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/rooms-to-go/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/wall-nut-custom-wall-murals/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/atlas-disposal/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/interceramic/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/echols/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/reliable-heating-and-air/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/romo/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/atlanta-kitchen/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/niki-murphy-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/emma-and-oliver-interiors/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/acquisitions-interiors/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/heather-cook/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/laura-mosso/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/molly-tidwell/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/sara-hutto/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/oconee-printing/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/sherwin-williams-2000/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/mitchell-gold-bob-williams/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"ae74451b60a54d7428ed5fbbb62e9ad5","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('benjamin', 'Benjamin', 2017, 'completed', 0, 1, 1, '{"name":"Benjamin","slug":"benjamin","year":2017,"status":"completed","bio":"Meet Ben, the beneficiary of the next SOARD dream room makeover.  He is quite a brilliant young man and incredibly handsome.  This remarkable young man is only 8 and regardless of the challenges he faces, he has accomplished many goals and acquired great talents that many of us as adults have still not attained. Ben is the fourth child in the family.  He was born with Myelomeningocele, which is the most serious form of Spina Bifida. This is a rare birth defect in which the spinal cord and spinal canal do not fuse together or close before birth.  This defect leaves the space open with a thin membrane covering it and this sac contains cerebrospinal fluid.  This can lead to hydrocephalus as well.  Ben experienced this and required a shunt placed shortly after birth.  In addition to Myelomeningocele, Ben was born with a club foot and congenital vertical talus also known as rocker bottom foot. Ben gets around in his wheelchair, which enhances his need for speed.  This speed racer is extremely adventurous, loves the great outdoors and enjoys exploring the world around him.   His differences do not create barriers he can’t overcome.  He loves to swim, water ski, snow ski, play wheelchair basketball, go hiking on his dad’s back and participate in track and field events. Ben raced at the Track and Field Junior Nationals Competition this past summer.  Not only is he a sports champion, but also plays the piano and violin.  This second grader is exceptionally multitalented and has a great sense of humor, too. Ben delights in telling jokes, dances to the Crazy Frog Pandora station, enjoys science experiments and reading, especially Encyclopedia Brown and fact books. He loves Geography and one day hopes to be a Biologist. This young man exudes excellence and charm.  His determination and drive are rolling him toward a bright and esteemed future.  We ecstatically worked on his renovations and anxiously looked forward to seeing his bright smile!  What a great experience this was for Ben!  For the first time since he has lived in Atlanta, he was able to wash his hand all by himself and he''ll be able to learn to be more independent with his new zero curb shower.  Sunshine on a Ranney Day also got to stretch our creative legs by creating a fold out desk over his toilet so he can do his treatments and still conserve space.  We know that our our makeovers are life changing for so many families, but when the kids are excited to be able to do things that are taken for granted so often, well, that''s why we''re in this business!!  We hope that Ben gains the Independence he longs for and we just know he''ll continue to be a great ray of sunshine to all he meets","quote":"Meet Ben, the beneficiary of the next SOARD dream room makeover.  He is quite a brilliant young man and incredibly handsome.  This remarkable young man is only 8 and regardless of the challenges he faces, he has accomplished many goals and acquired great talents that many of us as adults have still ","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/hero/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amir/photo-33/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/grace/hero/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zoe/hero/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-42/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-09/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-10/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-11/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-12/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-13/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-14/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-15/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-16/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-17/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-48/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/angel/photo-61/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-20/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-21/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-22/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-23/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-24/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-25/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-26/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-27/public","alt":"Benjamin makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/benjamin/photo-28/public","alt":"Benjamin makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/bfce39e9-d0ab-4ba4-160b-dfe733fa9600/full","source":"wix-migration","wixNumber":67},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('bennett-and-lacey', 'Bennett & Lacey', 2019, 'completed', 0, 2, 2, '{"name":"Bennett & Lacey","slug":"bennett-and-lacey","age":6,"diagnosis":"Joubert''s Syndrome","roomTypes":["Chair Lift","Therapy Room"],"year":2019,"status":"completed","bio":"Joubert Syndrome is a neurogenetic disorder characterized by low muscle tone, impaired coordination, developmental disability, abnormal breathing pattern, abnormal eye movements, and a distinctive brain malformation.\n\nAs time passed, Bennett did grow stronger, both physically and mentally despite daily challenges and numerous surgeries and set- backs. His incredible personality began to develop as well. From early on he was loving, caring, happy and brightened whatever room he was in. Lacey was born on January 18, 2013, almost thirteen years after Bennett. Fortunately, her stay in the NICU was only a week. Lacey, also diagnosed with Joubert Syndrome, has faced many of the same struggles as Bennett including a fragile infancy full of sleepless nights; but, generally her health has been better than his was to this point. She still has similar physical challenges - requiring assistance with daily activities including walking. Unlike Bennett, she is non-verbal, causing deep frustration for her. Bennett is now 19, a rising Senior at Roswell High School. He loves to be the life of the party! Bennett is extremely active in North Fulton Young Life, sings the National Anthem at Special Olympics annually, loves music and is working towards becoming a playwright. Lacey is 6 years old and a rising First Grader at Mimosa Elementary. She is creative with an innate sense of humor. She has developed a love for entertainment, has watched \"The Greatest Showman\" so many times that practically the entire family knows all the lines. She gets around her iPad like a pro, making her own movies, playing music and even FaceTiming friends (without her parents'' knowledge!) Lacey especially loves dance. It''s a part of her. She is a student at Atlanta Dance Central and excels in their adaptive dance program. Sunshine on a Ranney Day is excited to build an In-Home Therapy Room for Bennett & Lacey! On average, this family attends 7 therapy sessions and 2 doctors'' appointments each week. Our hope is that through access to a therapy room in their home, Bennett and Lacey will continue to grow stronger and accomplish more each day!","quote":"Joubert Syndrome is a neurogenetic disorder characterized by low muscle tone, impaired coordination, developmental disability, abnormal breathing pattern, abnormal eye movements, and a distinctive brain malformation.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bennett-and-lacey/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bennett-and-lacey/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bennett-and-lacey/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bennett-and-lacey/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bennett-and-lacey/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bennett-and-lacey/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bennett-and-lacey/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bennett-and-lacey/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bennett-and-lacey/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bennett-and-lacey/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bennett-and-lacey/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bennett-and-lacey/photo-11/public","alt":