gedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/jackson-healthcare/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/finlistics-2024/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/mohawk/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/reliable-heatingair/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/signarama/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/rooms-to-go/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/101-mobility/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nicole-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/jumptastic/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cnc-chattahoochee-nature-center/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/brusters/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"_migration":{"scrapedAt":"2026-03-06T13:32:09.454Z","source":"wordpress-xml-export","wpPostDate":"2021-06-26 13:59:28","wpCategories":["Meet the Kids"],"wpTags":["2019","Chair Lift","Therapy Room"],"thumbnailId":1192,"needsReview":[],"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/b2d26427-df22-4d77-15fc-38b53c9a2500/full"},"streamVideoId":"9979f4233c199c87af231903e2fec945","childCount":2,"roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('bobby', 'Bobby', 2015, 'completed', 0, 1, 1, '{"name":"Bobby","slug":"bobby","year":2015,"status":"completed","bio":"This handsome young man is 14-year old Bobby Hill.  He is very social and like most boys his age, loves playing sports!  This sports fanatic is also a math whiz and loves being part of the action at school.  However, last March a life changing event has kept him from doing what he loves.   Bobby was born with Spina Bifida and Hydrocephalous.  He has had over twenty surgeries with eight of those completed by the time he was two years old.  He has always been in a manual wheelchair until this year when he had to get a motorized chair with special seating due to his physical decline. Despite his disabilities, he and his family have strived to enjoy the most enriching and normal life possible.  Last March, he underwent neurosurgery and shortly after developed significant respiratory distress.  He suffered anoxic brain injury that originally left him so weak he had to relearn how to move his arms and legs.  He still can''t swallow safely or protect his airway so he has a tracheostomy.  He is currently receiving speech-language pathology services to help him regain use of his facial muscles and tongue.  Bobby now requires nursing services throughout the day and 24-hour care and supervision as he can''t be left alone at all.  He has also endured several falls, since he thinks he can still do everything he used to be able to.     Prior to March 2014, Bobby was extremely active.  He misses rock climbing, sled ice hockey, swimming, going to the beach and having campfires by his tree house.  He also misses riding his pony named Chocolate Chips every Saturday at the Therapeutic Riding Center.     Although his road to recovery has been long and challenging, he keeps charging on in therapy with hopes of a solid recovery and returning to many of his favorite activities. Sunshine on a Ranney Day wants to help him in his journey with renovations that will make the daily routine easier for him and his family.  We are going to widen their doorways and install new flooring to make it easier for him to use his motorized wheelchair throughout the home.  In addition, we will renovate two bedrooms to create a therapy suite large enough for all of his equipment with seating room for guests and a room with a sleeper sofa where one parent can rest while they take care of him.  We hope you will join us in supporting him at the big reveal in Eatonton, GA at 5pm on Friday April 3rd!","quote":"This handsome young man is 14-year old Bobby Hill.  He is very social and like most boys his age, loves playing sports!  This sports fanatic is also a math whiz and loves being part of the action at school.  However, last March a life changing event has kept him from doing what he loves.   Bobby was","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/hero/public","alt":"Bobby makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Bobby makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-46/public","alt":"Bobby makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/photo-04/public","alt":"Bobby makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/photo-05/public","alt":"Bobby makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/photo-06/public","alt":"Bobby makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/photo-07/public","alt":"Bobby makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/photo-08/public","alt":"Bobby makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/photo-09/public","alt":"Bobby makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/photo-10/public","alt":"Bobby makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/photo-11/public","alt":"Bobby makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/photo-12/public","alt":"Bobby makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/photo-13/public","alt":"Bobby makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/photo-14/public","alt":"Bobby makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/9bef27d9-3c95-4c26-00a3-30c70d577c00/full","source":"wix-migration","wixNumber":24},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('braeden', 'Braeden', 2015, 'completed', 0, 1, 1, '{"name":"Braeden","slug":"braeden","year":2015,"status":"completed","bio":"We’d like to introduce Princess Peyton.  This precious diva will soon be getting a room makeover fit for royalty.  This project is especially exciting because TLC’s Say Yes to the Dress Atlanta co-stars Lori and Monte will be designing her room!  It is a perfect match as this little princess has a passion for fashion and all things a Ranney Day wants to transform his room into a haven of hope where he can tumble and play safely.  This beautiful six-year old faces many daily challenges. Born with Pitt-Hopkins Syndrome, Epilepsy and Pervasive Developmental Disorder, he endures chronic gastrointestinal pain, seizures and developmental delays in cognition and physical performance.  Braeden has very little awareness of his body and surroundings with no protective instincts.   This along with anomalies of the feet make him prone to falling and difficult to keep safe at home. He is growing rapidly and attending therapy five times per week to achieve his goals. As he excels, he becomes increasingly more mobile.  With the help of a physical therapist and specialized braces with AFOs, he is learning to walk and desires more freedom and independence.   SOARD plans to remodel his room with strategic environmental modifications so he cannot pull on anything that will lead to falls.  In addition, the room will be padded to reduce injuries from loss of balance during exploration and play.  In addition, to help him get around the home independently while remaining safe, rails will be added to the walls leading to the stairs and between the kitchen and living room where he plays with his younger siblings, Molly and Reed.  We will be adding Mohawk SmartStrand carpet to the living room as well to make falls safer and a gate between the living room and kitchen to keep him safe from accidents.  Brae and Molly are really excited because one of their favorite things to do is chase each other around the living room.  This daily ritual of sweet sibling bonding is going to get a whole lot sweeter.  We can’t wait to see them giggle, laugh and dash around the new room together!   The Spirit of life organization was started in memory of our brother, Tommy Meo Jr., who was tragically taken from us at age 12 in September 2000.  Tommy has taught us that a lifetime is not measured by years, but by the amount of lives you have touched within the years you are here. We have dedicated a part of our lives to Tommy and through this, we strive to help others in his name. We want to continue to introduce the world to our brother, and for such beautiful reasons. Each year, after our main Walkathon fundraiser, we select an organization to donate to that we feel Tommy would be proud of. From the minute we found out about SOARD, we knew there couldn’t have been a more perfect match for us! Tommy would be honored to have the opportunity to sponsor a SOARD make- over for Braeden in his name .","quote":"We’d like to introduce Princess Peyton.  This precious diva will soon be getting a room makeover fit for royalty.  This project is especially exciting because TLC’s Say Yes to the Dress Atlanta co-stars Lori and Monte will be designing her room!  It is a perfect match as this little princess has a p","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braeden/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braeden/hero/public","alt":"Braeden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-43/public","alt":"Braeden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Braeden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braeden/photo-04/public","alt":"Braeden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braeden/photo-05/public","alt":"Braeden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braeden/photo-06/public","alt":"Braeden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braeden/photo-07/public","alt":"Braeden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braeden/photo-08/public","alt":"Braeden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braeden/photo-09/public","alt":"Braeden makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braeden/photo-10/public","alt":"Braeden makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/5f24ada7-6422-413c-c186-ee8dc02c6a00/full","source":"wix-migration","wixNumber":32},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('braxton', 'Braxton', 2022, 'completed', 0, 1, 2, '{"name":"Braxton","slug":"braxton","age":12,"diagnosis":"Spina Bifida Lipomyelomeningocele","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2022,"status":"completed","bio":"Braxton is 13 years old and the oldest of 3, he''s a big brother to Wyatt and Landry.  On most days, you can find him playing basketball in the driveway, gaming on the Xbox, or begging his mom to take him to the Lego store.  Braxton was born with Spina Bifida/Lipomyelomeningocele and has endured over 14 surgeries to date at Children''s Healthcare of Atlanta.  Braxton attends Veritas Classical Schools which is a home school hybrid.  This allows Braxton''s schedule to be more flexible when medical appointments, therapies, and surgeries arise.  Although ambulatory, Braxton''s mobility has lessened over the years and he''s relying more on his wheelchair and other assistive devices to accomplish daily activities.\n\nBraxton sometimes struggles physically since he is unable to run and walk like most kids his age but that has not slowed him down!  Braxton is the athlete of his family, playing both wheelchair basketball and competing in adaptive track and field for BlazeSports.  He would actually like to participate in ALL adaptive sports, but he would need his own chauffer.  On the basketball court, #5 plays with his whole heart and fierce determination!  Braxton recently made the Prep All-Tournament Team at the NWBA Nationals in 2022.  He hopes to play wheelchair basketball at the collegiate level as well as dreams to make Team USA one day.   On the track, he is a lover of field events and broke the national record for shotput in 2019.  Braxton is also an avid member of Scouts in Troop 1459 and is on track to earn his Eagle Scout Ranking in the future. He recently went on a 4-day adventure to Cumberland Island where he was able to hike over 20 miles with his troop in his Grit Freedom Chair.   Braxton is also a LEGO MANIAC and has thousands and thousands in his room!  He is very creative and has an 8-foot table housing a giant city that he has designed and continuously recreates all himself. He is an amazing artist as well and loves to veg out and play video games with his brother and friends. Braxton is active in his church youth group at North Point Community Church and is surrounded by amazing leaders and friends.  \n\nBraxton''s family calls him Braxton the Brave as he inspires his family everyday through the path that God has laid out before him.  Braxton and his family are so excited about his bedroom and bathroom accessible makeover.  Gaining that extra independence will be a game changer as well as make each day brighter!","quote":"\"He is very creative and has an 8-foot table housing a giant city that he has designed and continuously recreates all himself.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-19/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-20/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braxton/photo-21/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-32/public","alt":""}],"photoCount":22,"videoUrl":"https://www.youtube.com/watch?v=6MBQRphzkrw","photographer":"Niki Murphy Photography","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/jackson-healthcare/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/means-and-carney/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/mohawk/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/american-signature-furniture/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/interceramic/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/builders-cabinet-company/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/asv-productions/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cambria/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cr-construction-v2/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/echols/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/delta-faucet/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pulleyassociates/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/devore-johnson/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/tko-plumbing-2023/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bin-there-dump-that/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/niki-murphy-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"405144da9b63ad493bcc613036ae0e4a","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('breanna', 'Breanna', 2018, 'completed', 0, 1, 1, '{"name":"Breanna","slug":"breanna","age":11,"diagnosis":"Cystic Fibrosis","roomTypes":["Dream Bedroom"],"year":2018,"status":"completed","bio":"Even before she was conceived, her parents prayed for and anticipated the arrival of a sweet baby girl. Their wish was that one day they would be blessed with a little girl and her name would be Breanna Noel Blackburn. The name Breanna means \"to be strong\" and Noel means \"to be born\" so it was perfectly fitting.  Little did they know how fitting it would be. \n\n \n\nBreanna''s parents were thrilled when they found out they were expecting.  Knowing that there was a history of cystic fibrosis in the family, they made sure to take precautions and be prepared.  At twelve weeks gestation they had genetic testing done and it revealed that Breanna did in fact have Cystic Fibrosis.  Although they were prepared, it was still heartbreaking news. Cystic fibrosis is a genetic lung disease that causes thick sticky mucus to build up in the lungs, digestive tract and other parts of the body making it difficult to breathe.  It can also affect other organs.\n\n \n\nAt birth, Breanna needed enzymes to help her digest her food as she could not tolerate the fat in the milk.  This caused her to cry incessantly from the unbearable pain it caused her. Thankfully the CF Center was prepared and got her on the medication she needed to be able to digest it properly and what a difference it made! She went from crying non stop from sunup to sundown to eating and napping like a happy little baby.\n\nLife with cystic fibrosis hasn''t been easy.  Breanna has endured many admissions to Children''s Hospital of Atlanta over the years since she was born to treat lung exacerbations, chronic sinusitis infections, endure seven surgeries on her sinuses alone, removing polyps and infection.  A typical hospital stay for Breanna includes a strict schedule of respiratory therapy, IV medications and physical therapy.  Physical therapy in the hospital gym is a crucial part of her recovery as the more active she is the more clear she can keep her lungs which helps her to regain strength.  In addition to the typical symptoms that come with CF, Breanna suffers significant joint and muscle pain on a daily basis.  The pain is so intense that it nearly cripples her at times.  On a daily basis, Breanna requires twenty pills and two treatments that include three inhaled antibiotics and percussion therapy to clear her airway. Despite this, she does not let CF define her or places limits on what she can achieve.\n\n \n\nBreanna loves the ocean!  She feels like she can breathe better when she is near it.  The sea can be beautifully calming, yet invigorating.  Breanna feels more at peace by the ocean and if she had her way, she''d be a mermaid.  Swimming is also a form of therapy for Breanna as it feels really good on her joints and muscles.  There is nothing more special than nightly walks on the beach, watching her sing and dance along the shoreline.  For those few moments, there is not a care in the world.  Breanna and her family treasure those moments deeply wishing they could last forever.\n\n \n\nWhen she can''t be near the shore Breanna loves to be outside in nature.  She has a huge heart for animals and her greatest wish since she was four years old is to be a veterinarian when she grows up.  She dreams of being able to save every hurt or injured creature in the world.  Hopes and dreams don''t stop because of CF, it just makes everything in her world much more important.  Breanna''s family finds new hope on the horizon as there is a new medication that has recently been approved for Breanna''s age group by the FDA and they expect that it will do great things for Breanna!","quote":"\"Breanna feels more at peace by the ocean and if she had her way, she''d be a mermaid.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-40/public","alt":"Breanna makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS