INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('briana-2016', 'Briana', 2016, 'completed', 0, 1, 1, '{"name":"Briana","slug":"briana-2016","year":2016,"status":"completed","bio":"For those of you who have followed Sunshine on a Ranney Day for a while, you may remember this beautiful little lady, Briana! She is one strong girl, who has made miraculous gains since we last featured her in 2013.  Briana was four years old when a tragic accident left her in critical condition with paralysis. Doctors believed that she would never walk again. She was relying on machine to keep her alive; left limp with serious injuries to her brain and spinal cord.   The accident was heartbreaking for all involved. Briana was riding in her family''s car when it was hit head-on by teenagers driving their father''s Corvette. Both teens were killed instantly.    Briana''s therapy and recovery have been long and challenging, but she has made incredible progress. Her family and therapists have continued to work diligently, toward her goals, never losing hope. They have faith that she will defy all odds and indeed will walk again.  Back in 2013, SOARD was able to help Briana and her family by transforming their garage into a dreamy bedroom with a fully accessible bathroom and wheelchair ramp.  Briana has soared since then, attaining many milestones and regaining strength, including feeling in her feet-a hopeful sign that she will soon be walking again. Unfortunately, The Hudson''s lost their home to an aggressive fire. The flames destroyed it along with Briana''s wheelchair and therapy equipment.  Although another devastating loss, Briana and her family survived.  Another miracle!  Due to the support of our donors and business partners, SOARD is was blessed to be able to step in again providing her with another beautiful dream room in her newly rebuilt home.  It was an amazing feeling getting her back in her own room, and back to working toward her goals! Her dreams are soon to come into fruition as she is sure to exceed the doctors'' expectations. ","quote":"For those of you who have followed Sunshine on a Ranney Day for a while, you may remember this beautiful little lady, Briana! She is one strong girl, who has made miraculous gains since we last featured her in 2013.  Briana was four years old when a tragic accident left her in critical condition wit","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zoe/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zoe/hero/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-43/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana-2016/photo-04/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana-2016/photo-05/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana-2016/photo-06/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana-2016/photo-07/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana-2016/photo-08/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana-2016/photo-09/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana-2016/photo-10/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana-2016/photo-11/public","alt":"Briana makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/ccf79ea1-73b1-4aae-74b7-d03f7c565800/full","source":"wix-migration","wixNumber":49},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('briana', 'Briana', 2013, 'completed', 0, 1, 1, '{"name":"Briana","slug":"briana","year":2013,"status":"completed","bio":"Briana Hudson was riding in her family''s car when it was hit head-on by teenagers driving their father''s Corvette. Both teens were killed. Briana was 4 years old at the time.   Her heart stopped at one point and she received serious injuries to her brain and spinal cord.   Her mother, Denise Robins Hudson, says it was difficult to see her daughter in the ICU. &quot;She was hooked up to all the machines and just lying there,&quot; Robins Hudson said. Doctors said the once active little girl would probably never be able to walk. Briana''s grandmother said the family vowed to do all they could. &quot;It was like, ''Oh no. She''s going to walk again. We have faith,''&quot; Margie Robins said. They had to dig deep to hold on to that faith. Briana''s condition was critical. &quot;Briana couldn''t even hold her head up. She was just very limp,&quot; Robins Hudson said. From Children''s Healthcare of Atlanta, she traveled to a rehab hospital in Maryland.   Briana''s family and therapists have never given up, and they said neither has Briana. &quot;Just seeing Briana say, ''God is making me well,''&quot; is a blessing.   Briana was sleeping in her parents room which was the only bedroom on the main floor.  Sunshine on a Ranney Day went in and renovated their garage into Briana''s very own dream bedroom on the main level; and, also gave her a handicap accessible bathroom and wheelchair ramp.     Special THANKS to Sgt. Buddy Mays who was our special project manager.  Buddy was riding in the gunners’ turret of an armored Humvee, returning from a mission September 1, 2005, in Mahmuiyah, Iraq that traveled over a drain culvert when an IED detonated throwing him 40 feet in the air. Two members from his unit were killed from the explosion, two others seriously injured and Buddy Mays suffered severe spinal cord injuries that left him a paraplegic.  Buddy has been a huge mentor to Briana since her accident and a major part of how we were able to do so much for her:) God Bless America!","quote":"Briana Hudson was riding in her family''s car when it was hit head-on by teenagers driving their father''s Corvette. Both teens were killed. Briana was 4 years old at the time.   Her heart stopped at one point and she received serious injuries to her brain and spinal cord.   Her mother, Denise Robins ","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana/hero/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana/photo-02/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana/photo-03/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana/photo-04/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana/photo-05/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana/photo-06/public","alt":"Briana makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/briana/photo-07/public","alt":"Briana makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/063564a5-13d2-4b9e-54d0-e6120db96000/full","source":"wix-migration","wixNumber":8},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('brianna', 'Brianna', 2022, 'completed', 0, 1, 2, '{"name":"Brianna","slug":"brianna","age":18,"diagnosis":"Cerebral Palsy, Brain Damage, Epilepsy","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2022,"status":"completed","bio":"Brianna \\u201cBreezy\\u201d was born on June 4, 2004.  During birth, Breezy experienced complications causing brain damage and she received a later diagnosis of cerebral palsy and epilepsy.  Breezy continues to defy odds; the doctors did not expect Breezy to live to see her first Christmas and now she is 17 years old!  Breezy has a love for music and being outdoors. She comes from a musically talented family and attends a church that has many different types of instruments.  Breezy enjoys attention and interaction with people from reading a book to simply holding hands.\n\nBreezy is nonverbal and wheelchair dependent.  Breezy has faced so many challenges throughout her 17 years of life and proves what love, prayer, and faith can do.  Breezy lights up a room with her beautiful blue eyes and contagious smile.  She continues to amaze and capture the hearts of her family, friends, church family, and community.  \n\nBreezy is fully dependent on her family to take care of her everyday needs and an accessible bathroom and bedroom renovation will make life easier for the whole family.","quote":"\"Breezy lights up a room with her beautiful blue eyes and contagious smile.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brianna/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brianna/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brianna/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brianna/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brianna/photo-04/pub