INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('brylee', 'Brylee', 2022, 'completed', 0, 1, 1, '{"name":"Brylee","slug":"brylee","age":9,"diagnosis":"Nemaline Rod Myopathy","roomTypes":["Accessible Bathroom"],"year":2022,"status":"completed","bio":"\"Brylee loves animals and wants to be a veterinarian when she grows up.\"\n\nBrylee is now 10 years old and has had multiple surgeries and visits to the hospital. Brylee is a fighter!  Brylee can drive her wheelchair around the house.  She loves playing with her cousins and friends along with trips to the playground.  Brylee loves animals and wants to be a veterinarian when she grows up.  Brylee and her family are so excited about her accessible bathroom!","quote":"\"Brylee loves animals and wants to be a veterinarian when she grows up.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brylee/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brylee/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brylee/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brylee/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brylee/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brylee/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brylee/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brylee/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brylee/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brylee/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brylee/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/brylee/photo-11/public","alt