INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('caitlin', 'Caitlin', 2020, 'completed', 0, 1, 2, '{"name":"Caitlin","slug":"caitlin","age":10,"diagnosis":"Mitochondrial Disease, Epilepsy","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2020,"status":"completed","bio":"Although she is non-verbal, Caitlin has no trouble letting people know how she feels or what she wants by giving a cute, little yell!\n\nCaitlin stays home with her mother and participates in the hospital homebound school program as well as therapy programs. Caitlin requires round the clock care. As she continues to defy the odds, her growing size has made bathing difficult for her parents, and an accessible bathroom will make bath time safer and even fun. An adapted bathroom and \"Dream Bedroom\" will help Caitlin end her day with her mesmerizing light show and she will continue to shine as the light of her parents'' lives.","quote":"Although she is non-verbal, Caitlin has no trouble letting people know how she feels or what she wants by giving a cute, little yell!","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caitlin/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caitlin/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caitlin/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caitlin/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caitlin/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caitlin/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caitlin/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caitlin/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caitlin/photo-08/public","alt":""},{"url":"htt