INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('caliyah', 'Caliyah', 2019, 'completed', 0, 1, 1, '{"name":"Caliyah","slug":"caliyah","age":4,"diagnosis":"Grease Fire Burn Victim","roomTypes":["Dream Bedroom"],"year":2019,"status":"completed","bio":"Sunshine on a Ranney Day gave her the glamorous bedroom makeover of her dreams! It promises to be as beautiful as she is!\n\nShe missed her preschool graduation ceremony since she was hospitalized, but the school and hospital joined forces to bring a special graduation ceremony of her own right to her room. Being able to enjoy the rite of passage of graduating preschool really lifted her spirits. Although Caliyah is making great progress, she has a long road of recovery ahead of her. Her scars are still healing and she is not able to go in direct sunlight. Sunshine on a Ranney Day gave her the glamorous bedroom makeover of her dreams! It promises to be as beautiful as she is!","quote":"Sunshine on a Ranney Day gave her the glamorous bedroom makeover of her dreams! It promises to be as beautiful as she is!","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caliyah/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caliyah/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caliyah/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caliyah/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caliyah/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caliyah/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caliyah/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caliyah/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caliyah/photo-08/public","alt":""},{"