INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('callie', 'Callie', 2021, 'completed', 0, 1, 2, '{"name":"Callie","slug":"callie","age":15,"diagnosis":"Angelman Syndrome, Burn Victim","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2021,"status":"completed","bio":"Her only wish is to spend more time with her friends and Sunshine on a Ranney Day is going to grant it!\n\nCallie, who is still in the hospital recovering, is fully dependent on her family and caregiver to meet all of her needs including transferring, showering, hygiene and bathing. She receives intensive physical, occupational and speech therapies and participates in the county''s exceptional education program via the hospital/homebound services division. The acquisition of each skill has been a true feat for Callie. Through tough determination and the support of her therapists and family, she continues to overcome obstacles and celebrate milestones. A room and bathroom that is adapted to meet Callie''s unique needs has become even more essential since her accident and subsequent surgeries. Sunshine on a Ranney Day is excited to have the opportunity to provide Callie and her family with extensive renovations to her home that will make her days a whole lot easier. Plans are in the works for an enlarged bathroom with a walk-in shower, Hoyer Lift to assist with transfers and a designer bedroom with a sensory station and storage for her medical supplies. We can wait to see her enjoy her new platform swing with radiant smiles and echoing laughter!","quote":"Her only wish is to spend more time with her friends and Sunshine on a Ranney Day is going to grant it!","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/callie/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/callie/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/callie/photo-02/public","alt":""},