INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('camp-twin-lakes', 'Camp Twin Lakes', 2018, 'completed', 0, 1, 1, '{"name":"Camp Twin Lakes","slug":"camp-twin-lakes","year":2018,"status":"completed","bio":"Each year, SOARD completes one special project that helps children outside of a home residence.  We love helping the community and partnering with amazing organizations. We are excited to partner with Camp Twin Lakes for 2018!  Camp Twin Lakes has delivered fully adaptive, medically supportive, and deeply impactful camp experiences to more than 10,000 of Georgia’s children and young adults, helping each camper grow in their confidence and experience the joys of childhood.  Through intentional play, they develop mindful and confident children who are prepared to triumph over challenges. By learning perseverance, resilience, and a sense of community, the campers leave transformed and capable of extraordinary things.  Camp Twin Lakes is building a new space that will house ceramics, wood working, and an open air teaching kitchen.  They would also love to have a &quot;Zen Den&quot; to serve multiple purposes including a quiet room where a child can rest, a play room for when outdoor activities are rained out, and a sensory space for when a camper needs a calm environment.  This sounds like a perfect makeover for Sunshine on a Ranney Day.  We are so excited to create this room and are bringing in our amazing design team from Randall-Paulson Architects.  Let''s help these kids &quot;Keep Calm and Camp On!&quot; We plan to have this completed and ready for Camp Twin Lakes summer program!","quote":"Each year, SOARD completes one special project that helps children outside of a home residence.  We love helping the community and partnering with amazing organizations. We are excited to partner with Camp Twin Lakes for 2018!  Camp Twin Lakes has delivered fully adaptive, medically supportive, and ","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/camp-twin-lakes/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/camp-twin-lakes/hero/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-39/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-40/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/camp-twin-lakes/photo-04/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-41/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braeden/hero/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/camp-twin-lakes/photo-08/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-43/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-46/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-50/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/camp-twin-lakes/photo-12/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/camp-twin-lakes/photo-13/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/camp-twin-lakes/photo-14/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/camp-twin-lakes/photo-15/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/camp-twin-lakes/photo-16/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/camp-twin-lakes/photo-17/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/anderson/photo-16/public","alt":"Camp Twin Lakes makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/camp-twin-lakes/photo-19/public","alt":"Camp Twin Lakes makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/63c1a112-9fa7-4b54-9b68-19703af50300/full","source":"wix-migration","wixNumber":82},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('caroline', 'Caroline', 2015, 'completed', 0, 1, 1, '{"name":"Caroline","slug":"caroline","year":2015,"status":"completed","bio":"Let’s cheer for sweet Caroline!  Caroline, like most teenage girls, loves shopping, makeup, cheerleading, going to the beach and Starbucks Frappuccinos.  Although she is enjoying high school, her journey has come with many challenges. Caroline was born at 38 weeks via caesarian section due to fetal intolerance to labor. She was diagnosed at birth with Arthrogryposis, which is a rare non-progressive neuromuscular disease, and Pierre Robin Sequence which is characterized by craniofacial anomalies including a small jaw, cleft of the soft palate and a narrow airway. She was born with contractures of all her joints, bilateral clubfeet and required a tracheostomy to breathe properly. She has endured more than twenty surgeries, most of which were orthopedic. At three years of age, she was diagnosed with Scoliosis, which despite multiple painful experimental surgeries followed by infection is unresolved.  She currently receives supplemental nutrition via a gastronomy tube and relies on mechanical ventilation to breathe while she sleeps.   At the age of four, Caroline lost a foot due to poor vascular supply following a surgical procedure and has used an electric wheelchair ever since. She has not let it slow her down and has participated in wheelchair baseball and ballet.  Her favorite, however, is cheerleading!  She competes with a special needs cheer squad and serves as her high school cheer squad’s team mascot.  Not only does she excel academically and show her school spirit, she also has a fantastic sense of humor and maintains an upbeat, positive attitude. Despite everything she has been through, she refuses to be defeated!  When she is not cheering on her team, she is cheering on her younger brother, Tate.  She is his biggest fan and supporter-never missing one of his games or swim meets.   Caroline relies on her family for assistance with activities of daily living.  However, she desires more independence and privacy.  Sunshine on a Ranney Day is going to help make her dream a reality by remodeling her bathroom to accommodate her wheelchair and renovating her bedroom.  She is looking forward to having a bathroom that she can access on her own; one where she can enjoy a little privacy and independence.  We are so excited to bring a little more cheer to Caroline''s life!  Join us for her reveal in Marietta, GA on Saturday May 9th at 12pm!  To donate toward Caroline''s makeover, click here!","quote":"Let’s cheer for sweet Caroline!  Caroline, like most teenage girls, loves shopping, makeup, cheerleading, going to the beach and Starbucks Frappuccinos.  Although she is enjoying high school, her journey has come with many challenges. Caroline was born at 38 weeks via caesarian section due to fetal ","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ta-and-alissa/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ta-and-alissa/hero/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-02/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-03/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-05/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-07/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-43/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-46/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-11/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alejandro/photo-30/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-13/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/adrian/photo-32/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-15/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-16/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-17/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-18/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-19/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-20/public","alt":"Caroline makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-21/public","alt":"Caroline makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/6b7f10a1-2cc7-43e5-206d-8b87fc093800/full","source":"wix-migration","wixNumber":27},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('carson', 'Carson', 2021, 'completed', 0, 1, 1, '{"name":"Carson","slug":"carson","age":9,"diagnosis":"Autism, Sensory Processing Disorder","roomTypes":["Therapy Room"],"year":2021,"status":"completed","bio":"Having been diagnosed with sensory processing disorder, SPD at age three, and recently diagnosed with Autism, Carson is a sensory seeker who likes to move all of the time.\n\nAs Carson gets older, it will be even more important to have a safe space of his own, including appropriate sensory stimulation.  A custom sensory room from Sunshine on a Ranney Day will give Carson what he needs to be and grow happier and healthier. Together with his family, he will better enjoy their three cats, bearded dragon, and beta fish and will have spent some energy so he can sit down and watch Shark Week like other kids his age.","quote":"Having been diagnosed with sensory processing disorder, SPD at age three, and recently diagnosed with Autism, Carson is a sensory seeker who likes to move all of the time.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/carson/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/carson/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/carson/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/carson/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/carson/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/carson/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/carson/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/carson/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/carson/photo-08/public","alt":""},{"url":"https://image