sign Studio","Meet the Kids","The Wall Nut"],"wpTags":["2021","Therapy Room"],"thumbnailId":1262,"needsReview":[],"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/531584fe-9419-45f7-4d22-4b07aac84100/full"},"streamVideoId":"4647ae14f6475a66a2c22a4686692ead","roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('cayden', 'Cayden', 2025, 'completed', 0, 1, 1, '{"name":"Cayden","slug":"cayden","age":17,"diagnosis":"Paralysis Waist Down & Amputee","roomTypes":["Accessible Bathroom"],"year":2025,"status":"completed","bio":"Cayden was born with congenital scoliosis, a condition that has defined his young life with countless challenges. Despite enduring multiple surgeries, including the amputation of one of his legs, Cayden has remained resilient and full of hope. However, during a spinal fusion surgery meant to improve his quality of life, tragedy struck—he suffered a stroke that left him paralyzed from the waist down. Cayden spent 11 long weeks in the hospital, enduring excruciating pain, multiple surgeries, and severe infections.\n\nThrough it all, Cayden has shown remarkable strength and an incredible, selfless spirit. This brave young boy faces unimaginable challenges every day, and his family is now struggling to provide him with the resources he needs to live with dignity and comfort.","quote":"\"He is an amazing, selfless child\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cayden/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cayden/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cayden/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cayden/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cayden/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cayden/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cayden/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cayden/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cayden/photo-08/public"