.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/georgia-interior-painting/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pulley-and-associates/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/servicewise-electric/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/tko-plumbing/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/b-interiors/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/niki-murphy-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bin-there-dump-that/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/iframe-media/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"92828301650e18d2da02346dba65e4f7","roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('celia', 'Celia', 2022, 'completed', 0, 1, 2, '{"name":"Celia","slug":"celia","age":13,"diagnosis":"Leigh''s Disease","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2022,"status":"completed","bio":"Celia and her twin sister were adopted from China at the age of 26 months. Celia and her twin are currently thirteen years old and the youngest of six kids.  During adoption, it was thought that Celia had cerebral palsy (CP) but after extensive testing, Celia likely has a mitochondrial disorder, which is neuro-degenerative, called Leigh''s disease or a Leigh-like syndrome.\n\nCelia cannot walk unassisted, use her hands purposefully, or eat by mouth.  Celia has endured many surgeries and hospitalizations and unfortunately had a setback in 2020 during a procedure that was supposed to help improve her dystonia (painful involuntary muscle contractures).  Celia lost the ability to speak, process information, sleep, and most devastatingly her sweet spunky personality.  In 2021 the procedure was reversed and hopefully with the love and support of Celia''s family, their faith in God, and extensive therapies she can regain what was lost. \n\nCelia''s family wishes everyone had a Celia in their lives.  She''s joyful, happy, has an amazing smile, and loves her family.  She even has a superpower; Celia can use her toes to type and play games on her iPad!  Celia has good days and bad days, she struggles with strength, stamina, communication, and mental cognition but through it all, she is the brightest of lights and a gift to all that know her.  Celia truly is God''s precious blessing!","quote":"\"She even has a superpower; Celia can use her toes to type and play games on her iPad!\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/celia/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-32/public","alt":""}],"photoCount":17,"videoUrl":"https://www.youtube.com/watch?v=6tLlNzqyM3A","photographer":"Nicole W Photography","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/ranney-blair/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/reliable-heatingair/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/american-signature-furniture/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cambria/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cr-construction-v2/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/echols/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/schluter-systems/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/asv-productions/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/interceramic/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/delta-faucet/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pulleyassociates/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/devore-johnson/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/tko-plumbing-2023/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bin-there-dump-that/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nicole-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"d84df0179f454e686e86bc609a886f58","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('charlie', 'Charlie', 2014, 'completed', 0, 1, 1, '{"name":"Charlie","slug":"charlie","year":2014,"status":"completed","bio":"We hope this amazing 16-year old will be pleasantly surprised at the reveal of his new room - an awesome hang out fit for a hip teen and his friends!  Charlie is quite charming, and handsome too.  Friends and family describe him as a sweet son, brother, Godson and pal.  He is funny, loves board games and vacations, has killer dance moves and adores Ford Mustangs. What teen doesn''t? As he has grown older, taking vacations and dancing have become more challenging and dreams of driving a Mustang less plausible, as Charlie has Duchenne Muscular Dystrophy.  When Charlie hadn''t hit some of the physical milestones expected as a toddler, his mother began to question things and after a series of tests, Charlie was diagnosed with Duchenne Muscular Dystrophy.  This degenerative disease results in muscle loss and progressively leads to immobility.  At the time of this devastating diagnosis, Charlie and his family were faced with a new reality that meant lots of physical therapy, delays in motor skill development and the realization that some skills would never be achieved-like crawling.  Instead he had a &quot;cute scoot.”  Both then and now, he approaches the challenges of life with a positive attitude, although the limitations can be discouraging. The simple things a lot of us take for granted have become major hurdles for Charlie.  A quick trip to the grocery store with mom isn''t in the cards for him anymore. A shower is quite the undertaking. Even using the restroom is a family affair due to the extensive support required to assist him as he is 100% wheelchair bound.  Regardless of the physical, emotional, and lifestyle changes they have endured, some things that have remained steadfast are the strength and love of Charlie and his family. Charlie''s parents, Jennifer and Kurt, work tirelessly to give Charlie and his siblings everything they can. They have struggled financially over the years, but no matter what, they have kept their family''s stability as their number one priority. They do it with a smile on their faces, always offering a shoulder to lean on for others around them even if they were in serious need of a shoulder themselves. Charlie''s brother and sister, 12-year old twins Cooper and Jillian, love, help, and encourage Charlie in every way they can. They love to play outside together, play video games together, and leave a little room for pestering here and there because, after all, they are siblings! They also help Charlie with things like making lunch, getting dressed, and homework.  Charlie does not like putting people out and often becomes physically and emotionally distressed due to the difficulties of having to rely on others to complete activities of daily living such as showering, using the restroom, getting in and out of the bed, the house and the car.  His goal is to be as independent as possible. However, he never complains.  Charlie keeps his chin up as he goes after his aspirations full throttle. Just this past year, Charlie was on the Homecoming Court at his high school. He was in the cast of &quot;Bye Bye Birdie&quot; and did a heck of a job as a reporter.  When kids come over to play, they often go upstairs to play in the kids’ rooms; but, Charlie can no longer join them. He is stuck downstairs with the boring adults. Due to his difficulty traveling upstairs, the family has utilized the den on the first floor as his bedroom.  Our plan is to give him a private bedroom-giving him the privacy a young man desires as well as a place he can feel proud entertaining in!  We will be removing all of the carpet on the first floor and replacing it with laminate flooring so his wheelchair can move easily throughout the first level, turning the dining room into a place to play with a fully equipped media room and building a wheelchair accessible bathroom!    When Charlie heard that he was chosen as the beneficiary of a SOARD make-over, he was beside himself with joy; bursting at the seams over the excitement!  The spark of light that had been dimmed by his difficulties has returned as he anxiously awaits the May 31st reveal of his new room-a place where he can enjoy the company of family and friends while he shows them up with his dance moves!","quote":"We hope this amazing 16-year old will be pleasantly surprised at the reveal of his new room - an awesome hang out fit for a hip teen and his friends!  Charlie is quite charming, and handsome too.  Friends and family describe him as a sweet son, brother, Godson and pal.  He is funny, loves board game","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/grace/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/grace/hero/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-04/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-05/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-06/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-07/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-08/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-09/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-10/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-11/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-12/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-13/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-14/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-15/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-16/public","alt":"Charlie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-17/public","alt":"Charlie makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/520c76a8-45e3-4d22-b8e6-51bbc72c0100/full","source":"wix-migration","wixNumber":14},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('choa', 'CHOA', 2016, 'completed', 0, 1, 1, '{"name":"CHOA","slug":"choa","year":2016,"status":"completed","bio":"Sunshine on a Ranney Day was thrilled to launch one of our largest projects to date! Our mission and labor of love is providing children with long term illness, dream room makeovers to bring joy and light into their homes.  We have been partnering with our donors, volunteers and local organizations to bring positive change to the lives of the children and families we serve, one smile at a time.  We are delighted to partner with Children’s Healthcare of Atlanta to redesign the 9 sleep rooms in Egleston.  The sleep rooms are a place for family members to escape to and rest while their child is being treated in the hospital.  As anyone can imagine, the stress level, angst and sleep deprivation of a parent caring for a sick or medically complex child can be exhausting and quite overwhelming.  These parents and siblings need a comforting space to help them relax and unwind.  A place where they can step away from the emotional roller coaster and anxiety of dealing with life threatening illness and just let go, cry, sleep or comfort each other.  The current rooms consist of gray walls, a basic twin bed or sleep chair, an end table, a lamp, and a safe. They are sterile in nature and look like typical hospital rooms.  Many of these families endure countless nights of worry and need a sense of comfort with the warmth of a home like environment to help them get through the night.  An estimated 2,300 people sleep in these rooms every year.  Although they are grateful to be near their beloved children while they are receiving care, multiple families who have slept in the rooms agree that the comfort of home is missing.  Stacy Halstead, mother of Tripp Halstead, a young boy who was paralyzed by a fallen tree limb at 2 years old while playing at his daycare, spent five months caring for Tripp while he was at CHOA.  When asked about this project, she reported: “My husband and I, along with my parents have slept in these rooms many times. Personally, I’d love a more homey look. Warm soothing colors, maybe a beautiful picture on the wall not drawn by a child. A vase of pretty fake flowers. A noise machine or fan for noise.” Thanks to our amazing sponsors and CHOA''s generous donors, Sunshine on a Ranney Day renovated the sleep center including all nine rooms, the hallways, personal storage areas and two bathrooms.  We were ecstatic to have the opportunity to leverage the expertise of our designers to meet the needs of comfort and tranquility for the parents who are staying there during their children’s treatment and recovery. Being able to broaden our reach and touch the lives of so many families is an esteemed privilege.  ","quote":"Sunshine on a Ranney Day was thrilled to launch one of our largest projects to date! Our mission and labor of love is providing children with long term illness, dream room makeovers to bring joy and light into their homes.  We have been partnering with our donors, volunteers and local organizations ","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","alt":"CHOA makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/hero/public","alt":"CHOA makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"CHOA makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/choa/photo-04/public","alt":"CHOA makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-46/public","alt":"CHOA makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/choa/photo-06/public","alt":"CHOA makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/choa/photo-07/public","alt":"CHOA makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/choa/photo-08/public","alt":"CHOA makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/choa/photo-09/public","alt":"CHOA makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/choa/photo-10/public","alt":"CHOA makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/choa/photo-11/public","alt":"CHOA makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/choa/photo-12/public","alt":"CHOA makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/anderson/photo-16/public","alt":"CHOA makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/d02b92ba-53b9-4f96-fac7-00ebd2cdc000/full","source":"wix-migration","wixNumber":51},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('christian-b', 'Christian B', 2021, 'completed', 0, 1, 2, '{"name":"Christian B","slug":"christian-b","age":17,"diagnosis":"Lennox-Gastaut Syndrome","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2021,"status":"completed","bio":"Christian began having grand mal seizures, drop seizures and breath holding spells on a daily basis. It was a challenge to get these seizures under control, as well as obtaining a true diagnosis.\n\nChristian was also diagnosed with Spastic Cerebral Palsy due to his disordered muscle tone and contractures. He endured another significant episode of epilepticus and was hospitalized in November 2013. He spent Thanksgiving in the hospital and wasn''t released until Christmas. After that, he was assessed by a new neurologist, who diagnosed him with Lennox-Gastaut Syndrome (LGS). LGS is a severe form of epilepsy that typically becomes apparent during infancy or early childhood and is most often diagnosed between 3-5 years of age although it took longer to determine that this was another syndrome Christian had. Since then Christian has been on a regimen of six medications and daily supplements which have minimized his seizures. He is essentially nonverbal, but can vocalize some sounds and words including Momma, Dadda, PopPop, Nana and Papa. He also uses sign language with a few consistent signs that he uses to communicate basic want and needs. He requires full assistance when walking and wears AFO braces to help support his feet and legs. He can take a few steps on his own when he''s highly motivated. If he does walk, he tires very easily and can only walk short distances. His home is currently not wheelchair accessible. When he needs help with mobility, his family carries him from room to room. He uses a wheelchair for mobility outside of the home. Christian is such a laid back kid and just goes with the flow. He can be quite the jokester. He loves to be silly and get a reaction out of you. He enjoys looking at pictures of family members and friends. He has a special memory book of photos that he looks through every day. He also loves going on family vacations to the beach and Disney World. He enjoys watching his favorite shows when he''s relaxing. Christian''s favorite place to unwind and be free is his bedroom. That is why Sunshine on a Ranney Day is thrilled to be able to give him a dream room makeover and renovate his bathroom to be accessible. This project will soon be under way and we hope that you will get a kick out of seeing the finished product. This will be a labor of love and we invite you to join us in support of this venture.","quote":"Christian began having grand mal seizures, drop seizures and breath holding spells on a daily basis. It was a challenge to get these seizures under control, as well as obtaining a true diagnosis.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-19/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-20/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-21/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-22/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-23/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-24/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-25/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-26/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-27/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-28/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-b/photo-29/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPm