INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('christian-v', 'Christian V', 2019, 'completed', 0, 1, 3, '{"name":"Christian V","slug":"christian-v","age":16,"diagnosis":"Cerebral Palsy","roomTypes":["Accessible Bathroom","Dream Bedroom","Wheelchair Ramp"],"year":2019,"status":"completed","bio":"Christian is a gregarious 16-year old boy with Cerebral Palsy who dreams of being a DJ when he grows up.\n\nChristian was born prematurely by emergency c-section and spent 32-days in the NICU. Eight months later, after failing to meet developmental milestones, he was diagnosed with Cerebral Palsy. At three years old, he received his first wheelchair, entered pre-school and learned to speak. This is when his personality began to emerge. He has continued to thrive and grow despite his disability, which he says he doesn''t notice all that much. Now that he is 5 foot 2 and one hundred pounds, with a 250-pound wheelchair, caring for him in a traditional sized bathroom and narrow bedroom doors has become a difficult challenge. With a bathroom remodel and ramp installation, Sunshine on a Ranney Day hopes to keep his dream alive and help him achieve his goals while helping his family continue to care for him in his home. We hope that you will join us in making this project become a reality.","quote":"Christian is a gregarious 16-year old boy with Cerebral Palsy who dreams of being a DJ when he grows up.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-v/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-v/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-v/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-v/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-v/photo-04/public","alt":""},{"url":"https://imagedeliv