INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('ciaran-and-geordan', 'Ciaran & Geordan', 2023, 'completed', 0, 2, 2, '{"name":"Ciaran & Geordan","slug":"ciaran-and-geordan","age":16,"diagnosis":"Lebers Congenital Amaurosos","roomTypes":["Dream Bedroom","Therapy Room"],"year":2023,"status":"completed","bio":"Ciaran and Geordan were both born with major disabilities. 19 year old Ciaran is totally blind and significantly autistic. On top of that, he has a tic disorder (tourette syndrome) and an immune system disorder. He has no sense of safety and will wake up throughout the night and bang on walls, doors, windows, and even his bed - waking up his brother. \n\nGeordan is 16 and was also born blind. He was also diagnosed with pretty severe non-verbal autism. Geordan also has no concept of safety, making the level of care required for the two boys quite extensive. With their mom''s recent cancer diagnosis, both parents work tirelessly to care for the boys and give them the fullest life they can.\n\nCiaran and Geordan are highly anxious and noise sensitive, so therapy items like swings, trampolines and instruments are very calming to them. They are both passionate about music and have an acute sense of hearing for pitch and tone due to their blindness. Both boys are unique and talented in their own ways, something that is so evident in their passions and skills! The space that Sunshine on a Ranney Day is providing for them will be life-changing in regards to their independence and individual needs.","quote":"\"They are both passionate about music and have an acute sense of hearing for pitch and tone due to their blindness.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ciaran-and-geordan/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ciaran-and-geordan/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ciaran-and-geord