","childCount":2,"roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('cohen', 'Cohen', 2016, 'completed', 0, 1, 1, '{"name":"Cohen","slug":"cohen","year":2016,"status":"completed","bio":"Cohen, like most teenage boys, loves sports and video games. This handsome champion is a sports enthusiast who passionately played a variety of sports including soccer, basketball and football beginning at age 3.  Running, jumping, kicking, dunking! Cohen played hard and basked in all the joys of boyhood.   As Cohen grew, things began to change.  Around 12, his parents and pediatrician noticed that he developed a gait abnormality in which he started turning his left foot outward to balance himself.  A series of tests first lead to the startling diagnosis of severe scoliosis with extensive scans and found the curvature of his spine was so severe it had pushed his heart to the other side of his body.  An Orthopedic Surgeon performed Spinal Fusion Surgery on Cohen in January of 2014, placing 2 titanium rods and 17 screws in his back to straighten his spine. Unfortunately, Cohen never regained his mobility after the surgery. During the surgery, the surgeon also noticed some neurological deficits and referred Cohen to be seen by a neurologist. This led to additional testing revealing two devastating diagnoses, Inherited Peripheral Neuropathy and a rare diagnosis of Hereditary Spastic Paraplegia. Hereditary Spastic Paraplegia is a genetic disease (effecting the spinal cord) detected on the Gene.  SPG7.  It has no cure, causes muscle weakness and has significantly affected his bilateral lower extremities.  When incidents occur, his legs become very weak and give out without notice to Cohen because of the spasticity which results in frequent and dangerous falls as he cannot predict when this will happen. Currently, Cohen uses a wheelchair and walker to move about his home.  Luckily, his upper extremities remain unaffected at this time and he is able to use his upper body strength to push his wheelchair and help transfer himself.  However, this is quite a feat and poses many challenges during bathing and dressing routines.  Weakness and fatigue make it difficult for him to remain active.  Although he will never walk again and cannot participate in traditional physical therapy, Cohen attends Aquatic Therapy to activate his muscles in a weightless environment. The reality of adjusting to a new way of life at 16 is enormous.  However, Cohen strives to maintain a positive spirit, continues to attend high school on-line and perfects his talents as master videogame champion. SOARD provided modifications that made his home environment safer so he can maintain mobility in his wheelchair, make transfers easier and safer from his bed or chair and move freely in the bathroom. ","quote":"Cohen, like most teenage boys, loves sports and video games. This handsome champion is a sports enthusiast who passionately played a variety of sports including soccer, basketball and football beginning at age 3.  Running, jumping, kicking, dunking! Cohen played hard and basked in all the joys of bo","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/hero/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-42/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/camp-twin-lakes/photo-08/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-50/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cohen/photo-08/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cohen/photo-09/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cohen/photo-10/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/angel/photo-61/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cohen/photo-12/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cohen/photo-13/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cohen/photo-14/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cohen/photo-15/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cohen/photo-16/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cohen/photo-17/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cohen/photo-18/public","alt":"Cohen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cohen/photo-19/public","alt":"Cohen makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/bfce39e9-d0ab-4ba4-160b-dfe733fa9600/full","source":"wix-migration","wixNumber":40},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('colin', 'Colin', 2026, 'in-progress', 0, 1, 1, '{"name":"Colin","slug":"colin","age":17,"diagnosis":"STXBP1","roomTypes":["Accessible Bathroom"],"year":2026,"status":"in-progress","bio":"Colin was diagnosed at age 10 with STXBP1, a rare genetic neurological disorder that affects how the brain communicates with the body. The condition leads to developmental delays, muscle tone challenges, seizures, and significant impairments in speech and motor skills.\n\nColin is non-verbal and can only walk short distances with assistance. He will require lifelong care, and as he ages into adulthood, his parents need support to ensure their home can safely meet his changing needs.\n\nSafely lowering himself into a traditional bathtub is difficult and increasingly unsafe as he grows. Colins parents are working hard to support his independence wherever possible, including encouraging him to use the toilet.","quote":null,"heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/colin/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jackson/photo-01/public","alt":""}],"photoCount":1,"videoUrl":null,"photographer":null,"partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/wyp/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('connor', 'Connor', 2015, 'completed', 0, 1, 1, '{"name":"Connor","slug":"connor","year":2015,"status":"completed","bio":"This tall, bright and handsome young man is Connor Bode. Connor has a whole team of supporters rooting for him and working heroically together to make his dreams of a wheelchair accessible bathroom and bedroom makeover a reality!   Twelve time Ironman Champion Dave Nazaroff with Ride to Give, will once again partner with SOARD to raise money to bring an extensive bed and bathroom makeover for Connor.  The renovations will enlarge his room and make his bathroom wheelchair accessible so he can mobilize with ease.  Dave Nazaroff and his wife Kaete, cofounded Ride to Give, which is a charitable non-profit organization based in Nyack NY.  Last year, Dave trekked 900 miles through heat, pain and rough terrain to raise funds for renovations for one of SOARD’s makeover recipients, Callie Truelove.  In the summer of 2013 Dave, followed by a support van with a team of 3, completed the first annual Ride from Nyack to Jefferson, GA (over 900 miles by bicycle) in 5 days to raise awareness and donations for the family of Tripp Halstead, a toddler who suffered a traumatic brain injury in fall of 2012. The Ride raised $180,000 for the Halstead family, plus an additional $17,000 for Sunshine on a Ranney Day to go toward our extreme home renovations for Tripp.  Ride to Give aims to help children with special needs and life-threatening illnesses overcome their obstacles by completing this ride annually.  This year, the Halstead Family is also partnering with SOARD and Ride to Give to help make Connor’s dreams come true.  SOARD is excited to have the opportunity to partner with Ride to Give and the Halstead family in honor of Connor!  Our SOARD Community is forever bound by the mission of bringing smiles to children with lifelong illnesses!  Together we achieve so much more. We can’t wait to see Connor’s handsome face light up with joy at the big reveal.  His family describes him as a bright light with contagious smiles and giggles.  Anyone who meets him will agree!  At five months of age, Connor was diagnosed with open-lip bi-lateral Schizencephaly, a very rare brain disorder characterized by abnormal clefts or slits in the brain''s cerebral hemispheres. Connor has Cerebral Palsy caused by the Schizencephaly and as a result is non-ambulatory and nonverbal.  He is hearing impaired, has a visual impairment, has abnormal muscle tone, seizures, hydrocephaly and partial paralysis.  Connor has endured several significant surgeries in his sixteen years of life.  His most recent surgery was an incredibly painful surgery to reconstruct his hip and lengthen his hamstrings.  It took almost 6 months for Connor to build up his strength and tolerate weight-bearing in his stander and gait-trainer again.  Connor’s daily therapeutic regimen includes tube feedings, a plethora of medications, speech therapy, physical therapy, occupational therapy, vision therapy and music therapy.  He is working hard to exceed expectations and achieve his goals.  His greatest supporters are his parents who are always by his side, helping him to maximize his full potential and shine! Connor currently weighs 120 pounds and is almost 6 feet tall. It is very difficult to lift him into his shower chair, wheelchair and into his hospital bed.  SOARD’s renovations will allow safer transferring from the wheelchair to the bed and shower by his parents as well as increased mobility and independence.  Like every teen seeking more independence, he wants to have fun and is on the go!","quote":"This tall, bright and handsome young man is Connor Bode. Connor has a whole team of supporters rooting for him and working heroically together to make his dreams of a wheelchair accessible bathroom and bedroom makeover a reality!   Twelve time Ironman Champion Dave Nazaroff with Ride to Give, will o","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/connor/photo-02/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/grace/hero/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/hero/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/angel/photo-56/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-46/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/callie/photo-30/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/connor/photo-10/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/connor/photo-11/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alejandro/photo-30/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/connor/photo-13/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/connor/photo-14/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/connor/photo-15/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/connor/photo-16/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/connor/photo-17/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/connor/photo-18/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/connor/photo-19/public","alt":"Connor makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/connor/photo-20/public","alt":"Connor makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/d02b92ba-53b9-4f96-fac7-00ebd2cdc000/full","source":"wix-migration","wixNumber":29},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('cyrus', 'Cyrus', 2022, 'completed', 0, 1, 1, '{"name":"Cyrus","slug":"cyrus","age":15,"diagnosis":"Autism","roomTypes":["Accessible Bathroom"],"year":2022,"status":"completed","bio":"Cyrus does not place limitations on himself.  Cyrus was not supposed to live but he continues to defy expectations.  Cyrus is non-verbal but that does not stop him from expressing himself.  He is active and strong and is an expert countertop and furniture climber.","quote":null,"heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cyrus/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cyrus/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cyrus/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cyrus/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cyrus/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cyrus/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cyrus/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cyrus/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cyrus/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cyrus/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cyrus/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cyrus/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cyrus/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cyrus/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/cyrus/photo-14/public","alt":""}],"photoCount":14,"videoUrl":"https://youtu.be/Rm1ktXIb9kQ","photographer":"Pear Tree Photography","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pga-superstore/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/reliable-heatingair/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/echols/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cambria/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cr-construction/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pulleyassociates/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/delta-faucet/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/devore-johnson/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/top-knobs/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pear-tree-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/iframe-media/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"352590908685d06344f7ca4f190b21ab","roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('damon-dj', 'Damon (DJ)', 2023, 'completed', 0, 1, 2, '{"name":"Damon (DJ)","slug":"damon-dj","age":11,"diagnosis":"Spina Bifida & Hydrocephalus","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2023,"status":"completed","bio":"\\u201cAt 24 weeks gestation my life changed forever. I was told that my baby had spina bifida and that his life would be tumultuous at best. It was suggested that I terminate my pregnancy as it was predicted that his quality of life would be very low. I then sought the opinion of some amazing doctors at Children''s Healthcare of Atlanta who told me that the information I was provided would not be DJ''s story.  \n\nDJ was born at 32 weeks and this amazing young man has not stopped making an impact in my life and the life of others. Not only did he have spina bifida, but he was also diagnosed with hydrocephalus. He struggled through some developmental delays as he did not start walking until 2 years old; BUT HE STARTED WALKING!!! A prior specialist stated he would never walk, but GOD had other plans.\n\nHe continues to be a scholar maintaining honor roll since pre-K.  He may not run as fast or jump as high as other kids, but this kid has never stopped trying and would challenge you every chance he gets. Like most kids his age he is an avid gamer with his favorite video game being Super Smash Brothers.  He is a sports fanatic who supports all of his home teams: The Falcons, The Hawks, The Braves, and Atlanta United. He is currently a member of an awesome team, The Gwinnett Heat where he plays wheelchair handball, basketball, and football.  Besides collecting all of the Nintendo Amiibo ever made, his life goals are ever evolving. I am so proud of the young man that he has become and I''m excited to see what more GOD has planned for him in the future.\\u201d - Rashida, Damon''s mom","quote":"\"He may not run as fast or jump as high as other kids, but this kid has never stopped trying and would challenge you every chance he gets.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/damon-dj/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROY