INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('devon', 'Devon', 2019, 'completed', 0, 1, 3, '{"name":"Devon","slug":"devon","age":20,"diagnosis":"Spinal Injury","roomTypes":["Accessible Bathroom","Dream Bedroom","Therapy Room"],"year":2019,"status":"completed","bio":"Devon put his all into a block, trying to slow Marshall down and, moments later, he was lying on his back, staring at the clear blue September sky, unable to move his legs.\n\nTish and Donny had been unable to make the trip to Athens for the game. As they watched from the family''s home in Baton Rouge, The report was that a \\u201cSouthern player was down on the field.\\u201d Tish''s motherly instinct kicked in and she knew Devon was hurt. Getting information about Devon''s status was difficult at first. When a nurse from Athens Regional Hospital finally called, Tish''s only question was \\u201cDo I need to be on the next flight to Georgia?\\u201d The nurse''s quick response was \\u201cYes, I think so.\\u201d As the Gales have continued down this path which God has placed them on, adversities have continued, as well. Their home in Baton Rouge was in an area which flooded only a few months ago. They had previously been struggling with the idea of moving the family to Atlanta. Moving to Georgia would put Devon closer to the care of The Shepherd Spinal Center and the expert care there. The flood, they decided, was another way of God telling them \\u201cit was time.\\u201d The time has come and this family is being blessed. The community has pulled together to build Devon and his family a new home. Currahee Homes, Paran Homes, WSB Radio took the lead on making this happen. There are some amazing people working on this project. Go over to  to learn more about these amazing people. Sunshine on a Ranney Day, along with our designers at Crosby Design Group, are doing the interior design of Devon''s new home and completing his wheelchair accessible bathroom, bedroom, and in-home therapy room. We are blessed to be just a small part of this very large and heart-felt project!","quote":"Devon put his all into a block, trying to slow Marshall down and, moments later, he was lying on his back, staring at the clear blue September sky, unable to move his legs.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/devon/photo-17/pu