INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('dewone', 'Dewone', 2025, 'completed', 0, 1, 2, '{"name":"Dewone","slug":"dewone","age":20,"diagnosis":"Cerebral Palsy & Epilepsy","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2025,"status":"completed","bio":"Dewone was born a healthy and joyful child, but his life took a dramatic turn at a young age when he contracted bacterial meningitis. One day, he was found unresponsive and had been without oxygen for over an hour, resulting in a major stroke. This life-altering event left Dewone non-verbal, living with epilepsy, and unable to care for himself. Though he faces these challenges daily, his spirit remains bright, and he continues to inspire those around him with his resilience and joyful heart.\n\nFor Dewone''s single mother, caring for him has been both a profound labor of love and an ongoing challenge. His wheelchair-bound state, his need for constant support with feeding and personal care, and the lack of an accessible bathroom have made daily routines incredibly difficult. Sunshine on a Ranney Day''s renovation hopes to transform their lives by creating a home environment that allows for greater accessibility and comfort. A walk-in shower will allow Dewone''s mom to bathe him without the physical strain of lifting him, and padded walls will help ensure his safety as he continues to work on maintaining his mobility.\n\nDespite his limitations, Dewone is a beacon of light to everyone he meets. His smiles are contagious, and his affection brings warmth to those around him. He loves playing with light-up toys, tossing balls, and interacting with strings that have objects attached. His love of movement, along with his mother''s constant encouragement, helps him maintain as much independence as possible. This renovation will not only improve his quality of life but also open new doors for Dewone to thrive in a space that truly meets his needs.","quote":"\"His love of movement, along with his mother''s constant encouragement, helps him maintain as much independence as possible.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amari/photo-26/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dewone/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN