INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('dex', 'Dex', 2026, 'in-progress', 0, 1, 1, '{"name":"Dex","slug":"dex","age":14,"diagnosis":"Down Syndrome","roomTypes":["Dream Bedroom"],"year":2026,"status":"in-progress","bio":"Declan, lovingly known as Dex, was adopted at birth by his incredible parents, who learned just two weeks before he was born that he has Down syndrome. Dex also has autism, and as he prepares to enter high school, his parents are focused on helping him build important life skills and grow in independence. One meaningful step in that journey is creating a bedroom of his own, separate from his nine-year-old brother, Gus, where he can develop routines and responsibilities that will serve him well into adulthood.\n\nDex is full of personality and joy. He often wakes up in the middle of the night, ready to play and explore, so a room tailored specifically to his needs will allow him to do so safely, while also giving his family the rest they need. He also has big dreams and proudly says he wants to become a teacher one day. He enjoys practicing lessons in front of the mirror, and his new space will include one where he can continue building confidence, imagination, and communication skills.\n\nThis renovation will provide Dex with more than just a bedroom, it will give him a safe, supportive environment designed to nurture his independence, routines, and dreams.","quote":null,"heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dex/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jackson/photo-01/public","alt":""}],"photoCount":1,"videoUrl":null,"photographer":null,"partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/wyp/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('dylan-2026', 'Dylan', 2026, 'in-progress', 0, 1, 1, '{"name":"Dylan","slug":"dylan-2026","age":16,"diagnosis":"MECP2 Duplication Syndrome","roomTypes":["Therapy Room"],"year":2026,"status":"in-progress","bio":"Dylan has MECP2 duplication syndrome, a rare genetic condition that causes significant developmental delays, low muscle tone, limited verbal communication, frequent infections, and progressive neurological challenges that require lifelong care. Because he is medically fragile and receives home hospital care, where everyone comes to him, Dylan spends nearly all of his time at home, and his bedroom serves as the center for his education and therapies.\n\nHis mother, Natalia, is a devoted single parent who has dedicated her life to caring for and advocating for Dylan. She works tirelessly to ensure that, despite his medical complexities, he experiences the joys and milestones of being a teenager.\n\nAnd Dylan definitely has a teenage personality. During schooling, he has been known to pretend he''s asleep to avoid his assignments, only to crack one eye open to make sure his teachers notice. His quiet humor and playful spirit shine through, reminding everyone around him of the bright young man he is.","quote":null,"heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dylan-2026/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jackson/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/dylan-2026/photo-02/public","alt":"Dylan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/hero/public","alt":"Dylan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/camp-twin-lakes/photo-04/public","alt":"Dylan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Dylan makeover pho