apher":"Kristi Weaver Photography","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/sugar-hill-outdoors/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/jackson-healthcare/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kristi-weaver-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/tafollas-concrete/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"_migration":{"scrapedAt":"2026-03-06T13:32:09.448Z","source":"wordpress-xml-export","wpPostDate":"2021-06-18 23:08:00","wpCategories":["Meet the Kids"],"wpTags":["2019","Concrete Carport"],"thumbnailId":1285,"needsReview":[],"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/cc94e825-34a5-4bfa-d3f7-065bb1ab7200/full"},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('eliavah', 'Eliavah', 2021, 'completed', 0, 1, 1, '{"name":"Eliavah","slug":"eliavah","age":8,"diagnosis":"Open Heart Surgery, Misophonia","roomTypes":["Dream Bedroom"],"year":2021,"status":"completed","bio":"Eliavah suffers from misophonia, which creates intense fight or flight responses and anxiety triggered by specific sounds many people don''t even notice.\n\nSince she cannot share a room with her sister, Eliavah currently sleeps in her baby brother''s room, and he sleeps in their parent''s room. It is not easy for Eliavah to find a place in her home where she can unwind and safely escape the many stimuli of a typical family home.\nEliavah''s parents would love to turn their dining room into a bedroom for her. They imagine a place where Eliavah will have a sensory-friendly sanctuary of her own. Like most nine-year-old girls, she would love to listen to her favorite music ( David Bowie and Michael Jackson) in a bean bag chair surrounded by her stuffed animals, barbies, and crafts without stimuli that trigger negative responses. Eliavah''s heart has remained healthy, and she has such a passion and love for life. One day she hopes to be a Vet or maybe even be in a band with her best friend, her sister.\n\nA new bedroom in the home would not only enable Eliavah to safely escape from the sensory overload of day to day life, but it will also allow her brother to move to his own room. Eliavah''s dedicated parents will have their bedroom to themselves - something most of us take for granted, and the peace of mind that Eliavah is safe and comfortable.","quote":"Eliavah suffers from misophonia, which creates intense fight or flight responses and anxiety triggered by specific sounds many people don''t even notice.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-19/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-20/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eliavah/photo-21/public","alt":""},{"url":"https://imagede