INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('elijah', 'Elijah', 2016, 'completed', 0, 1, 1, '{"name":"Elijah","slug":"elijah","year":2016,"status":"completed","bio":"This handsome little miracle is Elijah.  He is vibrant, sporty and smart.  He aspires to be a veterinarian which spawned from the love of his furry friends-huggable cats that he totes around his home.  As an infant, Elijah was meeting his milestones and becoming an active toddler, walking all over the house and keeping his parents on their toes.  However, at 21 months, he began experiencing fevers and stopped walking.  Several tests lead to the dreadful discovery that he had a mass on his kidney and the final diagnosis was a Stage IV Neuroblastoma.  This aggressive cancer is documented to have only a 20% survival rate, which is a heartbreaking realization. Elijah has endured six rounds of chemotherapy, a severe surgery to remove the primary tumor and his kidney that was completely damaged, two stem cell transplants, twelve rounds of radiation, and five rounds of antibody therapy with Accutane. After Elijah completed frontline therapy, he underwent a two-year trial of DFMO in an effort to keep him in remission. He is currently in remission and the joy of this miraculous outcome is resounding. Elijah is full of life and love, and is most fond of video games, superheroes and his little sister.  SOARD transformed his bedroom into a vibrant gaming oasis with colors as bright and outgoing as he is. This exciting project brought him luminous smiles!","quote":"This handsome little miracle is Elijah.  He is vibrant, sporty and smart.  He aspires to be a veterinarian which spawned from the love of his furry friends-huggable cats that he totes around his home.  As an infant, Elijah was meeting his milestones and becoming an active toddler, walking all over t","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","alt":"Elijah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Elijah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Elijah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/elijah/photo-04/public","alt":"Elijah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/callie/photo-30/public","alt":"Elijah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/elijah/photo-06/public","alt":"Elijah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/elijah/photo-07/public","alt":"Elijah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/elijah/photo-08/public","alt":"Elijah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/elijah/photo-09/public","alt":"Elijah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/elijah/photo-10/public","alt":"Elijah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/elijah/photo-11/public","alt":"Elijah makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/d02b92ba-53b9-4f96-fac7-00ebd2cdc000/full","source":"wix-migration","wixNumber":39},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('elizabeth', 'Elizabeth', 2019, 'completed', 0, 1, 3, '{"name":"Elizabeth","slug":"elizabeth","age":17,"diagnosis":"Tranverse Myelitis","roomTypes":["Accessible Bathroom","Dream Bedroom","Therapy Room"],"year":2019,"status":"completed","bio":"Her only wish is to spend more time with her friends and Sunshine on a Ranney Day is going to grant it!\n\nAlthough she faces her battles head on, the social impact of this life change has hit her the hardest. She can no longer easily enter the homes of her friends due to lack of wheelchair accessibility. Her only wish is to spend more time with her friends and Sunshine on a Ranney Day is going to grant it! Elizabeth will be getting an accessible bathroom and a \\u201chang out\\u201d space in her teen suite so friends can come spend time with her at home. With this new set-up, her service dog Stevie Ray will not be left behind. He is very excited about having his human friends over! We are ecstatic about breaking ground on this unique and sensational project to help Elizabeth adjust to her new lifestyle. Watch out world, she is going to shine brighter than the sun!","quote":"Her only wish is to spend more time with her friends and Sunshine on a Ranney Day is going to grant it!","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/elizabeth/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/elizabeth/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/elizabeth/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/elizabeth/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/elizabeth/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/elizabeth/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eli