INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('emily', 'Emily', 2013, 'completed', 0, 1, 1, '{"name":"Emily","slug":"emily","year":2013,"status":"completed","bio":"We are so excited to welcome Emily home! Over the last several weeks, SOARD has worked with a wonderful and generous group of volunteers to renovate the Bowman home to accommodate Emily as she continues to heal from the devastating injuries she suffered in a hit-and-run accident in mid-February. Had we not stepped in to help, the Bowman''s would have had to re-locate to another - more wheelchair friendly - home.   Our first task was to make the ground floor completely wheelchair accessible. This included building an entrance ramp to the front of the house. We also converted a small bathroom into a large one that is fully functional and accessible. The downstairs dining room and den were remodeled to serve as comfortable adjoining bedrooms for Emily and her mom. And, as our vision extends beyond the physical aspects of the makeover, we have brought beautiful finishing touches to her living space.  SOARD feels blessed to have worked on this project. We truly appreciate the generous monetary donations, company sponsors, and volunteers that allowed us to do complete our mission. Here''s an overview of what this make-over involved and the companies and individuals who assisted. •\tBuilt a wheelchair-accessible ramp to the front of the home with surrounding landscaping by B. Green Landscape Group •\tInstalled an ADA accessible shower on the ground floor with plumbing assistance provided by Mr. Plumber •\tConverted a dining room and a den into accessible and adjoining bedrooms for Emily and her mom with a donated hospital bed which was moved into the home by College Hunks Moving Junk, and additional furniture donated by Woodstock Furniture Outlet •\tReplaced carpet with laminate flooring on main floor","quote":"We are so excited to welcome Emily home! Over the last several weeks, SOARD has worked with a wonderful and generous group of volunteers to renovate the Bowman home to accommodate Emily as she continues to heal from the devastating injuries she suffered in a hit-and-run accident in mid-February. Had","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/emily/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/emily/hero/public","alt":"Emily makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/emily/photo-02/public","alt":"Emily makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/emily/photo-03/public","alt":"Emily makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/emily/photo-04/public","alt":"Emily makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/emily/photo-05/public","alt":"Emily makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/emily/photo-06/public","alt":"Emily makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/357c8d88-c2a0-46c8-4f16-e0b0f4128900/full","source":"wix-migration","wixNumber":5},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('ethan-2022', 'Ethan', 2022, 'completed', 0, 1, 2, '{"name":"Ethan","slug":"ethan-2022","age":17,"diagnosis":"Mecp2 Duplication Syndrome","roomTypes":["Accessible Bathroom","Wheelchair Ramp"],"year":2022,"status":"completed","bio":"Ethan spent the first seven years of his life without an official diagnosis other than a general diagnosis of mentally disabled.  That changed when Ethan was seven and experienced a seizure where he ultimately ended up at Children''s Healthcare of Atlanta (CHOA).  Fortunately for Ethan, the neurologist at CHOA specialized in what would eventually become Ethan''s diagnosis, Mecp2 Duplication Syndrome or M2DS.  M2DS is a rare genetic condition causing many issues such as severe intellectual disabilities, impaired motor function, spasticity, speech, gastrointestinal, and respiratory issues.\n\nEthan is able to enjoy life in general; he is still mobile and eats soft foods by mouth.  He has had setbacks over the years but he continuously proves how strong he is time and time again.  Ethan''s mobility has declined over the past few years due to severe seizures.  Ethan''s Sunshine makeover includes a wheelchair-accessible bathroom and wheelchair ramp going into his house to make daily life a little easier for everyone.","quote":"Quote about Ethan","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan-2022/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan-2022/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan-2022/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan-2022/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan-2022/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan-2022/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan-2022/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan-2022/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan-2022/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan-2022/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan-2022/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan-2022/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan-2022/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan-2022/photo-13/public","alt":""}],"photoCount":13,"videoUrl":"https://youtu.be/L6CEmvuJlBg","photographer":"Marcelino Aguilar Photography","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/preston/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/interceramic/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/reliable-heatingair/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/us-cabinetworks/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/echols/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cambria/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cr-construction/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pulleyassociates/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bin-there-dump-that/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/delta-faucet/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/top-knobs/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/devore-johnson/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pls-carpentry/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/marcelino-aquilar-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/iframe-media/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"c971aa52ed481cb58808085fa8a1bbe8","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('ethan', 'Ethan', 2018, 'completed', 0, 1, 2, '{"name":"Ethan","slug":"ethan","age":9,"diagnosis":"Cerebral Palsy and Spastic Diplegia","roomTypes":["Accessible Bathroom","Therapy Room"],"year":2018,"status":"completed","bio":"We would like to introduce our 9 year old son Ethan Carson. He is the most fun-loving, playful kid you will ever meet and asks everyone he encounters, \"Hey, How are you?\" He has the most infectious smile and some of his favorite things are race cars, the Georgia Bulldogs, bouncy houses and balls, swimming, video games, music (esp. Luke Bryan!), and the most important of all his iPad! Ethan is also obsessed with watching Fixer Upper and Flip or Flop on HGTVR and talks constantly about ''beams'' on the ceiling, lights and fans! \n\nWhile the 9 month pregnancy was a model, all of the troubles that Ethan encountered were during his birth. After a very long delivery, Ethan got stuck in the birth canal, and went without oxygen for a period of time. He spent two days in NICU with a one lung only working at 13%. He was such a fighter though and eventually came through and we brought him home after a week long stay in the hospital. It was not until about 8 months old that we discovered Ethan was not able to do some of the normal things that children his age should be doing. Things like sitting up, crawling, tummy time, etc. were not in line with other babies his age. We then set out to find out what was going on and began our journey with the many wonderful specialists and doctors at Children''s Healthcare of Atlanta. After several seizures, numerous EKG''s, MRI''s, and respiratory issues, at the age two, Ethan was diagnosed with Cerebral Palsy (CP) and the more specific form be Spastic Diplegia. The form of CP and Spasticity Ethan has is a neuromuscular condition of hypertonia - manifested as an especially high and constant ''stiffness'' or ''tightness'' in the muscles of the lower extremities. This form of CP and Spasticity can be quite crippling in that it causes some major abilities in his physical movement and obvious issues with just day-to-day functions such as dressing, bathing, brushing teeth, combing hair, along with speech delay.\n\nEthan has not let his disability become a crutch for himself. In fact, he does not even know that he has this ailment; he crawls, walks in his Kaye walker, and wheels himself in his wheelchair throughout his day as if he was a normal boy - not letting his disability define him. He loves going to school each day and of course the \"School Bus\" ride is a highlight that he looks forward too on a daily basis. His favorite meals are pancakes (all day, every day), pizza with chocolate milk and his Mommy''s spaghetti.","quote":"\"He is the most fun-loving, playful kid you will ever meet and asks everyone he encounters, ''Hey, How are you?''\\u00a0\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ethan/photo-10/public","alt":""}