.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/falcons/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kirby-smart-family-foundation/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/la-vida-massage/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"_migration":{"scrapedAt":"2026-03-06T13:32:09.408Z","source":"wordpress-xml-export","wpPostDate":"2018-03-20 23:58:59","wpCategories":["Meet the Kids"],"wpTags":["2018","Accessible Bathroom","Therapy Room"],"thumbnailId":6605,"needsReview":[],"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/9d3b0563-5c22-4389-8822-c8d9055eac00/full"},"streamVideoId":"cccb6f4de1c340b619e33898918f246c","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('fenton', 'Fenton', 2019, 'completed', 0, 1, 1, '{"name":"Fenton","slug":"fenton","age":5,"diagnosis":"Modern Day Polio","roomTypes":["Therapy Room"],"year":2019,"status":"completed","bio":"Fenton is currently one of only four cases of Modern Day Polio in Georgia and one of roughly 300 nationwide.\n\nFenton''s spine was infused with inflammation that quickly destroyed tissue including the nerve conduits leading to his extremities. He is scheduled to receive an innovative new surgical procedure called nerve transfers and is hopeful that the results will be positive; and, he will be able to breathe without a ventilator. Fenton''s daily routine is built upon an intensive therapy schedule. With therapeutic electrical stimulation and consistent movement, children like Fenton show strengthening and meaningful muscle improvements over time. Intensive therapy treatments are important for Fenton to achieve maximum potential. Fenton is a resilient trooper and a complete ray of light. He provides hope in the face of fear and replaces sadness with smiles. Sunshine on a Ranney Day hopes to bring endless smiles to Fenton and his family though this exciting venture! We''d love to see you at the big reveal!","quote":"Fenton is currently one of only four cases of Modern Day Polio in Georgia and one of roughly 300 nationwide.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/fenton/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/fenton/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/fenton/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/fenton/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/fenton/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/fenton/photo-05/public