INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('gabrielle', 'Gabrielle', 2019, 'completed', 0, 1, 2, '{"name":"Gabrielle","slug":"gabrielle","age":14,"diagnosis":"Muscular Spasticity","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2019,"status":"completed","bio":"She is unable to walk and utilizes her power wheelchair for mobility and requires assistance in transitioning activities.\n\nShe is unable to walk and utilizes her power wheelchair for mobility and requires assistance in transitioning activities. Her right side is more flexible and allows her the ability to move for feeding herself and other activities such as writing or typing on the computer. Gabrielle''s story continues with highlights of her growing from glory to glory. She is experiencing the teenage years just as she should, having fun and reaching for great goals. Gabrielle enjoys computers, editing YouTube videos and basketball. She wants to become a video editor. She loves music, dancing and playing with her best friend and cousin, William. Her favorite PS4 games are Fortnite and NBA19. Sunshine on a Ranney Day was so excited to be able to give Gabrielle a life changing wheelchair accessible bathroom and dream bedroom makeover! This will not only help Gabrielle, but will majorly help her parents so they don''t have to lift her as much! We love our job!","quote":"She is unable to walk and utilizes her power wheelchair for mobility and requires assistance in transitioning activities.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/gabrielle/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/gabrielle/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/gabrielle/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/gabrielle/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/ki