":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/top-knobs/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/msi/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/traditions-in-tile/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/schluter-systems/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/georgia-interior-painting/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/tko-plumbing/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/servicewise-electric/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bin-there-dump-that/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/iframe-media/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"b7d19b4d7dc84e9bff23f7eb366d6bce","roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('harper-2025', 'Harper', 2025, 'completed', 0, 1, 1, '{"name":"Harper","slug":"harper-2025","age":12,"diagnosis":"Pitt Hopkins Syndrome","roomTypes":["Accessible Bathroom"],"year":2025,"status":"completed","bio":"Harper was born with Pitt-Hopkins Syndrome (PTHS), a rare genetic disorder that affects brain development. PTHS causes severe developmental delays, difficulty speaking, and challenges with movement and coordination, requiring lifelong care. Despite her complex diagnosis, Harper is an outgoing and energetic pre-teen who loves socializing, anything water-related, and the thrill of going fast—whether on a boat or an exciting ride at the fair.\n\nThanks to extensive physical therapy, Harper is no longer bound to a wheelchair and can now walk with the support of her shoes and braces. However, showering remains a challenge—she must step over a bathtub, or her parents have to lift her in. SOARD is committed to providing Harper and her family with an accessible shower, ensuring she has a safe and comfortable bathing space for the rest of her life.","quote":"Donate directly to Harper''s bathroom makeover here!\\u00a0","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper-2025/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper-2025/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper-2025/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper-2025/hero/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper-2025/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper-2025/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper-2025/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ