INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('harper', 'Harper', 2018, 'completed', 0, 1, 1, '{"name":"Harper","slug":"harper","age":4,"diagnosis":"PTHS - Pitt Hopkins Syndrome","roomTypes":["Dream Bedroom"],"year":2018,"status":"completed","bio":"This tiny diva is Harper Grace.  Harper''s gorgeous smile and contagious laugh can truly light up a room.  Although she isn''t able to communicate verbally, it''s amazing how much she can tell us with just a look.  Just by being around her, you can tell that she may be tiny, but she has a big heart and big purpose.\n\nAfter a fairly uneventful twin pregnancy, Harper and her brother Nolan were born on May 31, 2015.  At around a year of age, while her brother was meeting his milestones, Harper was falling further and further behind.  After going through several rounds of tests, a neurologist diagnosed Harper with Pitt Hopkins Syndrome (PTHS), which is a rare genetic disorder affecting a specific gene in chromosome 18, called TCF4.  There are roughly only 700 diagnosed cases worldwide.  PTHS is characterized by extreme developmental delay, gastrointestinal issues and a lack of speech.\n\nHarper is four and is striving to achieve developmental milestones.  Because of her developmental delays and motor planning issues, she is nonverbal but is striving to learn how to walk. She participates in speech, occupational, physical and hippotherapy where she is learning to accomplish independent movement and is using an augmentative communication device to express her needs and thoughts. Harper has little body awareness and doesn''t have the necessary protective instincts to help keep herself safe when she''s playing and sleeping. \n\nHarper, along with her twin brother, has a 2 year old little sister, Mia. Harper is in special needs pre-K at Whitlow Elementary and loves school and seeing her friends and teachers.  She''s a very social little girl, who likes to swing and swim and play with toys that are musical and light up.  She adores music and watching movies with a great soundtrack!","quote":"\"Harper''s gorgeous smile and contagious laugh can truly light up a room.\\u00a0 Although she isn''t able to communicate verbally, it''s amazing how much she can tell us with just a look.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harper/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCk