ion":null,"altTexts":null,"jsonLd":null,"streamVideoId":"cccb6f4de1c340b619e33898918f246c","roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('harrison', 'Harrison', 2020, 'completed', 0, 1, 1, '{"name":"Harrison","slug":"harrison","age":17,"diagnosis":"PURA Syndrome","roomTypes":["Accessible Bathroom"],"year":2020,"status":"completed","bio":"After experiencing traumatic violent seizures that lead to fractured bones and teeth, his parents sought out for answers through a DNA Sequencing test and he was diagnosed with PURA Syndrome.\n\nThis is a neurodevelopmental diagnosis that presents itself with children being nonverbal, non-ambulatory as they get older, seizures, developmentally delayed both mentally and physically, diaper dependent and yet they all have extremely sweet and happy demeanors Harrison has to sleep in a special \\u201cSleep Safe\\u201d bed, requires a wheelchair for mobility, uses simple signs and gestures to communicate, attends special classes at school for children with severe disabilities, and requires assistance in all aspects of his daily care. Harrison also serves as a \\u201cMiracle Kid\\u201d with For the Kids at both Kennesaw State University and Georgia Tech in an effort to give back to the community at Children''s Healthcare of Atlanta that has helped him to become the admirable person he is today. Sunshine on a Ranney Day has chosen Harrison as the beneficiary of an accessible bathroom renovation to help make his days brighter and his smile wider. He hopes that you will support this endeavor and join us at the big reveal.","quote":"After experiencing traumatic violent seizures that lead to fractured bones and teeth, his parents sought out for answers through a DNA Sequencing test and he was diagnosed with PURA Syndrome.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harrison/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/harrison/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids