INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('hawk', 'Hawk', 2017, 'completed', 0, 1, 2, '{"name":"Hawk","slug":"hawk","age":4,"diagnosis":"Spontaneous brain hemorrhage, global developmental delays, seizures, shunted hydrocephalus, reflux, feeding disorder requiring a g-tube, cortical vision impairment, cerebral palsy.","roomTypes":["Accessible Bathroom","Therapy Room"],"year":2017,"status":"completed","bio":"Hawk is a precious blessing that was prayed for long before he was conceived.  After several infertility treatments and lots of hoping, he was a gift that many cheerfully awaited at the arrival of his birth.  When asked whether she wanted a boy or a girl, his mother said, \\u201cI just want a happy life-loving child that will go everywhere with me.\\u201d  She says she was given exactly what her heart desired.  Hawk''s grandmother describes him as a love sponge! Who wouldn''t want to soak up a little love from this adorable angel?\n\nAfter being home for two and a half weeks, Hawk experienced a seizure and vomiting and was admitted to the hospital.  After testing, it was found that he sustained a massive hemorrhage in his brain.  He was transported to a specialized unit at Children''s Hospital of Atlanta.  He continued to have dangerous seizures and was therefore induced into a coma with pentobarbital.  Severe complications led to blood clots that needed to be drained via an external ventricular drain and subsequently, Hawk developed hydrocephalus.\n\nHe has endured numerous infections, DVTs and eight surgeries to place shunts in his brain during his short four years of life. Despite having seizures almost on a daily basis, he works hard in therapy to regain the skills he lost after the hemorrhage, i.e.  tracking with his eyes, eating, holding up his head, and become mobile.  Through extensive therapy that he loves, he is making gains.  His favorite things to do are swim, rough house with other children, go to school and take care of his pets!\n\nA new therapy room equipped with all of the specialized equipment he needs to reach his goals is already in progress.  We can''t wait to see Hawk attain his goals and soar!","quote":"Through extensive therapy that he loves, Hawk is making gains.\\u00a0\\u00a0His favorite things to do are swim, rough house with other children, go to school and take care of\\u00a0 \\u00a0 \\u00a0 \\u00a0 \\u00a0his pets!","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hawk/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN