INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('helen', 'Helen', 2021, 'completed', 0, 1, 2, '{"name":"Helen","slug":"helen","age":14,"diagnosis":"Infantile-Onset Pompe Disease","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2021,"status":"completed","bio":"Helen has Infantile-onset Pompe disease, which caused the development of cardiomyopathy, progressive muscle weakness, neuromuscular scoliosis, and impairment of respiratory function.\n\nWith the high level of care required by Helen, her family faces many obstacles in their home. Due to her Pompe disease, she has severe osteoporosis and has suffered fractures from minimal force. One of Helen''s more recent fractures occurred when a caregiver transferred her in her inaccessible home. \n\nDay-to-day life is complicated. On top of it all, as a 14-year-old girl, Helen is too big to be safely bathed. A bedroom and bathroom from Sunshine on a Ranney Day would bring Helen''s family safety and peace of mind and possibly create a little more time for Helen to get out and shine.","quote":"Helen has Infantile-onset Pompe disease, which caused the development of cardiomyopathy, progressive muscle weakness, neuromuscular scoliosis, and impairment of respiratory function.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/helen/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/helen/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/helen/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/helen/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/helen/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/helen/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/helen/photo-06/public","alt":""},{"url":"https://imagedelivery.net/