INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('hudson-2024', 'Hudson', 2024, 'completed', 0, 1, 1, '{"name":"Hudson","slug":"hudson-2024","age":6,"diagnosis":"Gaucher Disease Type 2","roomTypes":["Accessible Bathroom"],"year":2024,"status":"completed","bio":"Hudson is the youngest of 3 children, following his sister Olivia (8) and brother Gavin (10). He was born a happy healthy baby. Around 4 months of age, Hudson''s parents started noticing some differences in him, such as weight loss, difficulty nursing, and choking. After a few significant episodes Hudson was hospitalized around 6 months of age for further investigation. After a 16 day stay in the hospital and lots of testing Hudson was sent home with no answers and told to follow up with genetics. At the young age of 9 months old, on July 2nd, 2018, Hudson''s mom Nichole received the phone call that would forever alter the life their family had once dreamed of. Hudson was diagnosed with a rare, incurable, terminal, genetic disease, Gauchers Disease 2. They were told to put Hudson on hospice, that he would have no quality of life, never walk, talk, or live past the age of 2. Nichole''s response to them\\u2026.. \\u201cbut God\\u201d.\n\nHudson is now an amazing 5 year old who is living his BEST life! His family has and will continue to go to the ends of the earth for Hudson and his siblings. For the past 4 years they have made the drive to D.C. every 3 to 6 months for Hudson''s geneticist who is the only one in the US willing to give him a chance at life! In fact, Hudson is now being followed by geneticists all over the world as he is re-writing the books and making a way for all the children to come. \n\nHudson is a very social kid, who thinks his siblings have hung the moon. He loves sports (football, basketball, and baseball), movies (Toy Story is his favorite), and has a smile that lights up his family''s world! He''s also known to give the BEST hugs. You''ve never had a hug ''till you''ve had a Huddy hug! \n\nUnfortunately, Hudson is very susceptible to viruses that have kept him in the hospital ICU for more than half of his life. Because of this, they have had to keep Hudson confined within the walls of their home, limiting his exposure to the outside world. Sunshine on a Ranney Day is honored to bring light and joy into the walls that surround Hudson to help him continue living his BEST life!","quote":"\"You''ve never had a hug \\u2018till you''ve had a Huddy hug!\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson-2024/photo-19/public","alt":""}],"photoCount":19,"videoUrl":"https://youtu.be/sSlS_nIUoBg","photographer":"Vicki Alsup Photography","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/gas-south/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/reynard-custom-homes/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/vicki-alsup/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/servicewise-electric/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/tko-plumbing-2023/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pulleyassociates/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/schluter-systems/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/traditions-in-tile/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cambria/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cr-construction/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pls-carpentry/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/iframe-media/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bin-there-dump-that/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bobcat/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/niki-murphy-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"ae74451b60a54d7428ed5fbbb62e9ad5","roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('hudson', 'Hudson', 2023, 'completed', 0, 1, 1, '{"name":"Hudson","slug":"hudson","age":6,"diagnosis":"Gaucher Disease Type 2","roomTypes":["Accessible Bathroom"],"year":2023,"status":"completed","bio":"Hudson is the youngest of 3 children, following his sister Olivia (8) and brother Gavin (10). He was born a happy healthy baby. Around 4 months of age, Hudson''s parents started noticing some differences in him, such as weight loss, difficulty nursing, and choking. After a few significant episodes Hudson was hospitalized around 6 months of age for further investigation. After a 16 day stay in the hospital and lots of testing Hudson was sent home with no answers and told to follow up with genetics. At the young age of 9 months old, on July 2nd, 2018, Hudson''s mom Nichole received the phone call that would forever alter the life their family had once dreamed of. Hudson was diagnosed with a rare, incurable, terminal, genetic disease, Gauchers Disease 2. They were told to put Hudson on hospice, that he would have no quality of life, never walk, talk, or live past the age of 2. Nichole''s response to them\\u2026.. \\u201cbut God\\u201d.\n\nHudson is now an amazing 5 year old who is living his BEST life! His family has and will continue to go to the ends of the earth for Hudson and his siblings. For the past 4 years they have made the drive to D.C. every 3 to 6 months for Hudson''s geneticist who is the only one in the US willing to give him a chance at life! In fact, Hudson is now being followed by geneticists all over the world as he is re-writing the books and making a way for all the children to come. \n\nHudson is a very social kid, who thinks his siblings have hung the moon. He loves sports (football, basketball, and baseball), movies (Toy Story is his favorite), and has a smile that lights up his family''s world! He''s also known to give the BEST hugs. You''ve never had a hug ''till you''ve had a Huddy hug! \n\nUnfortunately, Hudson is very susceptible to viruses that have kept him in the hospital ICU for more than half of his life. Because of this, they have had to keep Hudson confined within the walls of their home, limiting his exposure to the outside world. Sunshine on a Ranney Day is honored to bring light and joy into the walls that surround Hudson to help him continue living his BEST life!","quote":"\"You''ve never had a hug \\u2018till you''ve had a Huddy hug!\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/hudson/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuP