INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('jack', 'Jack', 2016, 'completed', 0, 1, 1, '{"name":"Jack","slug":"jack","year":2016,"status":"completed","bio":"Meet Jack.  Jack is mature beyond his years with an amazing drive to have a positive impact on his community and the world at large.  With a cheerful and content disposition, he faces daily challenges that would bring the strongest of us to despair, but he keeps on keeping on with a smile and vigorous endurance.  This remarkable 10-year old was just 2 years old when he was diagnosed with an incurable genetic disorder called Neurofibromatosis (NF).  The disorder occurs in approximately 1:3,000 births and happens either through inheritance or through a random genetic mutation.  Jack’s case was the latter in that there is no NF present in his family. NF can manifest itself in countless ways and vary from person to person.  It does not discriminate on age, gender, race or socio-economic status.  It mainly causes tumors to grow ANYWHERE on the body that has a nerve ending.  These tumors, while usually benign can be problematic because of their location in the body and/or size.  Since there is no effective treatment, invasive surgery or chemotherapy are the only options to try to reduce or remove the tumors. Jack currently experiences reduced muscle tone and mild learning difficulties due to NF. Jack also has a neurofibroma (tumor) in his left orbital area causing pressure on his eye.  He had surgery to reduce the tumor when he was just 6 years old.  Due to the location they were not able to remove the tumor in its entirety but did reduce the size.  However, a potential issue with NF is that the tumor could actually grow back larger but we have not seen that yet.  In 2013, after a routine MRI, it was discovered that Jack had a glioma (tumor) on his brainstem and immediately began a course of chemotherapy to reduce or remove the tumor.  He battled 52 agonizing weekly chemotherapy treatments and while the glioma was reduced a bit in size it remains in his brain.   In October 2015, he endured brain surgery to create more space at the base of his skull as he had accumulated a buildup of cerebral fluid caused by the glioma which led to the development of a syrinx on his spinal column.  Without timely intervention, this would cause Jack to lose feeling and function in his extremities.  The effects of the surgery are being monitored and his condition is frequently reassessed. Although challenges are faced daily, Jack braves them eloquently. Rather than lying down, he lives passionately and actively fights to find a cure for this devastating disease. He co-founded CureNFwithJack about 6 years ago to raise money for research and awareness about Neurofibromatosis.  After actively fundraising for the past 4 years he has gained thousands of followers on social media (Facebook, Twitter, Instagram) and has selflessly raised over 1 million dollars for research to cure NF.  SOARD provided Jack with a room makeover as extraordinary as he is.  Although he is a radiant ray of sunshine bringing wonder to all who meet him, this room shined bright when he walked in!  You can learn more about Jack at www.curenfwithjack.com and watch a short film about his journey http://curenfwithjack.com/content/jacks-journey.","quote":"Meet Jack.  Jack is mature beyond his years with an amazing drive to have a positive impact on his community and the world at large.  With a cheerful and content disposition, he faces daily challenges that would bring the strongest of us to despair, but he keeps on keeping on with a smile and vigoro","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/photo-03/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/choa/photo-09/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/photo-05/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/photo-06/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eli/photo-21/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/photo-08/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/photo-09/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/photo-10/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/photo-11/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/photo-12/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/photo-13/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/photo-14/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/photo-15/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/photo-16/public","alt":"Jack makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/photo-17/public","alt":"Jack makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/c12d1c5a-919e-4acc-39c4-169dcd03e500/full","source":"wix-migration","wixNumber":38},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('jackson', 'Jackson', 2026, 'in-progress', 0, 1, 1, '{"name":"Jackson","slug":"jackson","age":10,"diagnosis":"SYNGAP1","roomTypes":["Therapy Room"],"year":2026,"status":"in-progress","bio":"Jackson has a SYNGAP1-related neurological disorder, Level 3 autism, and Lennox-Gastaut syndrome, complex conditions that cause severe developmental delays, limited verbal communication, and frequent, difficult-to-control seizures. These diagnoses impact nearly every aspect of his daily life.\n\nJackson is incredibly bright and curious. He is also highly active and has little awareness of danger, which means his parents must provide constant supervision to keep him safe. He can quickly figure out how to open doors, requiring his family to take extra precautions throughout their home.\n\nJackson loves to climb and seeks out sensory input through movement, jumping, and active play. Because of his sensory needs and safety challenges, a dedicated therapy bedroom designed specifically for him is essential.","quote":null,"heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jackson/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jackson/photo-01/public","alt":""}],"photoCount":1,"videoUrl":null,"photographer":null,"partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/wyp/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('jacob', 'Jacob', 2017, 'completed', 0, 1, 1, '{"name":"Jacob","slug":"jacob","age":9,"diagnosis":"Autism, PDD-NOS, Sensory Integration Disorder, Anxiety, Developmental Delays","roomTypes":["Therapy Room"],"year":2017,"status":"completed","bio":"Jacob is a ray of sunshine who gives amazing hugs and kisses!  Jacob is an energetic, bright boy who loves tractors, trains, and trucks.  Jacob was gifted to his parents through the joy of adoption.   What a wonderful surprise and blessing.  His parents traveled far from Georgia to Wyoming to meet him and take him back home to his forever home. \n\nJacob was a wonderful baby.  He didn''t cry much, never took a pacifier and ate very well.  He was developing as expected and then one day things just changed\\u2026no more hugs, he refused food, and he didn''t talk. He experienced a regression of skills.  Jacob''s pediatrician told his parents he was just slow as little boys often are and that they should not worry.  They knew something was different and to ensure the best for him, they were certain that they needed to seek the help of another physician.  A new pediatrician agreed and worked toward finding out why he was regressing.  Jacob was diagnosed with Autism, PDD-NOS, Sensory Integration Disorder, Anxiety and developmental delays.  He was enrolled in school and therapy to help meet his developmental milestones.  He has received occupational and speech therapy since he was 3.\n\nAt nine, Jacob has come a long way and is developing his own personality! He is funny, likes to be silly, enjoys being squeezed with deep sensory input and loves time with family.  He especially loves playing with his cousins!  His favorite places to go include McDonald''s, Wendy''s, Great American Cookie and going to the TA truck stop to watch the trucks come through.  \n\nHe loves his therapists and teachers and learns a lot from them.  However, he inspires and teaches those around him something new every day!  SOARD plans to give Jacob a dream therapy room and include items that provide sensory input as well as a few of his favorite things throughout the specially designed d\\u00e9cor.","quote":"\"Jacob inspires and teaches those around him something new every day!\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jacob/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sC