INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('janiyah', 'Janiyah', 2017, 'completed', 0, 1, 1, '{"name":"Janiyah","slug":"janiyah","year":2017,"status":"completed","bio":"This divine, ray of sunshine is Janiyah. At two months of age Janiyah suffered a nearly fatal traumatic brain injury that left her cortically visually blind, epileptic, microcephalic and severely developmentally delayed.   Beautiful Janiyah was only two months old and in need of a very special couple to provide her with the love, care and steadfast perseverance to overcome the event that changed her destiny.  It was no coincidence that she was blessed with foster parents who consider her to be a gift to cherish unconditionally. Janiyah remained in the hospital and rehabilitation center for 2 months; then went home with her new foster parents at 4 months old. She now enjoys the love of foster parents who see no faults and know no limits. Love that survives and sacrifices beyond the means provided to create a safe home and supply warm hugs to dull the pain.  Love that ensures a future of faith, hope and love. She is fully dependent on her foster parents who went from a two income home to one to provide her care around the clock as she is medically fragile.  Janiyah sees thirteen specialists including a neurologist, physical, occupational and speech therapists.  She has shown the most positive response from therapy which uses assistive technology to provide toys and interactive tools for children with limited mobility and communication.  She is also excelling in vision therapy.  Janiyah enjoys coloring and playing games using an innovative software called “Eyegazer”.  She uses her eyes to control the software and complete the tasks of her choice.  Janiyah also loves to relax while surrounded by fiberoptic lights and the sensory center.  She smiles when she hears familiar voices, clapping, music and songs. Her foster parents dedicate themselves to advocating for her and helping get her needs met; one look at her innocent, precious face is a reminder that quitting is never an option. Sunshine on a Ranney Day understood the challenges Janiyah and her foster family were faced with and wanted to bring a plethora of smiles to her gorgeous face by providing her with a room makeover and wheelchair accessible bathroom that was as beautiful as she is! A room that shimmers and sparkles and meets her unique needs.  Janiyah''s makeover goes in the books as one of the happiest and most emotional makeovers we''ve ever completed.  When the family entered the room, the happiness and joy over flowed from Janiyah''s parents and spilled on to everyone else in that room.  There wasn''t a dry eye in the house, in the best way possible. So many of the family''s close friends, therapists, and nurses showed up to celebrate Janiyah and her new gift of an accessible bedroom and bathroom.  The reveal was so heartwarming!  Deidre, Janiyah''s foster mom, was so moved by her makeover that she came as a guest speaker at the 2017 Evening of Sunshine Gala.  She gave her testimony and it was so beautiful.  We hope that the family and Janiyah will continue to have passion in their hearts and that this makeover continues to be a blessing year after year.","quote":"This divine, ray of sunshine is Janiyah. At two months of age Janiyah suffered a nearly fatal traumatic brain injury that left her cortically visually blind, epileptic, microcephalic and severely developmentally delayed.   Beautiful Janiyah was only two months old and in need of a very special coupl","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/hero/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/hero/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-42/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-43/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-46/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-50/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/janiyah/photo-11/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/janiyah/photo-12/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ayden/photo-15/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/janiyah/photo-14/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-48/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/angel/photo-61/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/janiyah/photo-17/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/anderson/photo-16/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/janiyah/photo-19/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/janiyah/photo-20/public","alt":"Janiyah makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/janiyah/photo-21/public","alt":"Janiyah makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/d02b92ba-53b9-4f96-fac7-00ebd2cdc000/full","source":"wix-migration","wixNumber":64},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('jason', 'Jason', 2023, 'completed', 0, 1, 2, '{"name":"Jason","slug":"jason","age":19,"diagnosis":"Cerebral Palsy & Dystonia","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2023,"status":"completed","bio":"Jason recently completed his freshman year at University of West Georgia! He was born a preemie weighing 2lb 9oz, spent 86 days in the NICU and by age one he was diagnosed with Cerebral Palsy and Dystonia. Today, Jason is wheelchair bound and uses a power wheelchair like a boss! He is completely dependent on someone to assist him with everyday life. Since he is not able to use his arms, he must be fed, but can clearly tell you that the food is too hot, salty or disgusting. So from the neck up Jason is a \"typical\" 17-year-old!\n\nFor Jason to take a shower, his family needs to undress him in his room and carry him through most of the house to reach the bathroom. Once in the bathroom, he uses a tub chair to shower. However, when Jason goes to camp and respite, he has a lot more independence and ability to do normal things like showering and using the restroom because of the accessibility of the bathrooms there. Because of this, he loves when he goes to camp - so we can''t wait to help him have the same feeling about his own space in his house! \n\nAside from going to camp, Jason loves going to the movies with friends and family to watch Marvel movies - of which he is an avid fan! He also loves anything Anime and frequently reads Fan Fiction Anime. His favorite places to visit are New Orleans and DC, but he has dreams of going to New York City! At home, Jason''s younger sister, Junia, frequently keeps him entertained with all kinds of shenanigans.","quote":"\"...from the neck up Jason is a ''typical'' 17-year-old!\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jason/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFu