INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('jessie', 'Jessie', 2017, 'completed', 0, 1, 1, '{"name":"Jessie","slug":"jessie","year":2017,"status":"completed","bio":"Meet Jessie and her bestie, Mo.  They are an adorable duo with an unbreakable bond.  They are also the next recipients of an amazing bedroom and therapy room makeover from Sunshine on a Ranney Day.  Jessie is thirteen and has had Mo, the gorgeous Goldendoodle as her service dog and best friend for two joyous years.  Jessie loves music, rhythm and singing. She is very talented and wants to be famous. She also enjoys therapeutic horseback riding and trapeze. She spends a lot of time at Canopy Studios performing on the trapeze. Her aspiration and passion shines through every time she practices. Jessie was born in Sao Paolo, Brazil and was placed in an orphanage immediately following her birth. She came to the US when she was two on a medical visa and was adopted by her forever family at the age of three.  Soon after her arrival in the US, she was diagnosed with Fetal Alcohol Syndrome and Failure to Thrive.  She was fragile and tiny weighing only seventeen pounds.    The first few years were quite difficult, but she never gave up.  Jessie endured eye surgery to correct ptosis and strabismus, had several sets of ear tubes, was diagnosed with hearing loss, autism and sensory processing disorder.    Mo has been a wonderful addition to the family.  He goes everywhere with Jessie, even to school. Mo has helped tremendously in reducing Jessie’s anxiety, preventing meltdowns and keeps her from wandering off.  He has opened her world to others as well because he is a good conversation starter.  This facilitates interaction with peers. Despite her progress, Jessie recently experienced a psychological episode and has developed a severe motion disorder. She has tremors in her arms and legs. These tremors make it impossible for her to sit still, write, color, or even feed herself. So far doctors have been unable to find a reason for the tremors and they are currently trying to find a medication that makes them manageable. These setbacks do not get Jessie down.  She continues to grow and reach for the stars.  Sunshine on A Ranney Day planned to provide her with an exquisite room makeover that met all of her needs and put smiles on her and Mo’s faces! &quot;Miss Jessie''s Sunshine on a Ranney Day Makeover Day&quot;, it says it right on Jessie''s proclamation that she received personally from the mayor''s office from the City of Winder.  What a special day it was for Jessie indeed!  Jessie was an outstanding makeover kid by not peeking at all into her makeover for 2 whole weeks prior to her reveal.  Pat and Janice Vinson even came to the reveal to hear her exclamation of excitement upon entering her rooms for the first time.  With the love and support of family, friends, and even members from the City of Winder at the reveal, it was one for the books.  Jessie received so many surprises that by the end of the reveal, she was plumb wore out.  Even Jessie''s therapy dog, Mo, seemed to appreciate her new bed and made himself right at home.  Enjoy the new space you two!","quote":"Meet Jessie and her bestie, Mo.  They are an adorable duo with an unbreakable bond.  They are also the next recipients of an amazing bedroom and therapy room makeover from Sunshine on a Ranney Day.  Jessie is thirteen and has had Mo, the gorgeous Goldendoodle as her service dog and best friend for t","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-40/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alejandro/photo-21/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/anderson/photo-07/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-46/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jessie/photo-07/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jessie/photo-08/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jessie/photo-09/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alejandro/photo-33/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jessie/photo-11/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/connor/photo-17/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jessie/photo-13/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/anderson/photo-16/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jessie/photo-15/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jessie/photo-16/public","alt":"Jessie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jessie/photo-17/public","alt":"Jessie makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/d02b92ba-53b9-4f96-fac7-00ebd2cdc000/full","source":"wix-migration","wixNumber":70},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('jocelyn', 'Jocelyn', 2018, 'completed', 0, 1, 1, '{"name":"Jocelyn","slug":"jocelyn","age":4,"diagnosis":"Retinoblastoma in right eye","roomTypes":["Dream Bedroom"],"year":2018,"status":"completed","bio":"Chemo therapy was tough on her petite body. Not only did she lose her hair, but also her energy and the joys of childhood.\n\nHowever, within two short months it returned and was more aggressive. Dr. Hubbard decided that she needed intra-arterial chemo. They placed Jocelyn under anesthesia again for this procedure that placed a small tube through her thigh, up through her heart to right behind her eye. This allowed for the chemo to be delivered directly to her eye via her own blood flow. Due to an adverse reaction that only happens in 0.01% of kids, Jocelyn lost her vision and her eye swelled significantly. This swelling lasted four months and they were unsure of what the course of action would be. It only took one month for the cancer to return and it spread rapidly. The new plan of treatment was injections of chemo directly into the eye while she was under anesthesia. At first it worked, but after only three treatments they found numerous tiny tumors referred to as seeds were spreading throughout her eye. The doctor reported that it was so severe that it could possibly spread to other parts of the body. The most significant concern was that it could eventually spread to the brain via the optic nerve. They continued to fight to save her eye with laser treatments and cryotherapy, but ultimately to save her life and spare her from losing vision in her left eye, they decided it was time to remove the eye itself. This decision was the most difficult of all. Knowing that this could affect her confidence later in life, they struggled with the thought of her living a fulfilled life without her right eye. They imagined her on her prom night wondering why she had to endure this. However, they quickly concluded that she already lost her vision and was at risk of losing her life. The wisest decision was to remove the eye to save her life. They fought hard to try to save the eye and attempted every available option; but, saving her beautifully cherished life was the only choice in the end. As they look toward a bright future, they look forward to her prom night where she will shine radiantly; and, they can bask in the greatness of all of the wonderful moments they share. Not only did they celebrate Jocelyn and her dream bedroom makeover, her reveal was on Veterans Day (observed) 2018. Jocelyn''s father is a proud soldier in the United States Marine Corps. From Jocelyn''s dad: \\u201cI am currently a Gunnery Sergeant in the United States Marine Corps. I''ve served in the reserves for 18.5 years. During this time my greatest honor has been able to serve with the finest Marines a person could hope to serve with. We were never perfect, but we always made an incredible team. I was deployed twice to Iraq. The first time, I withdrew from my college classes and had the privilege to serve with a unit that earned the Presidential Citation award. I was on-the-spot meritorious promoted to Cpl after my first deployment. I was deployed again and fell in with another incredible unit. We always meet mission and improved the area that we were in. We were awarded the Navy Unit Citation. I was awarded a combat meritorious promotion to Staff Sergeant during this time. I have been fortunate enough to serve on many funeral honors in every position; to playing the bugle, firing squad member, squad leader, and flag presenter...It has been a humbling experience to be there when our nation''s heroes are laid to rest for the final time...I''ve also been awarded the Navy and Marine Corps. Commendation Medal for my time while serving in a Supply Chief status and my outstanding performance in carrying out the functions and duties of Logistical Chief at the same time. I have earned a Brown Belt in the Marine Corps. Martial Arts Program (MCMAP). I''ve also earned my sixth award for the Selected Marine Corps. Reserve Medal. During the times of deployment the Global War On Terrorism Expeditionary Medal, Two Armed Forces Reserve Medal, Global War On Terrorism Service Medal, Two Sea Service Deployment Ribbons, and Iraq Campaign Medal with two stars was awarded. In addition to these I also have been awarded 4 Certificates of Commendations, 3 Letters of appreciation, and one Meritorious Mast.\\u201d Sunshine on a Ranney Day is proud to have designed an amazing dream room makeover specifically for Jocelyn.","quote":"Chemo therapy was tough on her petite body. Not only did she lose her hair, but also her energy and the joys of childhood.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jocelyn/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jocelyn/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jocelyn/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jocelyn/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jocelyn/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jocelyn/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jocelyn/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jocelyn/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jocelyn/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jocelyn/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jocelyn/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jocelyn/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sC