}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"_migration":{"scrapedAt":"2026-03-06T13:32:09.451Z","source":"wordpress-xml-export","wpPostDate":"2021-06-25 22:11:34","wpCategories":["Meet the Kids"],"wpTags":["2019","Therapy Room"],"thumbnailId":1182,"needsReview":[],"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/cc94e825-34a5-4bfa-d3f7-065bb1ab7200/full"},"streamVideoId":"37f8ecc4927674d3d2f90f2297457493","roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('joseph-2022', 'Joseph', 2022, 'completed', 0, 1, 2, '{"name":"Joseph","slug":"joseph-2022","age":5,"diagnosis":"Spina Bifida Myelomeningocele","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2022,"status":"completed","bio":"Joseph has always been a little Superman. Even after receiving the prenatal diagnosis of spina bifida, we couldn''t have been prepared for the challenges we were about to face. Joseph was born prematurely with a large, open hole in his spine and bravely began his life with 77 days in the NICU. He underwent ten surgeries, countless medical scans and tests, revolving doctor appointments, and multiple hospital stays, which are the routine for so many special needs children. This can be scary for a young child, but Joseph is brave beyond his years.  \n\nLike many children with spina bifida, Joseph developed hydrocephalus, a condition that allows fluid to accumulate in the brain. This can cause brain damage from the buildup of pressure. Joseph had a shunt surgically placed in his skull as a newborn to protect his brain. The tiny tubing and valve keep the fluid that cushions the brain freely flowing. Despite the effects of hydrocephalus and an underdeveloped cerebellum, Joseph grew into a smart, funny little five-year-old boy.\n\nFor the first year and a half of his life, Joseph required 24-hour oxygen and a feeding tube for all his nutrition. By 18 months, he received his first tiny wheelchair as he is paralyzed from the waist down. He was non-verbal and used a voice-producing device until the was three and half years old. Then one day he recited the entire alphabet and hasn''t stopped talking since! Today, he only requires supplemental oxygen at night and eats by mouth on his own. He loves showing off his wheelchair \\u201ctricks,\\u201d meeting new people and learning their names. Although he has some developmental delays you will notice when you meet him, what outshines those is how earnestly he wants to be your friend. He has a strong memory for stories and loves to repeat (and repeat!)  the adventures of historical heroes he has learned about.\n\nJoseph''s determination through each health challenge is growing into a resolution to be independent. His family and amazing team of therapists is doing everything they can to help him accomplish this. Unfortunately, even something as simple as a narrow doorway can thwart his efforts. That obstacle, along with a flight of stairs, means he must be carried to his bedroom. And this is just the beginning of how Joseph becomes like an infant all over again. He must be lifted to a changing station for diaper changes and all his grooming and bathing needs are fulfilled by mom and dad in a bathroom designed for those who can walk independently. \n\nGenerous friends of the Smith family sent Joseph''s story to Sunshine on a Ranney Day and soon Joseph will have the independence and dignity he desires. The makeover of a downstairs bedroom and the transformation of a bathroom that is not accessible will provide him with the physical means to begin an independence that will stay with him his entire life. We are incredibly excited and grateful to everyone involved with this phenomenal gift.  \n\nJust like Superman, underneath his sweet smile and friendly conversation, Joseph has strength and bravery that has kept this little guy soaring through everything life presents. Thank you to Sunshine on a Ranney Day for breaking down walls to help Joseph not just roll, but fly!","quote":"\"He loves showing off his wheelchair \\u201ctricks,\\u201d meeting new people, and learning their names.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/hero/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph-2022/photo-16/public","alt":""}],"photoCount":16,"videoUrl":"https://www.youtube.com/watch?v=qZ0e3UrxoxM","photographer":"Vicki Alsup Photography","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/beazer/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/crosby-design-group/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/mohawk/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/interceramic/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/american-signature-furniture/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/echols/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/builders-cabinet-company/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/asv-productions/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cambria/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cr-construction/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pulleyassociates/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/delta-faucet/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/devore-johnson/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/top-knobs/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/vicki-alsup/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"da79854da0a0d8fe1c689e75d6b87d3b","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('joseph', 'Joseph', 2019, 'completed', 0, 1, 2, '{"name":"Joseph","slug":"joseph","age":19,"diagnosis":"Spina Bifida","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2019,"status":"completed","bio":"During pregnancy, Joseph''s parents were given the news that Joseph was going to be born with Spina Bifida as well as a Chiari malformation, which is s structural defect in the brain, and hydrocephalus.\n\nHis disabilities do not define who he is and he never lets them slow him down. Joseph always has a smile on his face, loves to laugh and make jokes. He has a deep love for sports and has played Baseball, Wheelchair Basketball and Wheelchair Football. His incredible passion for sports is unwavering and he loves not only to play, but also to watch or help coaching younger teams. He currently helps manage his old 8th grade Middle School team at Vickery Creek Middle. Joseph aspires to work for a professional sports team one day. He is always willing to try new adventures and works diligently to reach his goals. He is encouraged to dream big and he will surely succeed as he never gives up. Sunshine on a Ranney Day is overjoyed to be working on a special renovation project designed especially for Joseph. This project will not only provide him with a fabulous new room, but also an accessible bathroom. Join us in spreading cheer throughout his home so he can enjoy his bright future in style.","quote":"During pregnancy, Joseph''s parents were given the news that Joseph was going to be born with Spina Bifida as well as a Chiari malformation, which is s structural defect in the brain, and hydrocephalus.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/joseph/photo