INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('josue', 'Josué', 2026, 'in-progress', 0, 1, 1, '{"name":"Josué","slug":"josue","age":18,"diagnosis":"Cerebral Palsy","roomTypes":["Dream Bedroom"],"year":2026,"status":"in-progress","bio":"At just 17 years old, Josue, has faced extraordinary challenges from a young age. After overcoming TB meningitis as an infant, he was later diagnosed with cerebral palsy. Josue, who requires intensive, hospital-level care at home, spends most of his time confined to his bedroom. He is unable to sit up without help, depends on g-tube feeding, and is nonverbal. His devoted single mother, a constant source of love and support, dedicates herself to his care, often sleeping in the same room to closely monitor him throughout the night. Josue''s world is a small one, centered around his mother and his bedroom.","quote":null,"heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/josue/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/josue/hero/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/josue/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/josue/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/josue/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/josue/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/josue/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/josue/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/josue/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/josue/photo-09/public","alt":""}],"photoCount":9,"videoUrl":"https://youtu.be/VbciIUNjSYI?si=Gct2-ahjQ9ZeIkNx","photographer":null,"partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/gas-south/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/jackson-healthcare/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cr-construction/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"5dc82e32c399eb0980daef7414e2b6b5","roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('juan', 'Juan', 2021, 'completed', 0, 1, 2, '{"name":"Juan","slug":"juan","age":16,"diagnosis":"Cerebral Palsy","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2021,"status":"completed","bio":"Like most teenage boys, he is taller and heavier than his petite mother. This creates a substantial challenge when transferring him from the wheelchair to the bathroom and into the tub.\n\nJuan''s medical, therapeutic and care needs are extensive and carry a significant expense. He receives special education services at school and attends physical therapy three times per week. His mother is a single parent working full time to provide him with the support and services he needs to achieve his goals. In addition to requiring extensive therapy, he also needs assistance in dressing, bathing, and getting in and out of the car and shower. Like most teenage boys, he is taller and heavier than his petite mother. This creates a substantial challenge when transferring him from the wheelchair to the bathroom and into the tub. The bathroom is too narrow for both of them and is not designed for an individual with special needs. As a result, she has to bathe him in his bed. Not only is this uncomfortable, but Juan also desires more privacy as he nears adulthood. His mom''s greatest wish is being able to gift him a home in which he will be able to achieve independence as an adult. Juan''s greatest wish is to reduce the painful burden of lifting and carrying him that his mother endures selflessly. \n\nSunshine on a Ranney Day is privileged to have the opportunity to make Juan''s dream come true! With the generous support of our donors, we will be renovating his home to expand his bedroom and transform his tiny bathroom into a fully adaptable bathroom that will make life a lot easier for both Juan and his mom. We hope this gift will lighten their burdens, lift their spirits and evokes endless smiles!","quote":"Like most teenage boys, he is taller and heavier than his petite mother. This creates a substantial challenge when transferring him from the wheelchair to the bathroom and into the tub.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juan/photo-18/public","alt"