lAfM","photographer":"Sweet Life Photography by Kim","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bt/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cardinal-construction/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-paulson/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/interceramic/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/reliable-heatingair/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/rooms-to-go/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/mohawk/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/echols/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/signature-hardware/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pulleyassociates/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/delta-faucet/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/devore-johnson/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/sweet-life-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"_migration":{"scrapedAt":"2026-03-06T13:32:09.469Z","source":"wordpress-xml-export","wpPostDate":"2021-06-26 22:38:42","wpCategories":["Meet the Kids","Randall Paulson Architects"],"wpTags":["2021","Accessible Bathroom","Dream Bedroom"],"thumbnailId":1268,"needsReview":[],"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/308b7af2-0b66-471e-2163-01acc72b2700/full"},"streamVideoId":"737096ac7a997c0b4171994d5acb488c","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('juana', 'Juana', 2018, 'completed', 0, 1, 2, '{"name":"Juana","slug":"juana","age":17,"diagnosis":"Encephalitis","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2018,"status":"completed","bio":"Like all sweet little girls, Juana spent her early childhood dreaming of what she be when she grew up.  Her dream was to be a teacher.  She aspired to make a difference, share her knowledge and help others shine.  She loved playing with pencils, books, notebooks, chalkboards and crayons.  She had all the essential tools, enthusiasm, compassion and intelligence needed for the job.  She even had experience.  She loved taking care of all of the children in the family and babysitting was something she excelled at.\n\nWhen Juana was fourteen, she was excitedly planning  her Quinceanera Party in Mexico.  This celebration was something she looked forward to every day with excitement and sweet anticipation.  Unfortunately, Juana became very ill and never got to enjoy her Quinceanera.  Juana had been sick for two weeks with what doctors had said was the flu.  It seemed to get worse and worse.  She was spending time with her sister Cecilia when she became critically ill.  She had fever, chills and nausea.  Then she developed a significant headache and became incoherent.  Cecilia took her to the ER.  It was a wild ride of examinations without answers before they finally identified the problem.  Her brain was significantly swollen due to encephalitis caused by an autoimmune disorder.  Her brain was so swollen that doctors had to induce a coma.\n\nAfter five days in a coma, doctors said they did not expect Juana to pull through.  She was on life support and they asked the family if they wanted to disconnect her.  Her family chose to continue to fight for a miracle and three weeks later she finally opened her eyes and began to breathe on her own.  Juana never fully recovered.\n\nJuana has endured brain surgery, experiences seizures, is in constant pain and has never regained her functional mobility.  She cannot walk or talk and has difficulty breathing.  Losing her abilities has been challenging for her and her family.  The encephalitis changed her life in a devastating way and has affected her both physically and emotionally.  Our goal is to bring Juana a whole lot of sunshine!  Lifting her spirits, making her smile and bring back some of her joy is our mission!","quote":"\"Her family chose to continue to fight for a miracle and three weeks later she finally opened her eyes and began to breathe on her own.\\u00a0\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juana/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juana/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juana/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juana/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juana/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juana/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juana/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juana/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juana/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juana/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juana/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juana/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juana/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juana/photo-13/public","alt":""},{"url":"https: