agedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cortland-partners/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/dental-now/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/chattahoochee-diposal/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"_migration":{"scrapedAt":"2026-03-06T13:32:09.411Z","source":"wordpress-xml-export","wpPostDate":"2018-03-27 19:17:54","wpCategories":["Meet the Kids"],"wpTags":["2018","Accessible Bathroom","Dream Bedroom"],"thumbnailId":6840,"needsReview":[],"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/14ccc2db-284b-4c55-9fd1-8db5b7b40a00/full"},"streamVideoId":"cccb6f4de1c340b619e33898918f246c","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('juliana', 'Juliana', 2018, 'completed', 0, 1, 2, '{"name":"Juliana","slug":"juliana","age":15,"diagnosis":"Cerebral Palsy, Hearing Loss, Retinopathy","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2018,"status":"completed","bio":"Juliana was born at 24 weeks weighing 1lb 6oz.  She survived on prolonged ventilator therapy and IV antibiotics for 5 months.  During her stay at the NICU she experienced numerous infections, a surgery for necrotizing enteric colitis, holosystolic murmur, patent ductus atreiosus and neonatal hypothyroidism.  This jovial warrior fought hard and survived all of these treacherous tribulations. \n\nLater, she was diagnosed with Cerebral Palsy, sensorineural hearing loss in the right ear and retinopathy of prematurity.  She has endured numerous surgeries including eye surgery and leg lengthening surgery.\n\nShe has been in physical and occupational therapy for fifteen years and continues to focus on her functional targets.  She works diligently towards becoming independent.  She uses a walker in school and a wheelchair for long distances.  She has recently begun to ambulate more independently by holding on to furniture and walking.  This is a cherished sight in her home!  Juliana enjoys therapeutic horseback riding, buddy baseball and summer camp.  \n\nThis lively teenager is a miracle who has never allowed her disability to limit her from enjoying life.  She has radiant smile that illuminates the world around her. It was this amazing smile that landed her the role of being an extra in the movie Mother''s Day and also was in the video for TV Teacher together with her sisters.\n\nAs any typical teenager, Juliana fights with her sisters over the TV remote, loves technology and spends her time listening to music and watching videos on You-Tube.  She also loves using apps on her iPhone and tablet.","quote":"\"This lively teenager is a miracle who has never allowed her disability to limit her from enjoying life.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/juliana/phot