FuPmfN2vPS6mt5sCkZQ/partners/kristi-weaver-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/atlas-disposal/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/rooms-to-go/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/reliable-heating-and-air/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/jackson-healthcare/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cr-construction-v2/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/levino-jones/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/the-town-carpenter/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/johnny-on-the-spot/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"_migration":{"scrapedAt":"2026-03-06T13:32:09.409Z","source":"wordpress-xml-export","wpPostDate":"2018-03-26 22:24:45","wpCategories":["Meet the Kids"],"wpTags":["2018","Accessible Bathroom","Dream Bedroom"],"thumbnailId":6741,"needsReview":[],"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/980e366f-9c04-44c1-de5b-1dc5652adb00/full"},"streamVideoId":"cccb6f4de1c340b619e33898918f246c","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('junializ', 'Junializ', 2026, 'in-progress', 0, 1, 1, '{"name":"Junializ","slug":"junializ","age":19,"diagnosis":"Type III Stroke","roomTypes":["Accessible Bathroom"],"year":2026,"status":"in-progress","bio":"Junaliz was born prematurely at 29 weeks in Puerto Rico due to her mother''s experience with domestic violence. She faced severe medical challenges, including a Type III stroke and hydrocephalus, requiring lifelong care from her single mother. After Hurricane Maria left them homeless in 2017, Juniliz and her mother were evacuated to Atlanta, where Junaliz''s fragile health continues to demand extensive care.\n\nNow battling lupus and fibromyalgia, her mother struggles to manage Junaliz''s needs. As both mother and daughter age and their medical conditions progress, caregiving will become increasingly difficult. SOARD aims to reduce future burdens on the mother and daughter by providing a wheelchair-accessible bathroom with a zero-entry shower.","quote":null,"heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/junializ/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/junializ/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/josue/photo-09/public","alt":""}],"photoCount":2,"videoUrl":"https://youtu.be/VbciIUNjSYI?si=Gct2-ahjQ9ZeIkNx","photographer":null,"partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/gas-south/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/jackson-healthcare/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cr-construction/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"5dc82e32c399eb0980daef7414e2b6b5","roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('kaitlyn', 'Kaitlyn', 2022, 'completed', 0, 1, 2, '{"name":"Kaitlyn","slug":"kaitlyn","age":12,"diagnosis":"Cerebral Palsy, Epilepsy","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2022,"status":"completed","bio":"Kaitlyn is a happy and fun-loving 10-year-old girl.  She, unfortunately, lost oxygen during her birth process and experienced seizures shortly after birth.  She had a 16 day NICU stay after birth and experiences many health and gross and fine motor challenges due to her brain injury.  She was diagnosed with Cerebral Palsy at just 8 months old and has been in weekly speech, physical and occupational therapy since just 6 months old.  She also participates in ABA therapy and intensive robotic therapy.   She is unable to use her physical voice but uses a communication device to communicate.  Kaitlyn uses a power wheelchair in the school and community settings and can walk with the support of a gait trainer in her home.\n\nDespite this multitude of challenges, Kaitlyn lives a happy and fulfilling life.  She loves doing yoga, playing Mario Kart with an adaptive controller, and baking with her family.  She runs races with her Dad in an adaptive jogging stroller and has already completed 2 half marathons.  She loves our family beach trips to Hilton Head Island and she even does yoga on the beach!  What fun!  She is active in her church and participates in church worship and dances up a storm each week.  Kaitlyn works so hard to overcome her challenges and puts forth so much effort each and every day.  \n\nWe''re so excited for Kaitlyn to have an accessible space to give her independence and a calm place to relax after those sometimes really tough and overstimulating and overtiring days.  She is already starting to ask about makeup and becoming more interested in fashion so it will be so neat to have a space where she can learn to become more independent as she heads into her teen years soon.","quote":"\"Kaitlyn works so hard to overcome her challenges and puts forth so much effort each and every day\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kaitlyn/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-32/public","alt":""}],"photoCount":18,"videoUrl":"https://youtu.be/2PoP4PD-CEc","photographer":"Pear Tree Photography","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pga-superstore/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/vickers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/interceramic/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/reliable-heatingair/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/builders-cabinet-company/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/mohawk/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/asv-productions/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cambria/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cr-construction/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pulleyassociates/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/delta-faucet/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/rooms-to-go/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/devore-johnson/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pear-tree-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"70c722ba9b0b8a7aeb29e0753fe75745","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('kalen', 'Kalen', 2016, 'completed', 0, 1, 1, '{"name":"Kalen","slug":"kalen","year":2016,"status":"completed","bio":"Kalen is an incredibly resilient, vivacious teenager who shoots for the stars regardless of the obstacles he faces.  His love for life, for basketball and for his friends is inspiring and warms the heart of those around him.  This Junior Hawk just turned sixteen and we want to help bring him a basket full of smiles while celebrating his triumphs as well as his birthday.  Kalen was born a handsome and perfect baby boy who was developing typically into a spunky and fun spirited young man at age seven.  On Friday, February 22, 2008, everything changed.  Kalen was in a serious car accident on the way to watch a basketball game with his sister.  Kalen sustained perilous injuries and he instantly became paralyzed. He had suffered a Chance Fracture at T12-L2.  The devastating news was hard to handle and waiting three days for his surgery was torturous.  Not only was he paralyzed from the legs down, but he also developed bed sores that developed into a permanent Keloidal scar.  Kalen was released from the hospital on April 8, 2008.  Upon release, he went to intensive rehabilitation for more than three weeks.  Kalen along with his strength and resiliency was extraordinary.  He recovered and adjusted to his new life extremely well.  After the accident, Kalen’s biggest fear was how he would be perceived of or treated at school.  To his surprise, there was an outpouring of concern, acceptance and love for him from his friends. It was incredibly moving and uplifting.  He still has the support of those same friends eight years later. They help him move throughout the school in his wheelchair, help him get his lunch, hold an umbrella over him when it rains and advocate for him when others do not accept him unconditionally.  Their acceptance, support and steadfast loyalty as friends has helped him bounce back.  He has learned to be adventurous and try new things such as sleep away camp and that having a disability does not define him.  Although he does not have the use of his legs, he can achieve all his goals.  He is very independent, but his paralysis creates challenges in independence, especially since his home is not modified to meet his needs. Sunshine on a Ranney Day provided a dream wheelchair accessible bathroom and bedroom so he can meet all of his needs and be more independent in the home environment.  His makeover was sure a slam dunk! ","quote":"Kalen is an incredibly resilient, vivacious teenager who shoots for the stars regardless of the obstacles he faces.  His love for life, for basketball and for his friends is inspiring and warms the heart of those around him.  This Junior Hawk just turned sixteen and we want to help bring him a baske","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/hero/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-03/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/grace/hero/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/photo-05/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/anderson/photo-07/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-25/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-46/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/photo-11/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/photo-12/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/photo-13/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/angel/photo-61/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/photo-15/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/photo-16/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/photo-17/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/photo-18/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/photo-19/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/photo-20/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/photo-21/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/photo-22/public","alt":"Kalen makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/photo-23/public","alt":"Kalen makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/bfce39e9-d0ab-4ba4-160b-dfe733fa9600/full","source":"wix-migration","wixNumber":50},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('karson', 'Karson', 2013, 'completed', 0, 1, 1, '{"name":"Karson","slug":"karson","year":2013,"status":"completed","bio":"Meet the Parker family! Kristopher, Brandi, Kaden (7), Karson (5), Korbin (3), and Koen (1). The Parker''s won their makeover at a charity event for Tripp Halstead, the Winder toddler recovering from a serious head injury due to a freak accident at his daycare during strong winds brought on by a storm. The makeover is needed to help their son Karson who is struggling with mitochondrial disease.   Kris and Brandi have been wanting to build a safe room for Kar for a long time but because of financial reasons haven''t been able to make it happen in the timing needed. One of the biggest challenges the family has is making everything &quot;Karson proof&quot; which they say is baby proofing on steroids.  Karson has recently learned to open and close doors. While this is great developmentally, he is now a danger to himself. The &quot;childproof&quot; doorknobs are not Karson proof as they don''t even slow him down. His parents had to push all the furniture against the walls and place anything and everything that he can tip or reach up high so he''s not a danger to himself or his siblings. He has no concept of the danger of sharp objects, not to mention the hazards of a kitchen. All of the drawers in the house have locks and there are baby gates everywhere keeping him out of certain rooms.   The room SOARD created for the Parker family is a Karson friendly therapy room, spacious enough for the entire family to enjoy. The therapy room includes a ball pit, therapy swing, handicap accessible bathroom, and sound system. Our makeover also included some remodeling in their kitchen/dining room. ","quote":"Meet the Parker family! Kristopher, Brandi, Kaden (7), Karson (5), Korbin (3), and Koen (1). The Parker''s won their makeover at a charity event for Tripp Halstead, the Winder toddler recovering from a serious head injury due to a freak accident at his daycare during strong winds brought on by a stor","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karson/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karson/hero/public","alt":"Karson makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karson/photo-02/public","alt":"Karson makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karson/photo-03/public","alt":"Karson makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karson/photo-04/public","alt":"Karson makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karson/photo-05/public","alt":"Karson makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karson/photo-06/public","alt":"Karson makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karson/photo-07/public","alt":"Karson makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/19bad55d-e080-41cc-eb82-d16c3663a800/full","source":"wix-migration","wixNumber":7},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('karter', 'Karter', 2025, 'completed', 0, 1, 1, '{"name":"Karter","slug":"karter","age":6,"diagnosis":"Autism Spectrum Disorder & Global Development Delays","roomTypes":["Therapy Room"],"year":2025,"status":"completed","bio":"Karter is an energetic and loving five-year-old with autism spectrum disorder and global developmental delays. His curious nature and boundless energy drive him to seek constant sensory input, jumping, climbing, rolling, and looking for pressure or tight spaces to feel regulated. However, his inability to recognize danger makes everyday life a constant challenge for his parents, who must always keep a watchful eye on him to ensure his safety. Simple tasks that many families take for granted such as  cooking a meal or stepping into another room, are stressful and overwhelming.\n\nTo give Karter a place where he can play, learn, and grow safely, Sunshine on a Ranney Day is transforming his home with a custom-built in-home therapy room designed just for him. This space will be a true haven secured with lockable doors to ensure his safety, yet filled with joy and freedom. Outfitted with sensory-rich equipment like swings, climbing structures, and compression tools, the room will allow Karter to release his endless energy, explore without fear, and find the calm his body craves. For his parents, it will bring the gift of peace of mind and the chance to experience moments of rest and joy, knowing their son is finally safe and thriving in a space made just for him","quote":null,"heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/karter/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amari/photo-26/public","alt":""}],"photoCount":18,"videoUrl":"https://www.youtube.com/watch?v=zlpzBaEaKl0","photographer":"Niki Murphy","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/fogas-family-foundation/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/jm-wilkerson-construction/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/gas-south/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/comfort-research/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/sherwin-williams/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/servicewise-electric/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/georgia-interior-painting/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/niki-murphy-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/iframe-media/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"12d2de36ea243c9116894dadad2cd55e","roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('katie-2014', 'Katie', 2014, 'completed', 0, 1, 1, '{"name":"Katie","slug":"katie-2014","year":2014,"status":"completed","bio":"This little pumpkin is Katie Adams.  Katie is not only a beautiful ray of sunshine, but also a fighter! Back in February Katie had a fever for 3 days and significant pain in her neck. The pediatrician was initially concerned that she had meningitis, but a myriad of tests including a CT Scan led to the conclusion that she had a more serious condition-a brain tumor.  This diagnosis seemed to make the world stop spinning for Katie’s family.  A neurologist explained that there was a lot of pressure on her brain and they had to do a minor surgery to relieve it.  This surgery was successful; and, they performed an MRI to monitor the results.  At this time, they found out that Katie not only had a brain tumor, but she actually had four of them.  One of the tumors was on her brain stem making it very dangerous.  This news was heartbreaking and terrifying. The day after they discovered the four tumors, Katie endured emergency brain surgery that lasted 8 dreadful hours.  They removed the tumor on her brainstem and expected Katie to be completely unconscious for the next 24-48 hours.  The surgery was successful and she pulled through with a light hearted spirit. When her surgery was complete the doctors came into the waiting room with gigantic smiles on their faces and said, &quot;She''s awake, smiling, and talking...She''s a FIGHTER!&quot;  They couldn’t believe it. This little angel hasn’t stopped fighting since! She has since endured five grueling cycles of chemo therapy.  This journey has included month long hospital stays, dehydration and typhlitis which is a side effect of the chemo which caused the lining of her stomach to tear.  As a result, doctors have had to insert a gastrointestinal tube to help keep her fed and healthy. Katie is currently preparing to begin her sixth and final cycle of chemotherapy.  The doctors are anticipating that she will continue this battle and successfully beat cancer! We are all cheering her on and praying that this final treatment will eradicate all of the tumors for good! Katie has kept a positive mind set and spirit throughout this entire journey.  She has fought each battle with a smile and has not let cancer slow her down! She is still the same loveable, sweet, energetic girl! Sunshine on a Ranney Day wants to brighten her world with a make-over that is as amazing as she is!  We will be replacing all of the flooring in her home to help reduce allergens and create a colorfully sparkling room that she will love to play and laugh in for years to come!  We can waiting to see her face light up as we reveal her new room on October 4th in Winder, GA.","quote":"This little pumpkin is Katie Adams.  Katie is not only a beautiful ray of sunshine, but also a fighter! Back in February Katie had a fever for 3 days and significant pain in her neck. The pediatrician was initially concerned that she had meningitis, but a myriad of tests including a CT Scan led to t","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/katie-2014/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/katie-2014/hero/public","alt":"Katie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/katie-2014/photo-02/public","alt":"Katie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/katie-2014/photo-03/public","alt":"Katie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/katie-2014/photo-04/public","alt":"Katie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/connor/photo-17/public","alt":"Katie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eli/photo-31/public","alt":"Katie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/katie-2014/photo-07/public","alt":"Katie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/katie-2014/photo-08/public","alt":"Katie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/katie-2014/photo-09/public","alt":"Katie makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/693623d4-af79-4f73-8dc5-430e5fa4ed00/full","source":"wix-migration","wixNumber":19},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('katie', 'Katie', 2013, 'completed', 0, 1, 1, '{"name":"Katie","slug":"katie","year":2013,"status":"completed","bio":"Katie Belle is a beautiful and happy 2 ½ -year old with mitochondrial disease. In addition, Katie Belle has severe global developmental delays and is non-verbal. She does not understand speech except her name and &quot;no&quot;. We do not know how long we have left with her, but we are cherishing every moment.  She currently receives occupational therapy, speech therapy, physical therapy and feeding therapy. Katie loves water, loves to be chased around, and will eat just about anything except eggs. She would play outside forever if she could. She enjoys playing in her sand box and sliding down slides. She loves veggie tales. It is the only thing she will watch. She is beautiful, sweet, loving and happy. This project will include the installation of much needed therapy equipment as well as minor room redecoration. ","quote":"Katie Belle is a beautiful and happy 2 ½ -year old with mitochondrial disease. In addition, Katie Belle has severe global developmental delays and is non-verbal. She does not understand speech except her name and &quot;no&quot;. We do not know how long we have left with her, but we are cherishing ev","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/katie/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/katie/hero/public","alt":"Katie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/katie/photo-02/public","alt":"Katie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/katie/photo-03/public","alt":"Katie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/katie/photo-04/public","alt":"Katie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/katie/photo-05/public","alt":"Katie makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/katie/photo-06/public","alt":"Katie makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/a51a88cc-5383-4648-4301-76636bf88e00/full","source":"wix-migration","wixNumber":9},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('kendall', 'Kendall', 2024, 'completed', 0, 1, 1, '{"name":"Kendall","slug":"kendall","age":16,"diagnosis":"Traumatic Brain Injury","roomTypes":["Dream Bedroom"],"year":2024,"status":"completed","bio":"Kendall''s parents are high school sweethearts and had three daughters and one son. Camryn, Kendall, Chase and Kaiden all have such beautifully unique personalities and roles within the family. The matriarch of my family is Kendall''s grandmother. She is affectionately known as Grandma to all. Although she is a feisty and fiery golden ager, she is the peacemaker of the family. Together they are Team Thomas. They are a team not because of their quantity, but because their togetherness is their happy place. They are Team Thomas, party of seven, and nothing can break them.\n\nKendall has a giving spirit and is loveable. She''s a hard worker and very passionate about football. She has always danced to her own beat and always thought outside of the box. Hence, the only female on the North Paulding High School freshman football team. She also played football in fifth grade. Kendall was very active. She refereed soccer, briefly played Lacrosse, loved babysitting, walked dogs, danced at church, and loved volunteering. Her favorite color is pink. Her favorite artists are Beyonce followed by Fantasia, Alicia Keys, and Chris Brown.\n\nTheir story and Kendall''s life suddenly changed on January 11, 2022, when the actions of one person had a piercing and life-altering effect on Team Thomas.. It was the unimaginable tragedy and near fatality of Kendall, who would later become the epitome of the power of prayer. It was that Tuesday, January 11, 2022, when Kendall was tragically struck by a vehicle at school landing on the left side of her head in front of her 11-year-old brother Chase and several others. Kendall was unconscious for almost three months. She sustained a traumatic brain injury and was fighting for her life. Due to the severity of her injuries, she has had to relearn how to do everything, from talking to walking. She has had four brain surgeries and three other procedures to accommodate her breathing and feeding. Although Kendall has made remarkable and miraculous improvements, she still has a long way to go. Nothing much has changed in regard to her infectious spirit, big personality, and love for Beyonce. Her favorite things to do now are singing and going to church.","quote":"\"Kendall has always danced to her own beat and thought outside of the box.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kendall/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kendall/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kendall/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kendall/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kendall/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kendall/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kendall/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kendall/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kendall/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kendall/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kendall/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kendall/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kendall/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kendall/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuP