INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('kennedy', 'Kennedy', 2021, 'completed', 0, 1, 2, '{"name":"Kennedy","slug":"kennedy","age":11,"diagnosis":"Cerebal Palsy","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2021,"status":"completed","bio":"Regardless of what she encounters, she always has a smile on her face.\n\nShe now is able to tolerate more weight and less painful movements where those are concerned. Kennedy scored above average on her school testing and will be going to middle school next year. There are many things that you and I take for granted that she is not able to do for herself\\u2026feed herself, use the restroom herself, or wash herself. These are just a few of the basic care needs that require assistance. \n\nShe could let things like this get her down but she doesn''t. She is an amazing young lady! She wants to be an interior designer when she grows up. She loves watching HGTV, and Love IT or List IT is her favorite with Hometown being a close second. She has even come up with using her initials as the name of her business \\u201cKJH Interior Designs\\u201d.","quote":"Regardless of what she encounters, she always has a smile on her face.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kennedy/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kennedy/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kennedy/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kennedy/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kennedy/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kennedy/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kennedy/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kennedy/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kennedy/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kennedy/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kennedy/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kennedy/photo-11/public","alt":""}],"photoCount":12,"videoUrl":"https://youtu.be/DexBIq29dx8","photographer":"Vicki Alsup Photography","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/gas-south/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/reliable-heatingair/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/emser-tile/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/echols/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cambria/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cr-construction/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/mohawk/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/american-signature-furniture/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pulleyassociates/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/delta-faucet/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/devore-johnson/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/in-the-wood-logo/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pls-carpentry/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/top-knobs/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/vicki-alsup/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/iframe-media/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"b4bca132ee5175ace0732311508ecf2d","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('kessley', 'Kessley', 2018, 'completed', 0, 1, 2, '{"name":"Kessley","slug":"kessley","age":4,"diagnosis":"Spastic Quadriplegia Cerebral Palsy with Dystonia, Hearing Loss, Epilepsy, Amblyopia and Global Developmental Delay","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2018,"status":"completed","bio":"This sweet and sassy four year old is Kessley.  She is a delightful beauty both inside and out.  Everyone around her is blessed and energized by her presence.  She is not only cute, but also feisty.  This little fighter has proven that she is happy to be here and she will stop at nothing to live a fulfilled life.  She has been a fighter since day one. \n\nFollowing a healthy pregnancy, Kessley stopped moving in the womb at 38 weeks gestation.  Upon delivery, they found that this was due to the umbilical cord being wrapped tightly around her body which deprived her from oxygen.  Kessley was immediately intubated following birth.  She had a collapsed lung, needed a blood transfusion and was fighting for her life.  The doctors discovered that she had one very small underdeveloped lung, but the other one was working extra hard to sustain her life.  She had difficulty responding and as a last resort, the pediatrician gave her an epi-pen injection and by the grace of God, it worked.  Her lung inflated enough to get a chest tube in and she was stabilized well enough to be transported to the NICU via helicopter.  In the NICU, she was assisted in her fight for life by a ventilator, chest tube and feeding tube.  Although it was heartbreaking to see her like this, the specialized care helped her to recover and within a few days, she was able to breathe on her own.  Through an MRI, the neonatologist found that there was significant damage to the brain due to lack of oxygen.  He did not expect her to come off of the feeding tube or breathe on her own.  She proved him to be terribly wrong, though! She began therapy in the hospital and was discharged on day 13, breathing and eating on her own.  The tubes were removed and she got to go home.  She was quite the tiny miracle and began to flourish; overcoming obstacle after obstacle.\n\nKessley has Spastic Quadriplegia Cerebral Palsy with Dystonia, moderate bilateral hearing loss, Epilepsy, amblyopia and global developmental delay.  She wears glasses, hearing aids and uses a power wheelchair to get around and a communication device to make her needs known. She attends regular speech, occupational, physical and hippo therapy where she works diligently to continue to make progress.  She is an incredibly hard worker and it is paying off.\n\nKessley has a team of loved ones cheering her on and supporting her every step of the way.  One of her biggest fans is her eleven-year-old brother, Tate.  Tate has been by her side since day one and she has proclaimed that he is the best brother in the whole world.  Together, these siblings have hung the moon and will continue to reach beyond the stars.  With such great support, dedication and a strong will to succeed, the sky is certainly the limit!","quote":"\"This little fighter has proven that she is happy to be here and she will stop at nothing to live a fulfilled life. \"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kessley/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kessley/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kessley/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kessley/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kessley/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kessley/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kessley/photo-06/public","alt":""},{"ur