INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('kyle', 'Kyle', 2017, 'completed', 0, 1, 2, '{"name":"Kyle","slug":"kyle","age":11,"diagnosis":"Duschenne Muscular Dystropy","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2017,"status":"completed","bio":"This young and debonair role model is Kyle and we are proud to be working on a special renovation project for his home.  Despite only being 11 and diagnosed with a rare disability, he demonstrates all of the qualities of a leader and those required to be a successful coach: knowledge of sports; excellent communication skills; the ability to inspire and motivate; determination and patience; physical stamina and a sensitive and supportive approach. Those who know him say he has been special from day one, with a kindness in his heart that puts everyone at ease.  You can certainly see this when he smiles!\n\nKyle is exceptional and admirable in every aspect.  He has big dreams and will let absolutely nothing stand in his way of achieving them, including Duchenne Muscular Dystrophy.  This rare genetic disease causes the body to fail to produce dystrophin, which is a protein which allows muscles to regenerate.  Without appropriate levels of dystrophin, the muscles of the body will atrophy or shrink over time causing a loss of mobility and function.  Children who seem to be developing typically, with strong muscles and healthy bodies will eventually lose many of their motor skills and the function of their organs.\n\nKyle has unwavering determination.  He takes pleasure in every moment of his adventurous life and has resolved to triumph by achieving his long term goals-no matter what!  He aspires to achieve a decorated list of accomplishments including the following plan:\n\nHe will be on the 2021 US Power Soccer World Cup team.\nHe will go to college and get a double degree in Physical Education and Business.\nHe will first be the first Head College Football Coach on the sidelines in a wheelchair.\nHe will then go to culinary school to become a chef.\nAfterwards, he will open a small chain of Restaurants cashing in on his winning record and popularity as a local Coach.\n\nThis makeover will incorporate all of the things he loves most. At the top of his list are his X-box, Florida State University, the Falcons and the Dolphins.  We are excited to see him thrive and enjoying his new room with his sister Emily and brother Conor, oh and can''t leave out the family dog Sam!","quote":"\"He has big dreams and will let absolutely nothing stand in his way of achieving them\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kid