INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('leland', 'Leland', 2025, 'in-progress', 0, 1, 1, '{"name":"Leland","slug":"leland","age":10,"diagnosis":"Spina Bifida, Hydrocephalus, Neurogenic Bowel and Bladder, Chiari II","roomTypes":["Accessible Bathroom"],"year":2025,"status":"in-progress","bio":"Leland has faced significant medical challenges since before birth. His diagnosis of myelomeningocele, the most severe form of spina bifida, was made at 19 weeks gestation. At 24 weeks gestation, he underwent fetal surgery out of state. Born prematurely at 28 weeks, he spent 72 days in the NICU and was later diagnosed with hydrocephalus, GDD, bilateral paralysis of feet and ankles, and other conditions affecting his mobility and organ function.\n\nAs he grows, he continues to make progress, but daily activities will always be physically demanding. His mobility becomes especially limited when he is unable to wear his AFO braces, which makes bathroom routines much more challenging and increases his need for support. These needs are expected to continue as he gets older, making consistent assistance important for his safety, comfort, and independence.","quote":null,"heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/leland/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/leland/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/leland/hero/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/leland/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/leland/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/leland/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/leland/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/leland/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/leland/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/leland/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/leland/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/leland/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/josue/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/leland/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/leland/photo-14/public","alt":""}],"photoCount":14,"videoUrl":null,"photographer":"Nicole Wood","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/gas-south/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cr-construction/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nicole-photography/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('levi', 'Levi', 2023, 'completed', 0, 1, 2, '{"name":"Levi","slug":"levi","age":6,"diagnosis":"Nemaline Myopathy","roomTypes":["Accessible Bathroom","Therapy Room"],"year":2023,"status":"completed","bio":"Levi is a brilliant, sweet and chatty 7 year old boy who loves Ironman, Spiderman and Sonic the Hedgehog. He is affected by Nemaline Myopathy, a rare form of muscular dystrophy. Because NM affects his muscles, he is unable to walk and instead zips around in a power chair. Levi is unable to breathe adequately on his own, so he has a trach and ventilator to help him.\n\nHe has had multiple surgeries and hospital stays in his short life in an attempt to keep him healthy and maximize his quality of life. In moments like these, he loves being around his brother Ari for playtime. He still strives for independence and having a space that is adapted to assist him rather than being another obstacle, will be life changing!","quote":"\"...having a space that is adapted to assist him rather than being another obstacle, will be life changing!\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/levi/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/levi/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/levi/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/levi/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/levi/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/levi/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/levi/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/levi/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/levi/photo-08/public","alt":""}