INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('lexy', 'Lexy', 2018, 'completed', 0, 1, 2, '{"name":"Lexy","slug":"lexy","age":11,"diagnosis":"Spinal Muscular Dystrophy Type 2 and Hypotonia","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2018,"status":"completed","bio":"Meet Alexas.  Her adorable nickname is Lexy, which fits her well.  She is bright, cheerful and is definitely a take charge kind of girl.  She is a ray of sunshine, not only putting a smile on the faces of those she meets, but also bringing sunshine and hope to others with Muscular Dystrophy.  \n\nLexy was born in 2007.  When she turned one, her mom realized that she was not progressing like a typical toddler and soon after, she had multiple medical exams that led to a devastating diagnosis of Spinal Muscular Dystrophy Type 2.  This disorder has brought with it medical complications such as pneumonia, low blood sugar, as well as multiple medications, several complex surgeries and the inability to walk. Lexy relies on her wheelchair to get around and machines to help her breathe and clear her lungs.\n\nAlthough living with MD is challenging, she perseveres and shines as a leader.  She has served as a local Goodwill Ambassador for Muscular Dystrophy for the past 5 years. In 2015 she was nominated the state Goodwill Ambassador for Muscular Dystrophy. She and her team, Alexas''s Army, have participated in the Walk for MDA five years in a row in which her efforts have raised a significant amount of money for the MDA.  She and her mom promote awareness through speeches and networking at this event and within their community.\n\n \n\nAlthough she sometimes questions why she has to live with MD, she has an amazing attitude and inspiring positivity.  Her will to survive and desire to contribute to the good of others is contagious.  This natural born leader loves going to school and adores art.  Her favorite thing in the world is American Girl Dolls.","quote":"\"She is a ray of sunshine, not only putting a smile on the faces of those she meets, but also bringing sunshine and hope to others with Muscular Dystrophy. \"\\u00a0","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lexy/photo-18/public","alt":""},{"url":"https://imagedelive