ROYFuPmfN2vPS6mt5sCkZQ/partners/reliable-heating-and-air/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/mohawk/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/the-town-carpenter/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"_migration":{"scrapedAt":"2026-03-06T13:32:09.409Z","source":"wordpress-xml-export","wpPostDate":"2018-03-26 18:34:16","wpCategories":["Meet the Kids"],"wpTags":["2018","Accessible Bathroom","Dream Bedroom"],"thumbnailId":6686,"needsReview":[],"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/d02b92ba-53b9-4f96-fac7-00ebd2cdc000/full"},"streamVideoId":"cccb6f4de1c340b619e33898918f246c","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('liam', 'Liam', 2024, 'completed', 0, 1, 2, '{"name":"Liam","slug":"liam","age":16,"diagnosis":"Duchenne Muscular Dystrophy","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2024,"status":"completed","bio":"Liam is a funny and artistic 16-year-old living with Duchenne Muscular Dystrophy. DMD is a fatal, genetic disorder marked by progressive muscle loss due to missing exons within his DNA that produces a necessary protein. He began using a wheelchair for long distances when he was eight and lost the ability to stand and walk at 12. Showering and other activities of daily living are very difficult for him now.\n\nHe is an epic gamer. His gaming PC allows him to interact with friends and family, near and far, within a level virtual playing field. A typical weekend will find him and his siblings in one game room at their stations off on an epic adventure together! Liam also uses creativity to explore his thoughts and feelings. He will often say \\u201cCan I have my art stuff?\\u201d so he can draw while he watches his favorite YouTubers, Ten Hundred, Jazza, and Ace of Clay. He has multiple shelves holding dozens of sketchbooks.\n\nOne of the greatest challenges caused by DMD is that his bathroom is difficult to navigate. Liam used to love taking long, hot showers to relieve the stresses of his day and the ache in his weakened muscles. When he lost the ability to stand, he lost the ability to shower comfortably. What was once a joy has become painful, both physically and emotionally. Sunshine on a Ranney Day is looking forward to creating a space that will bring back some of that relief while showering, as well as tailoring it to Liam specifically!","quote":"\"A typical weekend will find him and his siblings in one game room at their stations off on an epic adventure together!\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-19/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-20/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-21/public","alt":""},{"url":"ht