INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('lyra', 'Lyra', 2023, 'completed', 0, 1, 2, '{"name":"Lyra","slug":"lyra","age":7,"diagnosis":"Autism spectrum, sensory processing and speech disorders, global developmental delay","roomTypes":["Dream Bedroom","Therapy Room"],"year":2023,"status":"completed","bio":"Lyra is an incredible 7 year old kid. She has never met a stranger because everyone is a friend and she cares deeply for them. She loves all things glitter, unicorn, and pink. She is a kind, inclusive, and thoughtful kiddo that brightens the world of everyone she knows. She loves to craft and make things like cards, bracelets, pictures, and trinkets for all of her friends. Lyra lives to help especially in the kitchen and caring for the chickens. Her family adores her and she is her little brother''s hero.\n\nHer family learned that Lyra is autistic when she was two and a half years old at the Marcus center and she has grown so much since then. She receives support from services at McKenna farms and Focus on Function. On top of that, she gets to learn at her own pace and in her preferred learning styles at home. Sunshine on a Ranney Day is excited at the opportunity to transform her basement room into a safe learning/therapy room! Her favorite place to be is outside - swings, picking flowers, riding her scooter, horseback riding at McKenna, and anything with water!","quote":"\"She has never met a stranger because everyone is a friend...\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lyra/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lyra/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lyra/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lyra/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/lyra/photo-04/public","alt":""},{"