INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('madison', 'Madison', 2022, 'completed', 0, 1, 1, '{"name":"Madison","slug":"madison","age":12,"diagnosis":"Autism, Dysarthria, Apraxia, SPD","roomTypes":["Dream Bedroom"],"year":2022,"status":"completed","bio":"\"We often call her Goldilocks because she loves to try every bed in the house until she finds the one that is just right.\"\n\nMadison is 12-years old and attends The Link School—a private educational facility that focuses on hands-on learning. She thrives there and enjoys many typical childhood experiences such as pizza and ice cream. She is also an avid hoverboard enthusiast with a passion for Cat in the Hat and Boba Fett. She is a sweet, silly, pink-loving girl. We often call her Goldilocks because she loves to try every bed in the house until she finds the one that is just right. If you ask her what she is doing, she says, \"I''m getting cozy.\\u201d\n\nMadison survived her birth trauma because of her strength and determination. This little spitfire has defied the odds and she continues to work hard in all that she does. We are so blessed that God chose us to be Joshua and Madison''s parents. And we are grateful to Sunshine on a Raney Day for providing a Madison with a bedroom makeover.","quote":"\"We often call her Goldilocks because she loves to try every bed in the house until she finds the one that is just right.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/madison/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/madison/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/madison/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/madison/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/madison/hero/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/madison/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/madison/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/madison/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/madison/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/madison/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/madison/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/madison/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/madison/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/madison/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/istvan/photo-22/public","alt":""}],"photoCount":14,"videoUrl":"https://youtu.be/X5J7h__-KBY","photographer":"Birchfield Photography","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/finlistics-2024/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/reliable-heatingair/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/american-signature-furniture/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bin-there-dump-that/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/mohawk/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/birchfield-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/iframe-media/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"97994d2196734b6edb6fef7200872bb2","roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('mariah', 'Mariah', 2023, 'completed', 0, 1, 1, '{"name":"Mariah","slug":"mariah","age":17,"diagnosis":"Brain Tumor","roomTypes":["Accessible Bathroom"],"year":2023,"status":"completed","bio":"In 2013 when Mariah was nine years old, she had a headache that would not go away.  After several visits to various doctors, Mariah went to the emergency room at Children''s Healthcare of Atlanta.  The emergency room doctor initially thought Mariah had a viral infection but ran a CT scan for confirmation.  The CT scan showed a mass in Mariah''s brain which required a follow-up with a neurosurgeon.  Mariah underwent brain surgery and had the tumor removed and the prognosis was positive, Mariah was expected to recover and unlikely to have any more issues. \n\nUnfortunately, less than one year later Mariah had a regrowth of the tumor which required another surgery for removal.  After the second surgery, the doctors learned that the tumor was extremely aggressive. The type of tumor is called ATRT and the chances of survival are about 50/50. The doctors explained that Mariah would be extremely sick and spend the majority of the next year in the hospital. Mariah was sick at the beginning of treatment but later in the year she was doing so well that the doctors were baffled at how well she tolerated her therapies and medications. Towards the end of Mariah''s treatment, she had difficulty walking and increased weakness in her legs.  An MRI revealed that she had extreme swelling building in her brain and it was affecting all of her motor movements. Mariah''s condition continued to worsen, she eventually lost all of her ability to move and was very close to not being able to breathe on her own. Around 2016 Mariah was using a machine to rattle her lungs so that she would not get pneumonia.  She also needed help with all of her needs including going to the bathroom, getting dressed, and turning over in the night. Mariah was almost like a zombie.\n\nSince 2016, Mariah''s family has been on a path to help Mariah get better. The treatments that she received for her brain swelling left her with bone integrity issues as well as post-menopausal.  She also needed double hip replacements and hormone replacement. She has had one hip replacement.  Mariah has lived with a lot of pain and sadness as to why this has happened to her. However, God has truly used Mariah to grow her parent''s faith and to touch many lives around her in the community. Mariah continues to show signs of improvement to this day. She has not regained the ability to walk or use of her hands but she is much more alert and spunkier! Currently, Mariah attends therapies twice a week and is active in the church.  She is also involved in a special-needs organization called, Extra Special People. These outlets have provided an abundance of joy for Mariah.  Mariah and her parents are so thankful for their family and community.  They are eager to see what the future holds for Mariah and do not think God is finished healing Mariah.","quote":"\"Life has recently become more challenging for our family as Mariah is growing more everyday.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mariah/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-32/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alex/photo-14/public","alt":""}],"photoCount":17,"videoUrl":"https://youtu.be/JV2x2B3hkrg","photographer":"Jennifer Boxley Photography","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/dcrgbstr/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/jackson-healthcare/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cobb-emc-foundation/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/regas-interiors/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/servicewise-electric/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pls-carpentry/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/us-cabinetworks/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/top-knobs/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cambria/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cr-construction-v2/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/echols/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/traditions-in-tile/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/schluter-systems/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/delta-faucet/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pulleyassociates/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/tko-plumbing-2023/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cowan-supply/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bin-there-dump-that/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/niki-murphy-photography/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"9a609ab39a0c06674ee8eedd30bf36e3","roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('marie-and-alondra', 'Marie & Alondra', 2024, 'completed', 0, 2, 2, '{"name":"Marie & Alondra","slug":"marie-and-alondra","age":17,"diagnosis":"Diastrophic Dysplasia & Scoliosis","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2024,"status":"completed","bio":"Marie is a determined, funny 17 yr old with a spinal cord injury. This self-proclaimed night owl loves to dance, cuddle with her orange eyed cat and plays on many wheelchair sports teams, including basketball for Blaze sports and wheelchair tennis. Marie has been active in the Atlanta disability community since the age of 2. Marie has served as a mentor to other disabled children at Georgia disability camps, volunteers at the local children''s hospital and works in a pediatrician''s office part-time. She is currently studying children''s healthcare in college. This rising high school senior excels in math, language arts and science. Marie is a fabulous athlete. She plays basketball for Blaze sports all girls/women team and wheelchair tennis. \n\nWhen Marie graduates high school in late 2024, she hopes to move into a duplex her mother purchased nearby. Michele, Marie''s mom, will be renting out the other side of the duplex to Alondra and her family. This means that Marie can live independently, while also having the security of others closeby. The venture will tremendously help her gain the necessary independence that all young adults long for. Without the remodel, Marie cannot reach the next milestone in her life: learning how to live on her own with just a little help. The duplex needs improvements to make it accessible for both of the girls'' independent living, and that is where Sunshine on a Ranney Day comes in! Both sides of the duplex will receive renovations that will make it possible for both girls to grow towards independence in their daily activities.\n\nIn her current living situation, Alondra has to be carried through the home by her parents because the hallways aren''t wide enough for her wheelchair. This keeps her from being independent, but with an accessible space she can do most things on her own. For seven years, Alondra has lived in a home inaccessible to her needs. She has had many back surgeries and is in physical therapy to learn how to manage life in a power wheelchair. She plans on living with her parents for many years to come, so a home that is accessible to her will be life-changing. Alondra is applying to a technical school to be a medical assistant. Her favorite color is burgundy, and she loves lively Spanish music.","quote":"\"Marie & Alondra will be neighbors; living in the same duplex and equally working towards more independent living.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marie-and-alondra/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marie-and-alondra/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marie-and-alondra/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marie-and-alondra/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marie-and-alondra/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marie-and-alondra/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marie-and-alondra/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marie-and-alondra/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marie-and-alondra/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marie-and-alondra/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marie-and-alondra/photo-10/public","alt":""},{"url":"https://imagedelivery.net