INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('marilyn', 'Marilyn', 2024, 'completed', 0, 1, 2, '{"name":"Marilyn","slug":"marilyn","age":20,"diagnosis":"Morquio syndrome","roomTypes":["Chair Lift","Dream Bedroom"],"year":2024,"status":"completed","bio":"Marilyn is a smart, beautiful, and outgoing 20-year-old girl who loves BTS, shopping, boba, makeup and hanging out with friends and family!\n\nShe was born with Mucopolysaccharidosis (MPS) IV, a rare disease in which the body is missing or does not have enough of an enzyme needed to break down long chains of sugar molecules. Because of MPS she is unable to walk or grow and uses an electric wheelchair. Marilyn wears glasses and hearing aids and has had multiple surgeries to help with her health and mobility.\n\nIn her current room situation, her wheelchair is not able to be brought into the house. She would love to have her wheelchair inside the house so that she is not limited to just being in her room. This room makeover will bring her so much happiness and give her the independence of not needing help from her parents and siblings. Sunshine on a Ranney Day is beyond thrilled to be able to offer wheelchair access into her home and a bedroom of her dreams!","quote":"\"This room makeover will bring her so much happiness and give her the independence of not needing help from her parents and siblings.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-19/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-20/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-21/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-22/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-23/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-24/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-25/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marilyn/photo-26/public","alt":""}],"photoCount":26,"videoUrl":"https://youtu.be/9cGlgaRV5OI","photographer":"Carmen Mari","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/mri-software.svg/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/regas-interiors/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/101-mobility/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/american-signature-furniture/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/servicewise-electric/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/comfort-research/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/carmen-mari-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bin-there-dump-that/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"d7b3f02d123ec68bc496b29e69c4d696","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('marquis', 'MarQuis', 2022, 'completed', 0, 1, 2, '{"name":"MarQuis","slug":"marquis","age":18,"diagnosis":"Mitochondrial Encephalopathy","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2022,"status":"completed","bio":"MarQuis and his twin brother were born without any complications.  When MarQuis was around 10 months old, he was sick with a typical virus and woke up the next day a completely different child.  The initial thought was that MarQuis had a seizure until he had another episode.  MarQuis and his family traveled to multiple cities for an official diagnosis and finally at the age of 2 after a muscle biopsy MarQuis was diagnosed with mitochondrial disorder.  In 2005 MarQuis had an episode that the doctors did not think he would survive but God had other plans.  Fortunately, that was the final episode.\n\nMarQuis is permanently disabled and needs assistance with all daily needs.  MarQuis has a love for life and speaks his own language to communicate his needs.  His house is currently not accessible which is very challenging for his family and caregivers.  MarQuis and his family are so excited for MarQuis to have a space that is truly his own and reflective of his personality!","quote":"\"MarQuis has a love for life and speaks his own language to communicate his needs.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marquis/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marquis/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marquis/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marquis/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marquis/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marquis/photo-05/public","alt":""},{"u