INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('mary-elizabeth', 'Mary Elizabeth', 2015, 'completed', 0, 1, 1, '{"name":"Mary Elizabeth","slug":"mary-elizabeth","year":2015,"status":"completed","bio":"We’d like to introduce Mary Elizabeth.  Not only is she beautiful inside and out, but she is amazingly strong and selfless.  Mary Elizabeth was a healthy, happy and active 11-year-old in the spring of 2014.  She started to complain of stomach aches, headaches and had some strange bruising on her shins. She and her family visited the pediatrician before going out of town for spring break and they were assured that it was just allergies. Otherwise, she seemed perfectly healthy. However, while at the beach she was overly exhausted and was not as happy and spirited as usual.  Her family took her home to get more testing as they knew something was wrong. When the results came back, they got a call that would change their lives forever. Mary Elizabeth was diagnosed with Acute myeloid leukemia (AML), the most rare and aggressive form of leukemia.   This devastating news was hard to bear.  Dealing with heartbreak and angst, her parents tried to stay strong and hide their tears.  Mary Elizabeth told them that they were not allowed to cry because she knew she would be okay. Since the beginning of this difficult journey, Mary Elizabeth has been strong beyond human understanding and a true fighter who always puts others first.  Soon after the diagnosis, her family learned that the cancer was too aggressive for chemo alone and she would also have to have a bone marrow transplant.   Her brave brother was a perfect match and was more than happy to be his sister’s hero.  Although the bone marrow transplant was painful and scary, it went perfectly; and, the prognosis was looking good.  However, four weeks after her transplant, she developed severe Graft-versus-host disease (GVHD) of the gut and ended up back in the hospital. This caused her unbearable continuous pain that persisted and at her six-week check-up they found that the cancer had relapsed.  Her family sought medical intervention from specialists at St. Jude.  Since then, she has had to participate in very aggressive chemotherapy that caused severe burns over 90% of her body. Throughout this painful and wrenching treatment, Mary Elizabeth stayed strong and brave and the chemotherapy was successful.  She was back in remission.  At a check-up, they learned she had developed a chloroma (a leukemia tumor) on her spine. This tumor brought her additional pain and threatened to cause permanent paralysis.  Thankfully, the chemotherapy treatments worked to shrink this tumor as well.   Following this stretch of intervention, Mary Elizabeth required a second bone marrow transplant and luckily her father was a match.  Complications of the second transplant included a severe fungal infection, two instances of pulmonary hemorrhage, intubation and a medically induced coma.  The family was fearful that she may not pull through, but with grace she overcame again and again! She is still in recovery and hopes to be able to return home before Easter.   SOARD wants to sprinkle a whole lot of sunshine throughout her home so the family’s homecoming will be a joyous surprise!  We have planned spectacular bedroom make-overs for both Mary Elizabeth, who wants to share a room with her sister, and her brother -- a pair of heroic siblings bound by steadfast strength and love that never fails!   Please join us for the family’s homecoming and exciting reveal in April!  ","quote":"We’d like to introduce Mary Elizabeth.  Not only is she beautiful inside and out, but she is amazingly strong and selfless.  Mary Elizabeth was a healthy, happy and active 11-year-old in the spring of 2014.  She started to complain of stomach aches, headaches and had some strange bruising on her shi","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mary-elizabeth/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mary-elizabeth/hero/public","alt":"Mary Elizabeth makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mary-elizabeth/photo-02/public","alt":"Mary Elizabeth makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mary-elizabeth/photo-03/public","alt":"Mary Elizabeth makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mary-elizabeth/photo-04/public","alt":"Mary Elizabeth makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mary-elizabeth/photo-05/public","alt":"Mary Elizabeth makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mary-elizabeth/photo-06/public","alt":"Mary Elizabeth makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mary-elizabeth/photo-07/public","alt":"Mary Elizabeth makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eli/photo-31/public","alt":"Mary Elizabeth makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mary-elizabeth/photo-09/public","alt":"Mary Elizabeth makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mary-elizabeth/photo-10/public","alt":"Mary Elizabeth makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mary-elizabeth/photo-11/public","alt":"Mary Elizabeth makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/b66eeb02-d89b-4664-1b68-c7e69b36d800/full","source":"wix-migration","wixNumber":25},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('mason', 'Mason', 2018, 'completed', 0, 1, 1, '{"name":"Mason","slug":"mason","age":9,"diagnosis":"Synovial Sarcoma","roomTypes":["Dream Bedroom"],"year":2018,"status":"completed","bio":"Mason is a rare gem of a kid with a very rare form cancer. He is unique, loving, and has always been an old soul, wise beyond his years. He enjoys spending time with his 5 siblings (Mason is the 4th of 6 kids), his parents, and his best friend-a puppy named Mickey. Mason''s interests are vast and captivating,  ranging from listening to the Beatles to exploring vintage cars to building every Star Wars Lego set he can find with his brothers and mom. \n\nMason was diagnosed with Synovial Sarcoma just three weeks after his 9th birthday in July of 2017, making him only the 49th case of this form of cancer in a child nine years of age or younger. After the diagnosis of his primary tumor and with the rarity of this form of cancer, Mason and his parents travelled to several out-of-state high volume Sarcoma centers in search of the best Sarcoma team and treatment plan to save his life. Having never been on a plane before, Mason took nine flights within the six weeks following his diagnosis.  Often he and his mom were alone in hotels and hospital rooms hundreds of miles away from the rest of his family. Mason underwent a surgical lung biopsy out of state that unfortunately was unsuccessful and resulted in the hemorrhage of his lung. The following week, he endured a surgical sentinel node biopsy to further assess the possibility of metastasis. During the short time lapse between when Mason''s tumor was initially seen on MRI and while he was being staged and seeking a treatment plan, a follow up MRI showed that Mason''s tumor had increased in volume by 65%. Within days of receiving those results, he and his family traveled to Boston to meet an experienced Sarcoma team. It was determined that this team was the most qualified team with the best plan to effectively treat Mason''s cancer with the best chance at a good quality of life. Later that week, he had his fourth surgery since being diagnosed and his port was put in. Within a few hours of that surgery, he began the first round of the very strong neoadjuvent chemotherapy regimen. The side effects of chemo took him out of school, away from his friends, and often on isolation from even his siblings as they left him vulnerable to possibly life-threatening infections.\n\nChemotherapy took a significant toll on his fragile body.  Nearly every round of chemo he underwent resulted in unplanned trips to the ER and additional hospital admissions due to serious illnesses and complications. During the time he was on chemo, Mason missed many fun events and social activities including camp, birthday parties, trick or treating on Halloween, holiday celebrations and playing on his school''s basketball team. This was disappointing, but he never let it get him down and continued to fight like a true warrior.\n\nAfter several months of chemo in Atlanta, Mason and his mom returned to Boston, away from the rest of their family, for his big surgery. Boston became their home for the month of November as Mason underwent extensive tumor excision surgery which included the rebuilding of his medial knee and part of his leg to remove his tumor. After surgery, Mason was confined to an immobilizing leg brace and used a wheelchair to get around. He began extensive physical therapy and vestibular rehabilitation to regain balance and the use of his leg. Mason was determined to stand, walk, and regain the mobility he had lost. He worked hard and pushed through the pain and challenges he endured, including having a non-healing surgical wound battling recurrent staph infections.  Mason has rose above the many setbacks faced due to his unwavering determination to regain his mobility.  The surgical wound took 4.5 months to heal completely after his tumor excision surgery.\n\nAfter Mason completed his chemotherapy, his family adopted his new best friend and faithful companion, a Boston Terrier puppy named Mickey. Mason longed for a puppy for several years.  Given the miraculous treatment he received in Boston, the city held special meaning to Mason.  As a result, he thought it was quite fitting to choose a Boston Terrier.  The bond between Mickey and Mason in heartwarming and unbreakable!\n\nAlthough Mason''s progress has exceeded his doctors'' expectations in many ways, his future and prognosis remain uncertain. Each day is truly a blessing and he and his family celebrate every victory!","quote":"\"He is unique, loving, and has always been an old soul, wise beyond his years.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-19/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-20/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-21/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-22/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-23/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-24/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-25/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-26/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-27/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mason/photo-28/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-38/public","alt":"Mason makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-40/public","alt":"Mason makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-41/public","alt":"Mason makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alejandro/photo-21/public","alt":"Mason makeover photo"},{"url":"https://imagedeliver