magedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers-2/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/tko-plumbing/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/servicewise-electric/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/schluter-systems/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/traditions-in-tile/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/sherwin-williams/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bin-there-dump-that/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"_migration":{"scrapedAt":"2026-03-06T13:32:09.497Z","source":"wordpress-xml-export","wpPostDate":"2024-06-27 15:56:59","wpCategories":["Bin There Dump That Atlanta","Meet the Kids"],"wpTags":["2024","Accessible Bathroom","Dream Bedroom"],"thumbnailId":8969,"needsReview":[],"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/d02b92ba-53b9-4f96-fac7-00ebd2cdc000/full"},"streamVideoId":"b7d19b4d7dc84e9bff23f7eb366d6bce","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('matthew', 'Matthew', 2019, 'completed', 0, 1, 1, '{"name":"Matthew","slug":"matthew","age":7,"diagnosis":"Epilepsy, Autism","roomTypes":["Therapy Room"],"year":2019,"status":"completed","bio":"He stopped responding to his name, stopped making eye contact, started flapping his hands, and started babbling rather than using the words he had previously spoken on a regular basis.\n\nHe stopped responding to his name, stopped making eye contact, started flapping his hands, and started babbling rather than using the words he had previously spoken on a regular basis. Words like \\u201cmama\\u201d and \\u201cdadda\\u201d simply disappeared from his vocabulary. Matthew underwent extensive testing from a psychologist who spend a great deal of time assessing his skills and behaviors. At the conclusion of the assessment, they were told that Matthew had Autism. This diagnosis was unexpected and heartbreaking. After speaking with his pediatrician, they decided that the first step in getting Matthew the help he needed was to get him enrolled into the Babies Can''t Wait early intervention program. He was only in the program for roughly 6 months until he turned 3. He then continued services with the county public school system along with private speech, occupational and physical therapy. Now, after four years of weekly private speech, occupational, physical and ABA therapy Matthew is demonstrating significant gains. Matthew''s communication has increased tremendously. The ABA (Applied Behavioral Analysis) therapy helps teach him self-help skills, such as potty training and play skills. Matthew is starting to play more with friends, make eye contact and is talking more. Every single day is a new day and every milestone is big. The small victories add together to make big changes leading to a bright future for Matthew. Sunshine on a Ranney Day is excited to be planning a brilliant dream therapy room to help Matthew enjoy a place where he continue to thrive while in the comfort of his own home! Please join us in making this project come to fruition!","quote":"He stopped responding to his name, stopped making eye contact, started flapping his hands, and started babbling rather than using the words he had previously spoken on a regular basis.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-19/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-20/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-21/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-22/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-23/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-24/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-25/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/matthew/photo-26/public","alt":""}],"photoCount":26,"videoUrl":"https://youtu.be/e2wdruke-ag","photographer":"Studio79","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/jackson-healthcare/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/wall-nut-custom-wall-murals/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/swinerton/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/crosby-design-group/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/studio-79-photography/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"dac4333db02ec1f67f33fbb41cdeb4d1","roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('mattie-and-nathan', 'Mattie & Nathan', 2017, 'completed', 0, 2, 1, '{"name":"Mattie & Nathan","slug":"mattie-and-nathan","year":2017,"status":"completed","bio":"There truly is no buddy like a brother! These two boys share a room and have a lot in common.  Both are pretty, cool dudes with a lot of love to share with the world. Getting to know Nathan and Mattie means being blessed with the gift of joy. Nathan was premature and fought for survival from the day he was born due to a life-threatening infection that caused damage to his lungs and digestive system. He spent about six weeks in the NICU and struggled with learning how to breathe, eat, and grow. As a baby, he had continued difficulty eating and breathing and frequently spent time in the hospital due to respiratory and gastrointestinal disorders. Before Nathan turned two years old, he was diagnosed with eosinophilic esophagitis as well as autism. When he turned three, he got a feeding tube because he was losing weight and needed extra nutrition so he could grow. When he turned four, he experienced gastroparesis and shortness of breath leading to hospitalization.  While Nathan was in preschool, he had surgery to stop frequent vomiting and to facilitate healing of the lungs.  He was also diagnosed with mitochondrial disease the summer before he started kindergarten. Over the past 5 years, Nathan’s doctors have worked together with his family in order to find a balance of addressing his medical issues. Three years ago, Nathan’s feeding tube was changed from a g-tube to a gj-tube in order to keep him from aspirating while he got tube feeds. Two years ago, Nathan had another surgery to help ease his intestinal failure, give him more independence, and help preserve his dignity. His parents know that his health issues are very serious; so, they try each day to celebrate and encourage Nathan to live the fullest life possible. Nathan loves swimming, camping, horseback riding, going to church, video games, as well as spending time with his brother and friends.  Like many young men, he also enjoys watching science and engineering shows on Netflix and Hulu, especially Cosmos and Mythbusters. Mattie was born premature; but, reached all his milestones and was a happy baby until he was 9 months. When he began to eat solid foods, Mattie started to have serious digestive issues. At his first birthday, he was not gaining weight so Mattie''s doctor ordered blood work that came back with concerning results. Mattie was immediately sent to the hospital for a blood transfusion. After two months in the hospital, countless tests and surgery, Mattie came home from the hospital with a feeding tube and oxygen at night for sleep but no real answer as to what was wrong.   Due to weakness during his hospital stay and his declining heath, Mattie lost all the early milestones he had reached and had to start learning all over again. Since then, he has struggled to keep breathing, eating, and developing. After extensive testing, Mattie was diagnosed with eosinophilic esophagitis, autism, and mitochondrial disease.  He also has neurofibromatosis type 1, a tumor on the optic nerve in his brain, and a tumor on his cervical spine.  His parents were told that as Mattie grows he will have more and more tumors, and sadly that has been the case. He now has multiple tumors in his cervical spine, a small growth in his brain, an optic pathway glioma, and a plexiform tumor growing around his spine. He had a major surgery to partially remove a tumor around his cervical spine in the fall of 2016 and spent 3 weeks in rehab.  His doctors are monitoring the tumors for now and they will be treated with either chemotherapy or surgery if and when they become symptomatic. Mattie loves going to school, riding horses, swimming, and playing video games, and loves his friends and family.  He is one of the coolest kids out there.  He is a sweet, funny, charming, stubborn, smart, little guy who oozes personality and is really fun to be around. Due to the complexity of both brothers’ medical issues, they are under the continuous care of the Complex Care team at Children''s Healthcare of Atlanta. Balancing these complex medical issues with childhood and family life can be quite exhausting and difficult to manage.  The strength of the boys and their fight to thrive despite their challenges helps keep the family going.   No matter the prognosis, celebrating just how beautiful life can be with these amazing brothers is the focus of each day.   Sunshine on a Ranney Day wanted to help them capture each ray of sunlight and bring hope into their home through a brilliant room makeover designed especially for this dynamic duo! ","quote":"There truly is no buddy like a brother! These two boys share a room and have a lot in common.  Both are pretty, cool dudes with a lot of love to share with the world. Getting to know Nathan and Mattie means being blessed with the gift of joy. Nathan was premature and fought for survival from the day","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zoe/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zoe/hero/public","alt":"Mattie & Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Mattie & Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-46/public","alt":"Mattie & Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Mattie & Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mattie-and-nathan/photo-05/public","alt":"Mattie & Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mattie-and-nathan/photo-06/public","alt":"Mattie & Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mattie-and-nathan/photo-07/public","alt":"Mattie & Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mattie-and-nathan/photo-08/public","alt":"Mattie & Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mattie-and-nathan/photo-10/public","alt":"Mattie & Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/anderson/photo-16/public","alt":"Mattie & Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mattie-and-nathan/photo-12/public","alt":"Mattie & Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/angel/photo-48/public","alt":"Mattie & Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mattie-and-nathan/photo-14/public","alt":"Mattie & Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/mattie-and-nathan/photo-15/public","alt":"Mattie & Nathan makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/ccf79ea1-73b1-4aae-74b7-d03f7c565800/full","source":"wix-migration","wixNumber":69},"childCount":2,"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('max', 'Max', 2026, 'in-progress', 0, 1, 1, '{"name":"Max","slug":"max","age":14,"diagnosis":"Multiple Sulfatase Deficiency","roomTypes":["Accessible Bathroom"],"year":2026,"status":"in-progress","bio":"Max was born with a rare genetic mutation that prevents his body from properly clearing cellular waste. Over time, this buildup damages cells throughout his body, especially in the brain, gradually affecting every system. The condition is often referred to as childhood dementia because children lose skills and abilities they once had as the disease progresses.\n\nAs a young child, Max could walk, talk, laugh, and play just like his peers. Today, Max has lost all motor skills and relies entirely on full-time care for every aspect of his daily life. He is dependent on others for mobility, communication, feeding, and comfort. As his condition continues to advance, his family adapts constantly, learning new ways to care for him, keep him comfortable, and preserve his dignity.\n\nThough the disease has changed what Max can physically do, it has not changed the love that surrounds him. His family remains committed to giving him the safest, most supportive environment possible as they navigate the challenges of this devastating diagnosis.","quote":null,"heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/max/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jackson/photo-01/public","alt":""}],"photoCount":1,"videoUrl":null,"photographer":null,"partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/wyp/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('monica', 'Monica', 2016, 'completed', 0, 1, 1, '{"name":"Monica","slug":"monica","year":2016,"status":"completed","bio":"Monica was your typical 6-year old who loved to color and dance! She loves princesses and loved to play princess with her 9-year old sister. Monica and her sister have a magical bond like no other, they were destined to be best friends. They love to be together so much they chose to share a bedroom even though there are plenty rooms in the home for each girl to have their own.  On Tuesday morning, March 29th, the Lunn Family’s lives were changed forever.  Mom, Melina and Monica were involved in a tragic car accident in front of their school.  Monica spent the first 3 weeks in PICU at Egleston.  While there, it was determined that she broke her neck, causing her to become a quadriplegic and requiring the need to be on a respirator in order to breathe.  She survived her first surgery where a rib was fused to her C1 and C2 to provide stability and prevent further damage.  Several days later she survived another surgery as she was given a trach and put on a feeding tube.  One week ago, Monica was moved to Children’s/Scottish Rite.  She is able to talk and eat.  She participates in a rigorous schedule of Physical Therapy, Occupational Therapy, and Speech.  It is estimated she will be discharged near the end of May or beginning of June.  The next stage will be participating in daily out-patient therapy.  Through it all, Monica remains strong and happy.  Monica is a fighter and a survivor! Sunshine stepped in and gave Monica and her family reassurance they will be able to take care of her in an environment that is safe for both Monica and her parents. Monica''s parents gave up their bathroom and bedroom which is on the first floor of the home for their daughter. These two rooms Sunshine transformed, fit for a princess!","quote":"Monica was your typical 6-year old who loved to color and dance! She loves princesses and loved to play princess with her 9-year old sister. Monica and her sister have a magical bond like no other, they were destined to be best friends. They love to be together so much they chose to share a bedroom ","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/monica/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/monica/hero/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/christian-v/photo-29/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/hero/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/amir/photo-33/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-03/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/anna/hero/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alejandro/photo-21/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/hero/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caroline/photo-07/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-43/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/monica/photo-12/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/monica/photo-13/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/monica/photo-14/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/monica/photo-15/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/monica/photo-16/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/monica/photo-17/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/monica/photo-18/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eli/photo-31/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/monica/photo-20/public","alt":"Monica makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/monica/photo-21/public","alt":"Monica makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/fd5e6be1-748b-4db4-c182-472321f56100/full","source":"wix-migration","wixNumber":45},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('murphy-harpst', 'Murphy-Harpst', 2019, 'completed', 0, 1, 1, '{"name":"Murphy-Harpst","slug":"murphy-harpst","year":2019,"status":"completed","bio":"Murphy-Harpst Children’s Centers is an independent not-for-profit organization committed to meeting the needs of abused and neglected young people through residential treatment, placements in specialized foster care, and community programs that serve at-risk youth and their families. They serve approximately 150 children each year (75 beds on our residential campus, almost 50 specialized foster care homes and community service clients). With an average length of stay 9-12 months, our mission is to provide life and hope. TBRI Sensory Therapy Room   TBRI in being implemented on our campus to provide a nurturing program model for all caregivers to address the complex developmental trauma that our children have survived. Abuse, neglect, and trauma effect children through interactive psychological and behavioral manifestations. Many dysfunctional coping skills, chronic fear and sensory deficits create barriers to developing healthy relationships, building trust, improving self-esteem and independent functioning. Sensory processing disorders negatively impact behavior, social skills and academic performance.  &quot;Trust-Based Relational Intervention® (TBRI®) is a holistic approach that is multi‑disciplinary, flexible, attachment‑centered, and challenging. It is an evidence‑based, trauma‑informed intervention that is specifically designed for children who come from hard places, such as maltreatment, abuse, neglect, multiple home placements, and violence, but you’ll see that the principles apply to all children. TBRI® consists of three sets of harmonious principles: Connecting, Empowering, and Correcting Principles.&quot; Sunshine on a Ranney Day partnered with Murphy-Harpst to create a safe, sensory infused therapy center for individual and group therapy, TBRI training site and as an TBRI friendly example for the campus. This sensory room will be the first of many enhancements planned and serve as example to enable them to expand the creative process throughout the entire campus, especially living spaces of children. ","quote":"Murphy-Harpst Children’s Centers is an independent not-for-profit organization committed to meeting the needs of abused and neglected young people through residential treatment, placements in specialized foster care, and community programs that serve at-risk youth and their families. They serve appr","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/hero/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-02/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-03/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-04/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-05/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-06/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-07/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-08/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-09/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-10/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-11/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-12/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-13/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-14/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-15/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-16/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-17/public","alt":"Murphy-Harpst makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/murphy-harpst/photo-18/public","alt":"Murphy-Harpst makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/de76f94e-280a-4568-8f9a-9ee5fe21e900/full","source":"wix-migration","wixNumber":101},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('naji', 'Naji', 2025, 'completed', 0, 1, 1, '{"name":"Naji","slug":"naji","age":19,"diagnosis":"T4 to L5 Spinal Injury","roomTypes":["Therapy Room"],"year":2025,"status":"completed","bio":"Naji is a nineteen-year-old young man, born on April 5, 2004 with a congenital heart defect that necessitated four open heart surgeries. His plans after high school were to pursue college degrees in both finance and law. Unfortunately, his plans were put on hold after sustaining a spinal cord injury in September 2022.\n\nThe injury Naji sustained in September 2022 caused him to become paraplegic. He was hospitalized for several months after his surgery for both recovery and extensive in-patient rehabilitation therapy. The nature of his injury by definition involves an extremely long recovery, including extensive physical and occupational therapy, lots of dedication and hard work to his treatment plan. Other hurdles he is having to navigate in addition to his paralysis are: the management of constant pain, neurogenic bowels, neurogenic bladder, emotional and psychological stress and anxiety.\n\nNaji is an extremely intelligent young man, as well as being very sensitive and caring. He has a unique sense of humor, loves animals and in fact has two dogs and a kitten: Oreo, Tango and Bear. He is dedicated to achieving recovery, going to college and pursuing a career that would allow him to become a productive member of society, and to give back what society has graciously given him.","quote":"\"He is dedicated to ... pursuing a career that would allow him to become a productive member of society - to give back what society has graciously given him.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/naji/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/naji/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/naji/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/naji/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/naji/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/naji/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/naji/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/naji/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/naji/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/naji/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/naji/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/naji/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/naji/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/naji/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/liam/photo-28/public","alt":""}],"photoCount":15,"videoUrl":"https://youtu.be/mPna7lJi5XI?si=ViAJgRT1CeK_JnOY","photographer":"Niki Murphy","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/gas-south/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/jackson-healthcare/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial-2/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/georgia-interior-painting/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/servicewise-electric/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/thibaut-2/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/frank-advertising/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/niki-murphy-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/iframe-media/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"82c7236b5824088e5e89adcd6b2854ec","roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('nathan', 'Nathan', 2014, 'completed', 0, 1, 1, '{"name":"Nathan","slug":"nathan","year":2014,"status":"completed","bio":"We love making dreams come true and cannot wait to transform Nathan’s basement into an amazing theatre room!  He truly needs a special place where he can play his favorite video games and enjoy time with family and friends while maintaining his health.  Cystic Fibrosis has forced Nathan to be a very brave young man.  From the time he was an infant he has shown incredible strength while receiving many unpleasant procedures. After 14 years of battling this life-threatening disease, he is more concerned with caring for his family than the painful and daunting treatments he endures. When he and his mom walk into the hospital for an admission, he will ask &quot;Mom, are YOU going to be okay?'''' What a loving heart and maturity far beyond his years!  Cystic fibrosis (CF) is a life-threatening genetic disease that primarily affects the respiratory and digestive systems.  Many have described CF like having a cold every day of the year. This includes constant coughing, sinus issues and chronic stomach pain.  Nathan’s family began the long hard fight against Cystic Fibrosis in 1993 when his older sister, Courtney, was diagnosed. Upon Nathan''s arrival into the world in November of 1999, he was immediately tested for CF as it is well documented as a genetic disease. Although the family and physician hoped he would not have to face the same battles his sister Courtney did, test results revealed the heartbreaking reality that he too had Cystic Fibrosis.  This diagnosis has led to 14 years of a plethora of daily medications, chest physical therapy, wearing specialized decongestion vests for hours and repeated long hospital stays.     Unfortunately, after experiencing the loss of his beloved sister, Nathan has learned to understand the gravity of this dreadful disease and approaches all of the hardships it brings him with a strong fight to stay healthy and keep his family strong.  On a recent camping trip with family and friends, everyone excitedly rushed outdoors first thing in the morning to enjoy the day.  Before joining in the activities, Nathan had to spend an hour doing his breathing treatments with chest physical therapy and said, &quot;I wish I didn''t have to do all these treatments, but I know I wouldn''t be alive without them.&quot;  Despite these trials, he does not let anything slow him down.  Thankfully, CF has not robbed him of the one thing he loves most-playing soccer!  However, the complications of CF limit his ability to remain outside and participate in extensive activity.  When Nathan is not being a super star out on the fields, he loves being at home with family or friends watching movies or playing video games.  SOARD is thrilled to have the opportunity to once again partner with Make-A-Wish® Georgia for this project!  Nathan is looking forward to being able to have a blast in his new Theatre Room for years to come!  Join us for the upcoming “kick off “ in helping Nathan reach all of his goals-on and off the field!   Who can resist the urge to help this handsome, brave young man? What a cutie!  His reveal will be on Saturday August 9 in Canton, GA!","quote":"We love making dreams come true and cannot wait to transform Nathan’s basement into an amazing theatre room!  He truly needs a special place where he can play his favorite video games and enjoy time with family and friends while maintaining his health.  Cystic Fibrosis has forced Nathan to be a very","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","alt":"Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tayler/hero/public","alt":"Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nathan/photo-04/public","alt":"Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/adrian/photo-31/public","alt":"Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/bobby/photo-04/public","alt":"Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nathan/photo-07/public","alt":"Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nathan/photo-08/public","alt":"Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nathan/photo-09/public","alt":"Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nathan/photo-10/public","alt":"Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nathan/photo-11/public","alt":"Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-09/public","alt":"Nathan makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nathan/photo-13/public","alt":"Nathan makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/d02b92ba-53b9-4f96-fac7-00ebd2cdc000/full","source":"wix-migration","wixNumber":17},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('nicolas-and-maddox', 'Nicolas & Maddox', 2024, 'completed', 0, 2, 2, '{"name":"Nicolas & Maddox","slug":"nicolas-and-maddox","age":8,"diagnosis":"Metachromatic Leukodystrophy","roomTypes":["Dream Bedroom","Therapy Room"],"year":2024,"status":"completed","bio":"Meet Nico and Maddox! In September of 2022, both boys were diagnosed with Metachromatic Leukodystrophy (MLD), a genetic disease that affects the brain and nervous system. Those with the disease progressively lose function as the substance that protects the nerve cells (Myelin) becomes damaged. The result is a loss of motor and cognitive function over time. There is no cure, and no treatment options are available at this stage of their disease.  \n\nNico (8) is a bundle of curiosity and creativity. From the moment he said his first words, dinosaurs became his world. His playroom is a prehistoric playground adorned with dinosaur toys, including his favorite T-Rex. It''s common to find him engrossed in dinosaur books or correcting his parents on the difference between a Brachiosaurus and a Brontosaurus. Beyond his fascination with dinosaurs, Nico possesses a remarkable intellect and vivid imagination that sets him apart. His inquisitive nature has led him to develop a keen interest in puzzles. He often thrived on the mental stimulation that solving puzzles provides.\n\nMaddox (6) is a bundle of joy who can turn any moment into a celebration with his infectious laughter. His zest for life is evident in everything he does, and his laughter fills the air with happiness. He possesses an innate ability to lighten up a room, bringing smiles to the faces of those around him. His playful spirit and genuine enthusiasm for life make him a magnetic presence, drawing people in with the promise of shared laughter and joy. Music holds a special place in Maddox''s heart, and he expresses his love for life through the power of song. His repertoire includes the timeless classics \"Happy Birthday\" and the festive \"Jingle Bells.\" His unwavering enthusiasm turns any sing-along into a heartwarming performance that leaves everyone smiling.\n\nOne of the family''s favorite pastimes is following the path through their garden to look at all of the vegetables and flowers planted along the way. This is a perfect reflection of the family''s love for life and being together!  Sunshine on a Ranney Day''s goal is to make them as comfortable as possible as symptoms begin to limit the boys'' abilities. We hope to help the family make the most of their time with the boys by improving the accessible areas of the home to accommodate the boys'' needs.","quote":"\"One of the family''s favorite pastimes is following the path through their garden to look at all the vegetables and flowers planted along the way.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nicolas-and-maddox/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nicolas-and-maddox/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nicolas-and-maddox/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nicolas-and-maddox/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nicolas-and-maddox/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nicolas-and-maddox/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/josue/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/istvan/photo-22/public","alt":""}],"photoCount":7,"videoUrl":"https://www.youtube.com/watch?v=cNj8nQrV3II","photographer":null,"partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/forsyth-rotary/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bc-homes-inc/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/mohawk/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/schluter-systems/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/wall-nut-custom-wall-murals/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bin-there-dump-that/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"cccb6f4de1c340b619e33898918f246c","childCount":2,"roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('noah-2023', 'Noah', 2023, 'completed', 0, 1, 2, '{"name":"Noah","slug":"noah-2023","age":11,"diagnosis":"Rasmussen Encephalitis","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2023,"status":"completed","bio":"Noah was born at 32 weeks with no complications. He was a healthy active kid until 6 yrs old when he had his first seizure episode in the summer of 2018. Doctors couldn''t figure out why Noah was having seizures 10 times a day until an amazing doctor at Children''s Healthcare of Atlanta figured out what was wrong with him. In the spring of 2019, Noah was diagnosed with Rasmussen Encephalitis. In late fall of 2019, he had his first brain surgery (Right Hemispherectomy) and his last seizure.\n\nToday, Noah is now physically disabled on the left side of his body and needs help with day-to-day needs. Noah has always had an open mind with the outcome of his surgery. He remains strong and motivated to regain some of his independence while playing sports with Gwinnett Heat in Gwinnett County. He has physical/occupational therapy 2 times a week, Botox every 4-6 months, and is doing amazing with his long recovery. Noah is super excited to have a space he can call his own where he can move around freely and independently.","quote":"\"Noah has always had an open mind with the outcome of his surgery.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-19/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-20/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-21/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-22/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-23/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-24/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/noah-2023/photo-25/public",