INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('nygil', 'Nygil', 2020, 'completed', 0, 1, 2, '{"name":"Nygil","slug":"nygil","age":17,"diagnosis":"Cerebral Palsy","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2020,"status":"completed","bio":"He weighed only one pound, twelve ounces and doctors told his parents that he would not survive through the night.\n\nAlthough his parents were told he wouldn''t survive through the night, Nygil has lived seventeen joyous years and is nearing adulthood. As he grows, so does his need for in home care and independence. Granting Nygil a bedroom and bathroom makeover will allow him to maneuver throughout his room in his wheelchair and walker efficiently, leading to greater independence and an opportunity to continue to thrive at home.\nWe are overjoyed to be able to provide this makeover for Nygil. His new room is sure to be as fashionable as he is and will incorporate all the things that he loves. We hope to see him beaming with joy as we spread a little sunshine his way. Please join us at the big reveal!","quote":"He weighed only one pound, twelve ounces and doctors told his parents that he would not survive through the night.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nygil/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nygil/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nygil/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nygil/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nygil/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nygil/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nygil/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/nygil/photo-07/publi