6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/delta-faucet/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/signature-hardware/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/niki-murphy-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/iframe-media/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/echols/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pulleyassociates/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/interceramic/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/reliable-heatingair/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"_migration":{"scrapedAt":"2026-03-06T13:32:09.466Z","source":"wordpress-xml-export","wpPostDate":"2021-06-26 22:31:38","wpCategories":["Meet the Kids"],"wpTags":["2020","Accessible Bathroom","Dream Bedroom"],"thumbnailId":1250,"needsReview":[],"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/308b7af2-0b66-471e-2163-01acc72b2700/full"},"streamVideoId":"5761822471fe541b91a053d02ce757a5","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('oakley', 'Oakley', 2023, 'completed', 0, 1, 2, '{"name":"Oakley","slug":"oakley","age":9,"diagnosis":"Spina Bifida & Hydrocephalus","roomTypes":["Accessible Bathroom","Wheelchair Ramp"],"year":2023,"status":"completed","bio":"Oakley was born in China in March of 2014. She was found in a baby box, and taken to the orphanage. Oakley has Spina bifida, and this is likely the reason her biological parents were unable to care for her as best as she needed. Her medical file looked really complex and scary, but the moment her family saw her picture, none of it mattered, whatever it looked like. They began the process to adopt Oakley when she was about a year and a half old, and finalized the process just before she turned two. \n\nBecause of her Spina bifida, Oakley is paralyzed mid thigh down. She was also born with hydrocephalus and tethered cord syndrome that required surgery on her spine. Oakley uses a wheelchair but when she is at home, she likes to be out of her chair more than when she is at other places, so she will scoot around using her arms. She has some seriously strong arms! She can show you how to do a pull up or two under the table! And there is really nothing she can''t figure out a way to make work where she needs to. \n\nOakley is the happiest, most joyful, hilarious child you will ever meet. She has no cognitive delays, and her sense of humor is on point. She is sharp. So smart. Her family likes to say she is 8 going on 22. She seriously runs the ship. She keeps everyone in the house in order, and I am pretty sure she does the same at school. She is a social butterfly, and every kid loves her. You would never know in her tiny little life that she had ever dealt with anything. She''s the one who reminds her family to be grateful, to not forget what they have, and to find the joy even where it seems it shouldn''t be.\n\nFor her, a wheelchair accessible bathroom or a ramp will mean the world. Currently, they carry her in and out of the house to and from the van when they leave and come home. A new bathroom ahead of beginning her new bowel management process will be such a sweet step towards making her more independent and giving her somewhere private that she would actually enjoy being in during this process every night. She is also starting to get heavier as she is getting older, so this makeover will make the bathroom process much easier for her family, as well. But she finds such joy in such little things, this would truly make her world. She longs to be independent, but never complains about not feeling completely so. She is truly sunshine on a rainy day. She radiates joy like no other child. Her laughter is infectious. Her knock knock jokes are no joke. They''re the real deal. She is peace, and love. The no nonsense, no fuss attitude she has is contagious, and it changes everybody else''s environment. Her family is so much better because she is here.","quote":"\"You would never know in her tiny little life that she had ever dealt with anything.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-19/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-20/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-21/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-22/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-23/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-24/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-25/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-26/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-27/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-28/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-29/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-30/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-31/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oakley/photo-32/public","alt":""}],"photoCount":32,"videoUrl":"https://youtu.be/CkFcOBVnP5I","photographer":"Hales Photo","partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/gas-south/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/linen-flax-home/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/hales-photo/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/wall-nut-custom-wall-murals/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/delta-faucet/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pulleyassociates/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/traditions-in-tile/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/top-knobs/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/schluter-systems/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cowan-supply/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cambria/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/cr-construction-v2/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/servicewise-electric/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/tko-plumbing/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/pls-carpentry/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/bin-there-dump-that/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/iframe-media/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/nothing-bundt-cakes/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"d8fd4b5ef3d73d83668d87980668b70a","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('oliver', 'Oliver', 2015, 'completed', 0, 1, 1, '{"name":"Oliver","slug":"oliver","year":2015,"status":"completed","bio":"We’d like to introduce sweet Oliver.  This little pumpkin is not only adorable, but also loving and snuggly! His favorite thing in the world is a bear hug from daddy. His second favorite is Mickey Mouse.  Oliver was born with two rare genetic conditions Phelan-McDermid Syndrome (22q13 deletion) and a partial Trisomy 9 (9q34 duplication).  He is one of only two children in the world with this extremely rare combination of genetic disorders and is one of the 1,100 known worldwide cases of Phelan-McDermid Syndrome. Consequently, Oliver has severe physical, developmental and cognitive delays.  In his short three years, Oliver has already endured 14 surgeries and frequent hospitalizations.  The hospital has become a second home for him and his family.   Complications of his condition include Cerebral Palsy and Epilepsy, as well as deficits of the cardiac, neurological, intestinal and renal systems leading to extreme chronic pain. He receives his nutrition intravenously and is incredibly susceptible to infection. As a result of being so medically fragile, he is unable to go to school or therapy outside of the home.  He is currently non-ambulatory and non-verbal and receives extensive in home therapies to facilitate improved muscle control, cognition and communication. Unfortunately, his disorders are progressive; and, it is expected that his medical and physical conditions will become more severe.  Therapy is critical to enhancing his development and physical growth.  At his age, there is a short window of opportunity to employ a variety of exercises to improve his core strength and gross motor strength to keep up with his physical growth. If adequate development of the musculoskeletal system does not occur during this crucial period, his muscles will not be able to adapt to the physical changes his body goes through as he grows.  Adequate muscle development is critical in supporting his body’s physical growth as well as in supporting the function of his kidneys and intestines.  Despite his physical limitations and chronic pain, Oliver is a joy!  His eyes light up when you interact with him and it is clear that he is full of passion for life. With bright smiles, he expresses his desire to grow and learn even during tough times.  His perseverance and cheerful demeanor are inspiring.  Sunshine on a Ranney wants to see more of those sweet smiles and plans to redesign his home to accommodate his changing needs. This project will include remodeling of the floor and bathroom to become wheelchair accessible, a room make-over and transforming the family dining room into a therapy suite so he can get all of the interventions he needs at home!  ","quote":"We’d like to introduce sweet Oliver.  This little pumpkin is not only adorable, but also loving and snuggly! His favorite thing in the world is a bear hug from daddy. His second favorite is Mickey Mouse.  Oliver was born with two rare genetic conditions Phelan-McDermid Syndrome (22q13 deletion) and ","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/grace/hero/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-42/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-46/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oliver/photo-08/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oliver/photo-09/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alejandro/photo-30/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/adrian/photo-32/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ayden/photo-15/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oliver/photo-13/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oliver/photo-14/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oliver/photo-15/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/charlie/photo-10/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oliver/photo-17/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/angel/photo-46/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oliver/photo-19/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oliver/photo-20/public","alt":"Oliver makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/oliver/photo-21/public","alt":"Oliver makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/d02b92ba-53b9-4f96-fac7-00ebd2cdc000/full","source":"wix-migration","wixNumber":22},"roomCount"