INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('osayi', 'Osayi', 2024, 'completed', 0, 1, 1, '{"name":"Osayi","slug":"osayi","age":4,"diagnosis":"Autism Spectrum Level 3","roomTypes":["Therapy Room"],"year":2024,"status":"completed","bio":"Osayi is a vibrant ball of energy who greets each day with enthusiasm and curiosity! He''s up early in the morning and often takes his time winding down at night. With a passion for climbing, jumping, and cars, this spirited little boy is always on the go!\n\nNavigating speech therapy, occupational therapy, and chiropractic visits, Osayi is in need of a special sensory room where he can safely release his energy and explore the world around him. His mom dreams of a contained space where he can play freely, without the worry of him running off.\n\nIncorporating light therapy and decompression seats will help Osayi find calm during his busy days. His mom lovingly calls him her \\u201cgenius boy,\\u201d as he has a remarkable knack for numbers and letters that continues to amaze her. Through Sunshine on a Ranney Day, Osayi is on the path to having the perfect therapy room tailored just for him. Join us in celebrating his journey and helping him shine even brighter!","quote":"\"His mom lovingly calls him her \\u201cgenius boy,\\u201d as he has a remarkable knack for numbers and letters that continues to amaze her.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/osayi/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/osayi/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/osayi/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/osayi/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/osayi/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/osayi/photo-05/public","alt":""},{