INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('paige', 'Paige', 2018, 'completed', 0, 1, 1, '{"name":"Paige","slug":"paige","age":15,"diagnosis":"FOXG1 Syndrome","roomTypes":["Accessible Bathroom"],"year":2018,"status":"completed","bio":"This hip and happy teen is Paige. Paige is a very happy child that loves her family and pets! She enjoys going to school and hanging out with her typical peer buddies! She gets very excited when she sees the bus arrive to pick her up in the mornings.  Paige also enjoys running errands with mom and dad on the weekends, especially to the \\u201cfish\\u201d store, because she really enjoys watching them swim around in the big tanks.   Paige giggles at her brother all the time when he makes funny sounds and faces at her. Her giggle warms your heart and brings smiles to those around her.\n\nPaige was born on September 28th 2002.  There were no complications with birth and all her development seem to be going well, until at Paige''s 4-month checkup. Paige''s pediatrician could no longer feel her soft spot and was afraid the sutures in her head had closed up. Skull x-rays were ordered along with a referral to a neurosurgeon.\n\n At 5 months of age an MRI showed an insult to the brain, which more than likely happened in early utero. Which meant, there was no way to know what caused it.  To better understand her abilities and treat her, geneticist performed several tests, which all came back negative leaving her family desperate for answers.\n\nPaige was given many individual diagnoses and was treated by a number of specialists including a Neurologist, Geneticist, Gastroenterologist, Ophthalmologist, a Urologits, Endocrinologist and an Orthopedist.  She was also seen for speech, occupational, physical and vision therapies. \n\nThey treated her for several conditions including Esotropia (crossed eyes), Encephalopathy, Choreoathetosis (Movements), Severe Receptive and Expressive Language Disorders, Cerebral Visual Dysfunction, Partial Complex Epilepsy, Allergic Rhinitis (seasonal allergies), Feeding Problems, GERD, Anemia and Eosinophilic Esophagitis (EE-inflammation or swelling of the esophagus).\n\n It wasn''t until new Exome testing was available in 2015 that they were able to look at Paige''s DNA, finally received a diagnosis: FOXG1 Syndrome. FOXG1 Syndrome is a rare neuro-developmental disorder caused by a mutation of the FOXG1 gene, which impacts brain development and function. This severe condition is characterized by seizures, inability to control body movements, and lack of speech. While the spectrum of abilities is quite broad depending on the exact genetic mutation, many of the children diagnosed with FOXG1 cannot walk or talk, and struggle to communicate their most basic daily needs. It is possible for parents to be carriers, but most cases of FOXG1 are non-inherited and have no family history. There is no cure for the FOXG1 Syndrome, but with medications, physical and speech therapy and nutritional support to help manage symptoms and prevent complications, a stable quality of life can be achieved.","quote":"\"Paige giggles at her brother all the time when he makes funny sounds and faces at her. Her giggle warms your heart and brings smiles to those around her.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ta-and-alissa/hero/public","alt":"Paige makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-40/public","alt":"Paige makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-40/public","alt":"Paige makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kalen/hero/public","alt":"Paige makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Paige makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zoe/hero/public","alt":"Paige makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-42/public","alt":"Paige makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Paige makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-50/public","alt":"Paige makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2v