INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('priscilla', 'Priscilla', 2020, 'completed', 0, 1, 2, '{"name":"Priscilla","slug":"priscilla","age":4,"diagnosis":"Traumatic Brain Injury","roomTypes":["Accessible Bathroom","Therapy Room"],"year":2020,"status":"completed","bio":"Her only wish is to spend more time with her friends and Sunshine on a Ranney Day is going to grant it!\n\nPriscilla lives with her foster family, where she is deeply loved and flourishing. The home is not equipped to meet her needs as she develops and requires extensive care. Sunshine on A Ranney Day is designing a specialized therapeutic bedroom equipped with a calming sensory swing, soft therapeutic toys, contrasting bold colors and a variety of specifically designed lights which is intended to stimulate her senses and improve learning through her environment. We will also provide her with a fully accessible bathroom and a handicap ramp that will make transportation with a wheelchair easier. \nThis room tailored specifically for Priscilla and is constructed with learning and achieving developmental milestones in mind. It will be an oasis fit for a princess, where she can feel safe, loved and thrive. We hope to bring Priscilla a whole lot of sunshine and smiles that will brighten her days and help her unlock her ultimate potential. \nPlease join us as we present the completed design!","quote":"Her only wish is to spend more time with her friends and Sunshine on a Ranney Day is going to grant it!","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/priscilla/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/priscilla/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/priscilla/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/priscilla/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5