ivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/niki-murphy-photography/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"_migration":{"scrapedAt":"2026-03-06T13:32:09.465Z","source":"wordpress-xml-export","wpPostDate":"2021-06-26 22:29:36","wpCategories":["Meet the Kids"],"wpTags":["2020","Accessible Bathroom","Therapy Room"],"thumbnailId":1247,"needsReview":[],"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/308b7af2-0b66-471e-2163-01acc72b2700/full"},"streamVideoId":"417494fda97b4fbc0237d226f585d1ea","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('rachel', 'Rachel', 2014, 'completed', 0, 1, 1, '{"name":"Rachel","slug":"rachel","year":2014,"status":"completed","bio":"Rachel Buckner’s sweet smile radiates warmth, doesn’t it?  This beautiful nine-year-old is winning the battle against Leukemia!  Last year, Rachel was enjoying summer camp with her Girl Scout Troop when she became ill. What began as feeling tired with a reduced appetite led to a visit to the hospital and a heartbreaking diagnosis.  Rachel was diagnosed with childhood acute lymphoblastic leukemia (also called ALL or acute lymphocytic leukemia).  This is a cancer of the blood and bone marrow.  ALL is the most common childhood leukemia and the prognosis is favorable.  However, the battle is painful and exhausting.  Physicians expect that her treatment will last for two years and consists of chemotherapy, painful spinal taps and muscle weakness.  Rachel’s amazing spirit carries her through! Rachel loves spending time with her friends and her older sister Caroline.  Her parents delight in hearing the girls laugh and tease each other.  Rachel loves stuffed animals, books music and American Girl dolls.  She still loves to dress like a fashionista with glamorous hats and wants what all girls crave, a beautiful pink and purple palace where she can sleep restfully and dream of her future.  SOARD has teamed up with designers to make her dreams come true.  Because Rachel is often fatigued from her treatments, she needs to rest throughout the day and often goes to bed early.  Currently, her room does not have enough insulation to block the noise of the daily hustle and bustle, but that will change with this remodel.  With plans to add specialized drywall and insulation, our design team is currently working on transforming her room to become that special place where she can rest, dream and soar.  Join us for the royal reveal on March 1, 2014 to see this beautiful princess smile and shine!","quote":"Rachel Buckner’s sweet smile radiates warmth, doesn’t it?  This beautiful nine-year-old is winning the battle against Leukemia!  Last year, Rachel was enjoying summer camp with her Girl Scout Troop when she became ill. What began as feeling tired with a reduced appetite led to a visit to the hospita","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/rachel/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/rachel/hero/public","alt":"Rachel makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/rachel/photo-02/public","alt":"Rachel makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/rachel/photo-03/public","alt":"Rachel makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/rachel/photo-04/public","alt":"Rachel makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/rachel/photo-05/public","alt":"Rachel makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/rachel/photo-06/public","alt":"Rachel makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/09d0e72d-677c-4628-5aeb-d0497b746200/full","source":"wix-migration","wixNumber":11},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('raynel', 'Raynel', 2021, 'completed', 0, 1, 1, '{"name":"Raynel","slug":"raynel","age":16,"diagnosis":"Spastic Quadriplegic Meningitis","roomTypes":["Accessible Bathroom"],"year":2021,"status":"completed","bio":"His current room and bathroom are too narrow to meet his needs for transferring, showering and moving throughout the home.\n\nRaynel has Spastic Quadriplegic Meningitis which was contracted at the age of four. The effects of the infection led to many permanent disorders including obstructive hydrocephalus, cerebral palsy, a neurogenic bladder, developmental delay and hearing loss. He is fully dependent for all activities of daily living. Raynel has had a cochlear implant and is learning to use American Sign Language to communicate. His parents are learning ASL along with him so that they can continue to communicate with him as his language advances. \n\nSunshine on a Ranney Day is ecstatic over being able to see how much Raynel has grown and continue to support him as his needs change. He is truly extraordinary and continues to inspire us with his strength, positivity and illuminating smile. We are eager to complete these renovations and see him smile once again!","quote":"His current room and bathroom are too narrow to meet his needs for transferring, showering and moving throughout the home.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/raynel/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/raynel/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/raynel/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/raynel/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/raynel/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/raynel/photo-05/public","alt