INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('samuel', 'Samuel', 2020, 'completed', 0, 1, 1, '{"name":"Samuel","slug":"samuel","age":9,"diagnosis":"Cerebral Palsy","roomTypes":["Therapy Room"],"year":2020,"status":"completed","bio":"Due to his challenges with cerebral palsy and balance deficits, Samuel is unable walk independently. He uses a Kaye Reverse walker, a gait belt, or a Lofstrand crutch for mobility.\n\nDue to his challenges with cerebral palsy and balance deficits, Samuel is unable walk independently. He uses a Kaye Reverse walker, a gait belt, or a Lofstrand crutch for mobility. He also wears AFO''s on both feet and has significant weakness in his right hand. Samuel has put in hundreds of hours working through physical therapy, occupational therapy, therapeutic horseback riding, and a one-on-one gymnastics class for conditioning and strengthening. Every little success is a milestone for him and he has made huge stride over the past several years. After enormous amounts of hard work and dedication, Samuel can stand for minutes at a time, walk across the therapy gym without falling and catch a volleyball. These feats drive him to work harder and keep sight of his goals and dreams. \n\nIn spite of his physical challenges, Samuel is like any other 8 year-old boy with a hearty sense of humor, zest for mischief, a wealth of good jokes, an obsession with motorcycles and a never-ending supply of giggles when his dog bathes his ears with kisses. His ultimate goal is to ride a motorcycle one day and he is surely going to accomplish that goal.\n\nThe relationship between Samuel and his brother Wesley is a beautiful and unique one. Wesley lovingly stands by him in every endeavor and cheers him on. Samuel yearns to be as independent as his brother and therefore eagerly works toward mastering new skills. They celebrate every victory together and no triumph is small. \n\nSunshine on a Ranney Day will be celebrating all of Samuel''s conquests through the provision of a stunning new therapy room! We look forward to watching him light up the room as his radiant smiles and contagious giggles fill the renovated space! We hope that you will join us at the big reveal!","quote":"Due to his challenges with cerebral palsy and balance deficits, Samuel is unable walk independently. He uses a Kaye Reverse walker, a gait belt, or a Lofstrand crutch for mobility.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/samuel/photo-15/public","alt":""},{"url":"https:/