INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('shane', 'Shane', 2020, 'completed', 0, 1, 2, '{"name":"Shane","slug":"shane","age":8,"diagnosis":"Cerebral Palsy","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2020,"status":"completed","bio":"The financial burden of Shane''s care has kept the family from being able to add an accessible bathroom, so they must lift Shane and carry him to the tub.\n\nShane''s parents were able to move their family, which also includes his little sister, to a ranch style home to better accommodate his wheelchair. Home is a bustling place where Shane''s sister is a very active child. She is quite protective of Shane, and dad likes to say she talks enough for the two of them. The family also includes Shane''s grandparents, who immigrated from India to help with his care. The financial burden of Shane''s care has kept the family from being able to add an accessible bathroom, so they must lift Shane''s 60 pounds (and growing) frame and carry him from outside the bathroom to the tub. Giving a bath has become an overwhelming physical and emotional task after days filled with physical therapy, occupational therapy, feeding therapy, vision, aquatic, and speech therapy.\n\nShane may not be able to carry on an interactive conversation but imagine a less stressful end to a busy day; a safe bath and then his enjoying some music with his family in the safe harbor of a colorful and accommodating bedroom.","quote":"The financial burden of Shane''s care has kept the family from being able to add an accessible bathroom, so they must lift Shane and carry him to the tub.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shane/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shane/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shane/photo-02/public","alt":""},{"url":"https://imagedelivery.net/RO