rtners/cr-construction/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/randall-brothers/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/echols/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/rooms-to-go/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/behr-paint/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/devore-johnson/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/keuco/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/mohawk/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/iframe-media/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/signature-hardware/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/sweet-life-photography/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"_migration":{"scrapedAt":"2026-03-06T13:32:09.464Z","source":"wordpress-xml-export","wpPostDate":"2021-06-26 22:27:51","wpCategories":["Meet the Kids"],"wpTags":["2020","Accessible Bathroom","Dream Bedroom"],"thumbnailId":1244,"needsReview":[],"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/b90ad1b0-3459-4032-0695-e6990c270a00/full"},"streamVideoId":"5761822471fe541b91a053d02ce757a5","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('shawn-2018', 'Shawn', 2018, 'completed', 0, 1, 2, '{"name":"Shawn","slug":"shawn-2018","age":19,"diagnosis":"Microcephaly, Cerebral Palsy, and Epilepsy","roomTypes":["Dream Bedroom","Therapy Room"],"year":2018,"status":"completed","bio":"Shawn is a handsome and maturing nineteen year old young man who will soon be graduating high school. This vibrant teen enjoys bowling, biking, walking and riding the school bus. He also loves watching movies, his iPad, camps and socializing.  \n\nShawn is developmentally disabled due to microcephaly, cerebral palsy, and epilepsy. He is nonverbal and requires assistance with most activities of daily living including bathing, toileting, dressing and hygiene.  As he grows and becomes a young adult, his needs will change significantly.  He will remain in special education programs through age 21 at which time he will graduate and spend a great deal of time at home. Although he will be enrolled in a day program, he will need a unique space of his own where he can continue to thrive, mature and reach his ultimate potential.\n\nSunshine on a Ranney Day will be designing a specialized space that reflects his interests complete with a renovated bedroom and a therapy suite.   The importance of developing your individuality as an adult is a crucial part of maturation and having your own space is a cherished rite of passage we hope Shawn truly enjoys!","quote":null,"heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn-2018/photo-18/public","alt":""}],"photoCount":18,"videoUrl":"https://youtu.be/e5aP_glP2_Q?si=yQm2qXDDMqjY03EO","photographer":null,"partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/mohawk/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/rooms-to-go/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/reliable-heating-and-air/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/discount-tire/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/anna-gamble-photography/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/creative-floor-works/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/sweet-mayberrys/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/porter-paints/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"streamVideoId":"f34c5416772ac7d53e858c38912b026d","roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('shawn', 'Shawn', 2017, 'completed', 0, 1, 3, '{"name":"Shawn","slug":"shawn","age":11,"diagnosis":"Duschenne Muscular Dystropy","roomTypes":["Accessible Bathroom","Dream Bedroom","Therapy Room"],"year":2017,"status":"completed","bio":"This young and debonair role model is Kyle and we are proud to be working on a special renovation project for his home.  Despite only being 11 and diagnosed with a rare disability, he demonstrates all of the qualities of a leader and those required to be a successful coach: knowledge of sports; excellent communication skills; the ability to inspire and motivate; determination and patience; physical stamina and a sensitive and supportive approach. Those who know him say he has been special from day one, with a kindness in his heart that puts everyone at ease.  You can certainly see this when he smiles!\n\nKyle is exceptional and admirable in every aspect.  He has big dreams and will let absolutely nothing stand in his way of achieving them, including Duchenne Muscular Dystrophy.  This rare genetic disease causes the body to fail to produce dystrophin, which is a protein which allows muscles to regenerate.  Without appropriate levels of dystrophin, the muscles of the body will atrophy or shrink over time causing a loss of mobility and function.  Children who seem to be developing typically, with strong muscles and healthy bodies will eventually lose many of their motor skills and the function of their organs.\n\nKyle has unwavering determination.  He takes pleasure in every moment of his adventurous life and has resolved to triumph by achieving his long term goals-no matter what!  He aspires to achieve a decorated list of accomplishments including the following plan:\n\nHe will be on the 2021 US Power Soccer World Cup team.\nHe will go to college and get a double degree in Physical Education and Business.\nHe will first be the first Head College Football Coach on the sidelines in a wheelchair.\nHe will then go to culinary school to become a chef.\nAfterwards, he will open a small chain of Restaurants cashing in on his winning record and popularity as a local Coach.\n\nThis makeover will incorporate all of the things he loves most. At the top of his list are his X-box, Florida State University, the Falcons and the Dolphins.  We are excited to see him thrive and enjoying his new room with his sister Emily and brother Conor, oh and can''t leave out the family dog Sam!","quote":"\"He has big dreams and will let absolutely nothing stand in his way of achieving them\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/shawn/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/kyle/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuP