INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('sims', 'Sims', 2015, 'completed', 0, 1, 1, '{"name":"Sims","slug":"sims","year":2015,"status":"completed","bio":"Our next big project is a remodel for the Sims family.  This tight-knit family is led by Estella Sims, a selfless and compassionate mother of three special needs youth.  Although she is in her sixties with physical ailments of her own, she devotes herself to ensuring that they have all of their needs met and plenty of love!  It was love, generosity and a philanthropic spirit that led her to adopt Antavious, Shanika, Ashley and Terrace.  Their bright eyes and sweet smiles make it evident that they are happy to be part of this forever family.  Shanika reports that she is grateful that Estella chose to be her mother and provide her with such a loving environment and a better life.  When interviewed, she stated, “I love my mom very much for the love and precious things she has given me.  I hope that every child receives the love and support I have received.”  This beautiful sentiment speaks volumes to the values being instilled by Estella. In addition to love, the Sims family unit thrives on the principles of acceptance and appreciation of one another.  Although the challenges they face include blindness, Cerebral Palsy, developmental disabilities, Fetal Alcohol Syndrome and chromosomal abnormalities, their can-do attitude and desire to overcome all obstacles together keeps them strong and triumphant.  These obstacles have become increasingly more difficult to manage as the children have grown. As they grow, so does the need for larger wheelchairs, medical equipment and accessibility.  These needs supersede the size and infrastructure of their small home. Sunshine on a Ranney Day plans to help them out by adding on to their home in order to make space for their medical equipment, make their bathroom wheelchair accessible and add room for a nurse.  This will be the last project of adding onto a home for SOARD. Sunshine on a Ranney Day has been blessed to have Jackson Healthcare help support this makeover financially as well as have their employees help with the renovation!  It brings us joy to be able support Estella and her family! We hope that you will join us at the reveal this winter!","quote":"Our next big project is a remodel for the Sims family.  This tight-knit family is led by Estella Sims, a selfless and compassionate mother of three special needs youth.  Although she is in her sixties with physical ailments of her own, she devotes herself to ensuring that they have all of their need","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Sims makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Sims makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/angel/photo-56/public","alt":"Sims makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/breanna/photo-25/public","alt":"Sims makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-46/public","alt":"Sims makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Sims makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/photo-07/public","alt":"Sims makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/photo-08/public","alt":"Sims makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/photo-09/public","alt":"Sims makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/eli/photo-31/public","alt":"Sims makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/photo-11/public","alt":"Sims makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/photo-12/public","alt":"Sims makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/photo-13/public","alt":"Sims makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/photo-14/public","alt":"Sims makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/photo-15/public","alt":"Sims makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/a61d1dbc-75f9-46c4-8b35-bdca2c949700/full","source":"wix-migration","wixNumber":30},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('sofia', 'Sofia', 2015, 'completed', 0, 1, 1, '{"name":"Sofia","slug":"sofia","year":2015,"status":"completed","bio":"Sofia, who is 5 years old has a smile that gives strength to her entire family. Sweet Sofia is the youngest of three children; sister to Adrian 13, and Celina 11.  Sofia was born with congenital health complications but is making progress. Sofia was born with respiratory problems that kept her in NICU for two months and before she was released, her family learned that she was diagnosed with Anemia, Apnea, Pharyngeal Dysphagia and Cranial Nerve Nuclei. Shortly after in her young life, she was diagnosed with Cerebral Palsy and Moebius Syndrome, which is an extremely rare congenital neurological disorder characterized by facial paralysis and inability to move eyes from side to side. She also has kidney failure and hearing loss. Already by age 4, she had 2 surgeries on her hips, including a 3-week hospitalization due to a respiratory infection during the surgery. Despite these congenital complications, Sofia is currently in Pre-K and receives therapy and learning how to communicate with sounds, as well as learning sign language.  Sunshine on a Ranney Day is renovating the master bathroom and making it wheelchair accessible.  Sofia was also sharing a room with her sister.  We are giving her, her own room which was her brother Adrian''s.  We are finishing off a garage room to make it into Adrian''s bedroom and additional storage space.   SOARD is so grateful to have a partnership with Telemundo Atlanta for this project.  Come join us for a special reveal on Saturday May 2nd at 12pm in Rex, GA!","quote":"Sofia, who is 5 years old has a smile that gives strength to her entire family. Sweet Sofia is the youngest of three children; sister to Adrian 13, and Celina 11.  Sofia was born with congenital health complications but is making progress. Sofia was born 