INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('stetson', 'Stetson', 2020, 'completed', 0, 1, 1, '{"name":"Stetson","slug":"stetson","age":6,"diagnosis":"Angelman Syndrome","roomTypes":["Therapy Room"],"year":2020,"status":"completed","bio":"It is ironic that \"happy\" is a symptom of Angelman Syndrome, a rare neurogenetic disorder that causes global developmental delays, lack of speech, and seizures.\n\nStetson''s mom stopped working outside the home to care for him. They have spent the last four years traveling to specialists all over the east coast and even participating in brain studies to help learn more about this rare disease. Stetson participates in speech therapy twice a week, hippo-therapy, and swim lessons as well as going to kindergarten, where he also receives additional PT, OT, and speech therapy. \nChildren with AS tend to be very sensory seeking and have an oral fixation, but overall, they are happy kids. Stetson loves to wander, climb, and play with whatever he can get his hands on. He can be very impulsive and is not always safe while exploring. He has to be watched non-stop, even in his own home, to make sure he is safe. With the increasing demands of a new baby brother, a sensory/therapy room will allow Stetson to explore and play safely while attention is shared between two children. It will also provide him with the opportunity to improve his motor skills at home while playing and offer some of the independence six-year-old boys crave, things that are important for his development. Stetson''s parents will have peace of mind knowing he is both safe and getting the proper stimulation.\nThe past five years have been replete with travel, testing, and treatment. With an in-home sensory/therapy room, Stetson''s whole family will benefit from more routine day-to-day life at home.","quote":"It is ironic that \"happy\" is a symptom of Angelman Syndrome, a rare neurogenetic disorder that causes global developmental delays, lack of speech, and seizures.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-12/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-13/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-14/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-15/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-16/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-17/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/stetson/photo-18/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alejandro/photo-19/public","alt":"Ste