INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('summit-counseling-center', 'Summit Counseling Center', 2017, 'completed', 0, 1, 1, '{"name":"Summit Counseling Center","slug":"summit-counseling-center","year":2017,"status":"completed","bio":"We love working with other organizations who focus on helping give hope and healing to children. Summit Counseling Center of Atlanta has an amazing service to help counsel children with health and behavior issues, abuse, loss from divorce or death, suicidal feelings, bullying, self-harm, social issues and many other things.  Did you know the #2 leading cause of death among those 10-24 years old is suicide? Helping children in their early stages can help save a life. This past year the Summit Counseling Center has had an increase of children by over 50%. The large conference room went under renovation to make it into 2 therapy rooms.  These therapy rooms are helping professional therapists give many more children the help that they need to heal. Sunshine on a Ranney Day worked with a top designer, Crosby Design Group and these rooms look amazing! ","quote":"We love working with other organizations who focus on helping give hope and healing to children. Summit Counseling Center of Atlanta has an amazing service to help counsel children with health and behavior issues, abuse, loss from divorce or death, suicidal feelings, bullying, self-harm, social issu","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","alt":"Summit Counseling Center makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-41/public","alt":"Summit Counseling Center makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/grace/hero/public","alt":"Summit Counseling Center makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Summit Counseling Center makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-44/public","alt":"Summit Counseling Center makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-43/public","alt":"Summit Counseling Center makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-46/public","alt":"Summit Counseling Center makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Summit Counseling Center makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/photo-09/public","alt":"Summit Counseling Center makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/photo-10/public","alt":"Summit Counseling Center makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/photo-11/public","alt":"Summit Counseling Center makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/photo-12/public","alt":"Summit Counseling Center makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/photo-13/public","alt":"Summit Counseling Center makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/d02b92ba-53b9-4f96-fac7-00ebd2cdc000/full","source":"wix-migration","wixNumber":65},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('ta-and-alissa', 'Ta & Alissa', 2014, 'completed', 0, 2, 1, '{"name":"Ta & Alissa","slug":"ta-and-alissa","year":2014,"status":"completed","bio":"Great news!  This beautiful family is getting a beautiful home remodel!  Tashawn “Ta” and his sister Alissa are flipping with excitement.  Aren’t they precious?  With the help of Sunshine on a Ranney Day and The Atlanta Swim Academy, this sensational project will be making its splash of a debut May 3rd as it kicks off with a Charity Swim-a-Thon organized and implemented by the children of the Swim Academy.  These thoughtful young athletes have come together to help SOARD raise money to make this remodel possible.  Ta and Alissa will be cheering them on as they swim lap after lap in their honor. Participants will help the SOARD team design dream rooms for Ta and Alissa.  Since they are both passionate about swimming, the team has plenty of inspiration already.  The reveal for the project is set for June 21st and our volunteers are ready to dive in.  Ta and Alissa are a dynamic duo.  They were brought to their parents as foster children from different families and were later adopted.  Their mom, Ali, is a social worker and is passionate about making children’s dreams come true.  She and her husband were happy to be able to do just that for Ta and Alissa.  It is clear that this family was destined to be together.  You can’t look at these gorgeous family photos without seeing the LOVE they have for one another!  Ta is an outgoing and independent eight year old young man who does not let his disability get in the way of achieving his goals!  Born at only 27 weeks gestational age, Ta weighed only a little over a pound and was diagnosed with Cerebral Palsy and a seizure disorder at an early age. He takes medications to control his seizures and asthma symptoms. Despite the challenges of his physical disability, he is eager to learn and strives to be as independent as he can be.  He is excelling at school and beginning to read.  He even represented his class in the school geography bee this year! Ta propels his manual wheelchair everywhere, plays wheelchair sports and loves swimming.  Not only is he a champion in the pool, but also on land.  He has begun to walk with a walker, but the carpeting in his home makes it difficult to get around as fast and easily as he’d like to. Alissa, this adorable three year old doll with radiant curls, was born at 26 weeks gestational age.  She was only 9.84 inches long at birth and spent the first two months of her life in the NICU.  Alissa has severe acid reflux disease and digestive disorders.  She has a g-tube that is used for supplemental nutrition, fluids and medications.  Alissa struggles with asthma and chronic illness as well.  Her immune system is limited, therefore she gets sick very often.  Despite weekly medical appointments and battling chronic illness, Alissa is thriving developmentally. Her speech and language has exploded and she is an extremely adventurous child.  Alissa loves to play at the park, run, jump and climb on everything.  She is also a swim enthusiast like her brother!  Her larger than life personality and strong will have helped her excel in every aspect of her life.  Aside from remodeling both of the children’s rooms, SOARD will be removing the carpet and replacing it with laminate flooring so Ta can be mobile throughout his whole home.  We will also be expanding his second story bathroom and adding a roll-in shower so he can be more independent.  Additionally, renovation plans include an electric chairlift leading from the garage to the main living areas and second floor so he can independently travel throughout his home.  The remodel will surely include exciting areas for Alissa to tumble and explore as well! Of course no kid room makeover is complete without our inspirational kids chairs, made in USA and available for purchase online.  This unique partnership between the children of The Atlanta Swim Academy and SOARD is one to be treasured.  What is more heartwarming than children helping children? Whether you are a zealous swimmer, enjoy an occasional dip in the pool, love swimming against the tide or venturing beyond the shoreline, please join us in supporting and cheering on Ta and his team!  For more information on how you can help, please contact us at info@sunshineonaranneyday.com or click the link below to learn how to get involved in the Swim-A-Thon at The Atlanta Swim Academy. Special THANKS to Emily Main with Here on Earth Photography for giving this family a very special family photo shoot!  We know these families do not take much time out for themselves, so this was our treat!","quote":"Great news!  This beautiful family is getting a beautiful home remodel!  Tashawn “Ta” and his sister Alissa are flipping with excitement.  Aren’t they precious?  With the help of Sunshine on a Ranney Day and The Atlanta Swim Academy, this sensational project will be making its splash of a debut May ","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ta-and-alissa/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ta-and-alissa/hero/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/summit-counseling-center/hero/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-39/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ta-and-alissa/photo-07/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/adrian/photo-31/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ta-and-alissa/photo-09/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/alejandro/photo-30/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ta-and-alissa/photo-11/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ta-and-alissa/photo-12/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ta-and-alissa/photo-13/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ta-and-alissa/photo-14/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ta-and-alissa/photo-15/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ta-and-alissa/photo-16/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ta-and-alissa/photo-17/public","alt":"Ta & Alissa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/ta-and-alissa/photo-18/public","alt":"Ta & Alissa makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/6b7f10a1-2cc7-43e5-206d-8b87fc093800/full","source":"wix-migration","wixNumber":15},"childCount":2,"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('tayler', 'Tayler', 2014, 'completed', 0, 1, 1, '{"name":"Tayler","slug":"tayler","year":2014,"status":"completed","bio":"Sunshine on a Ranney Day and Make-A-Wish® Georgia have teamed up to brighten the world of little Miss Tayler.  Tayler’s life is nothing short of a miracle!  At birth, doctors believed she would not survive, but she has made it her mission to prove them wrong.  Tayler’s mom was only eight months pregnant when she was born. Her mom had been in the hospital for a while, but the doctors were not 100% sure what was wrong.  Tayler was delivered through cesarean section and during the delivery, the doctors broke all the bones in her body.  At that time, they diagnosed her with two life threatening medical conditions: Osteogenesis Imperfecta and Hypoplastic Lung Syndrome.  Osteogenesis Imperfecta, also known as brittle bones disease, affects the body’s ability to produce collagen and connective tissue which leads to easily fractured bones, loose joints and reduced muscle tone.  This condition is why all her bones broke during the delivery. The second condition, Hypoplastic Lung Syndrome, caused her lungs to be very small – “pea size” according to her family.  As a result of her underdeveloped lungs, Tayler was placed on a ventilator to help her breathe and the doctors did not think that she would survive for very long.  In fact, they tried to convince her mom and dad to take her off the ventilator, but they refused.  After living in the hospital on the ventilator for eleven months, the doctors were able to perform a tracheostomy for Tayler.  This allowed her to come home for the first time!  Since then, Tayler has lived at home with her conditions and proved the doctors wrong, surpassing all of their expectations.   Tayler spends most days in her room where she can be close to her medical equipment.  She sleeps in a crib and has a nurse with her for at least 12 hours each day. Tayler loves to get outside, but it is hard because she requires extensive medical equipment.  She enjoys spending time with her favorite people and experiencing new things.  Tayler smiles, laughs and giggles when she is happy!  She also loves stickers, books, Cheetos and dum-dum lollipops.  Yummy!  Tayler’s room is a very special place as she spends most of her time there.  Her room is where she enjoys the company of her family and visitors.  She loves lights and is drawn to visual stimuli, therefore renovations will include specialized materials designed to appeal to her senses as she explores her environment.  Please join us for the reveal on March 22, 2014.  Sunshine on a Ranney Day is transforming an extra room that is larger, into Tayler''s bedroom so she has more room for all of her medical equipment and room for her and her nurse to play.  Sunshine on a Ranney Day and Make-A-Wish® Georgia aim to transform the lives of children with life threatening medical conditions and make them smile.  It is exciting to partner with this organization to make Tayler’s wishes come true so she can continue to shine and bless the world with her beautiful light.","quote":"Sunshine on a Ranney Day and Make-A-Wish® Georgia have teamed up to brighten the world of little Miss Tayler.  Tayler’s life is nothing short of a miracle!  At birth, doctors believed she would not survive, but she has made it her mission to prove them wrong.  Tayler’s mom was only eight months preg","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tayler/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tayler/hero/public","alt":"Tayler makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tayler/photo-02/public","alt":"Tayler makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tayler/photo-03/public","alt":"Tayler makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tayler/photo-04/public","alt":"Tayler makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tayler/photo-05/public","alt":"Tayler makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tayler/photo-06/public","alt":"Tayler makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tayler/photo-07/public","alt":"Tayler makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/0fadbe5f-1179-4301-22b6-6f04f117b500/full","source":"wix-migration","wixNumber":12},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('tripp', 'Tripp', 2013, 'completed', 0, 1, 1, '{"name":"Tripp","slug":"tripp","year":2013,"status":"completed","bio":"We met Stacy and Bill Halstead in the fall of 2012; and, were immediately touched and inspired by their story. Together with their extended family, they are proving to be an amazing pillar of strength for their young son, Tripp.   Stacy and Bill met in Asheville NC in 2006 and married the following year. Difficulty in getting pregnant led them to fertility specialists and soon Stacy learned that their efforts were successful. Feeling tremendously blessed, Stacy and Bill cherished every moment they spent with their thriving baby boy. Hopes of giving Tripp a sibling were dashed after the devastating miscarriage of a daughter they named Ella Mary. Shortly thereafter they learned that their window of opportunity for bearing more children was becoming increasing small. After overcoming their loss, Stacy and Bill immersed themselves in providing Tripp the best they could offer. Their family was complete.  On Monday, October 29, 2012 life changed irrevocably for Tripp, and Stacy, and Bill. The day began as just another typical day. They dropped Tripp off at daycare, kissing him goodbye and reminding him how much they loved him, then continued on to work. Later that morning, while playing in the yard, high winds whipped unexpectedly through the neighborhood of the daycare center. A huge tree limb snapped in a gust and, tragically, fell directly onto Tripp’s head.  He was rushed to Winder-Barrow Hospital then flown to Egleston Children’s Hospital in Atlanta. Emergency surgery revealed that the impact of the tree limb had shattered Tripp’s skull into multiple pieces. His prognosis was poor and Stacy and Bill were told to brace for the worst. Miraculously, Tripp survived that initial surgery and several that immediately followed. The next several months were like an out-of-control rollercoaster - physically for him, and emotionally for Stacy and Bill.  Tripp is proving to be quite a fighter as he endures innumerable obstacles and surgeries. The road ahead is full of challenges. Doctors remain unsure of the extent of Tripp’s brain injury and his prognosis is uncertain. However, Stacy and Bill''s faith is unshakeable and within the year began preparations to bring Tripp home.  With a new (to them) ranch-style house purchased, Bill started planning a wheel-chair accessible remodel. It was around this time that Sunshine on a Ranney Day heard about his ambitions and stepped in to assist. With the goal of making the entire house Tripp friendly - we totally gutted the interior and started, basically, from scratch. We transformed a conventional house into a comfortable, functional, and fully-accessible home with a spacious open floor-plan. Hundreds of volunteers, businesses and sponsors supported and assisted in making this dream become a reality. We are also very thankful for all the generous monetary donations. We connected with people around the world who are touched by Tripp''s story and by our mission.","quote":"We met Stacy and Bill Halstead in the fall of 2012; and, were immediately touched and inspired by their story. Together with their extended family, they are proving to be an amazing pillar of strength for their young son, Tripp.   Stacy and Bill met in Asheville NC in 2006 and married the following ","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tripp/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tripp/hero/public","alt":"Tripp makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tripp/photo-02/public","alt":"Tripp makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tripp/photo-03/public","alt":"Tripp makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tripp/photo-04/public","alt":"Tripp makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tripp/photo-05/public","alt":"Tripp makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tripp/photo-06/public","alt":"Tripp makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tripp/photo-07/public","alt":"Tripp makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/10acbb5c-078a-48c9-6268-11edcd002e00/full","source":"wix-migration","wixNumber":6},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('tyrece-maddie-zane-and-quinn', 'Tyrece, Maddie, Zane, & Quinn', 2025, 'in-progress', 0, 4, 2, '{"name":"Tyrece, Maddie, Zane, & Quinn","slug":"tyrece-maddie-zane-and-quinn","age":null,"diagnosis":"Tyrece 10, Maddie 9, Zane 8, Quinn 8","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2025,"status":"in-progress","bio":"Tyrece, Maddie, Zane, and Quinn are four extraordinary children who''ve overcome incredible challenges and are now thriving in a home filled with love, laughter, and possibility. Each of them came into the world facing adversity — and each found their forever family with Vicki and Cyndy, two moms who saw their strength and chose to help them grow, heal, and shine.\n\nTyrece, age 10, is full of curiosity, courage, and quiet determination. He is Navajo and came to his family as a baby after surviving shaken baby syndrome, which left him with cerebral palsy, a traumatic brain injury, legal blindness, severe scoliosis, and Autism Level 3. Doctors didn''t believe he''d survive. But Tyrece has never stopped proving people wrong. He''s incredibly smart, communicates using a button device, and lights up when he hears music — especially traditional Navajo songs. He races with Ainsley''s Angels, plays baseball, joined the robotics team at school, and even starred in the school musical. Tyrece loves the wind, the water, and being included in everything. He doesn''t just want to be in the room — he wants to be part of the story.\n\nMaddie, age 9, is quiet and deeply resilient — a true warrior at heart. After suffering severe abuse and neglect, including an attempted drowning and shaken baby syndrome, Maddie came to Vicki and Cyndy with a TBI, CP, Autism Level 3, scoliosis, brittle bones, and significant feeding challenges. For a long time, he didn''t trust anyone. Now, he''s beginning to respond, smile, and communicate with the help of a button, following his big brother Tyrece''s lead. Maddie loves to be held, go for walks, and listen to his favorite music — especially Bing Crosby. His Tonies box brings him comfort, and his moms say he''s an old soul. Every day, he shows more signs of engagement and strength. Every day, he chooses to keep going.\n\nZane, age 8, is the thinker of the family — a little professor with a giant heart. He has mild CP, Autism Level 2, ADHD, and OCD. He came to the family when he was just a month old and has grown into a bubbly, inquisitive boy who loves water, teaching others, and being around people. Zane plays CP soccer, attends school with his sister Adrianna, and is always ready to ask questions or blow bubbles. He is curious about everything and loves helping his siblings.\n\nQuinn, also 8 and Maddie''s biological brother, is the calm in the storm. He has Autism Level 2 and ADHD and is happiest when things are structured and peaceful. He loves his tablet, Legos, and quiet time indoors. He doesn''t enjoy being outside as much, which is one reason the family chose their new home — to create a space where all four children could feel safe, free, and supported.\n\nSoon, their home will grow even more — this summer, the family will welcome Alyssa, a 43-year-old Navajo woman with cerebral palsy who previously lived in a group home on the reservation. Vicki and Cyndy took custody of her to ensure she could live with love, dignity, and the same sense of family that they''ve given their boys. The move into their larger home was made with her in mind, and it''s another example of how this family doesn''t just care for children — they think about lifelong support, inclusion, and care.\n\nVicki and Cyndy are more than moms — they''re advocates, educators, and community builders. Vicki is a professor of Nursing and serves on the board of Ainsley''s Angels, and both moms are actively involved in the local special needs community. They bring their kids to adaptive events, advocate for inclusion, and offer supplies and support to other families in need. They believe their children should be seen, heard, and celebrated — and that by helping them thrive, they''re helping the entire community grow stronger, too.","quote":"Tyrese, Maddie, Zane, and Quinn are not defined by what they''ve been through. They are defined by who they are: resilient, joyful, brilliant, and brave. This is not just a story about survival \\u2014 it''s a story about becoming.","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tyrece-maddie-zane-and-quinn/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tyrece-maddie-zane-and-quinn/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tyrece-maddie-zane-and-quinn/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tyrece-maddie-zane-and-quinn/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tyrece-maddie-zane-and-quinn/hero/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tyrece-maddie-zane-and-quinn/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tyrece-maddie-zane-and-quinn/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tyrece-maddie-zane-and-quinn/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tyrece-maddie-zane-and-quinn/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tyrece-maddie-zane-and-quinn/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tyrece-maddie-zane-and-quinn/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/josue/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/marie-and-alondra/photo-42/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/tyrece-maddie-zane-and-quinn/photo-13/public","alt":""}],"photoCount":13,"videoUrl":null,"photographer":null,"partnerLogos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/gas-south/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/kids-r-kids/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/jackson-healthcare/public"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/partners/real-floors-commercial/public"}],"shortDescription":null,"metaDescription":null,"altTexts":null,"jsonLd":null,"childCount":4,"roomCount":2}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('vanessa', 'Vanessa', 2017, 'completed', 0, 1, 1, '{"name":"Vanessa","slug":"vanessa","year":2017,"status":"completed","bio":"This alluring, spirited teenager is Vanessa.  Vanessa was born in Boston while her family was visiting from Haiti.  From the very start, her parents knew that she was special.  She was born with sickle cell anemia, also known as sickle cell disease.  This disease is characterized by abnormal hemoglobin in the red blood cells.  The lack of hemoglobin and oxygen in the blood causes chronic widespread pain and fatigue.  This condition can be exacerbated to crisis level and can be brought on by illness, temperature changes, stress, dehydration and being at high altitudes.  The trauma of chronic pain and anemia can lead to significant organ damage and become life threatening. In Vanessa’s case, sickle cell anemia robbed her of energy and stamina.  This led to difficulty participating in and enjoying everyday activities that most kids delight in daily, like swimming at the pool, playing at the park and trick or treating. Watching her endure such excruciating pain and unable to experience a jovial childhood was heart wrenching. When Vanessa turned 7 her crises became more serious and life threatening.  With hopes of a brighter future, her family moved to the United States so that she could receive advanced medical care.  Soon after that an unexpected miracle changed her fate forever.  Her angelic baby sister, Sarah, was born sickle cell free and was also a perfect match for Vanessa’s bone marrow.  Sarah’s healthy birth allowed for the bone marrow transplant needed to give Vanessa a healthy future. The process was long, recovery was hard, but the results were phenomenal and well worth the wait.    Today, Vanessa is healthy and has a beautiful future ahead of her. She is a selfless happy teenager full of hopes and dreams and is living pain free. Vanessa has a creative soul and is brilliantly talented.  She has a passion for fashion, loves designing, sewing, and arts and crafts. Like most teens, she loves having her friends over to experiment with make-up and glamorous hairstyles. Sunshine on a Ranney Day partnered with Make-A-Wish Georgia to give Vanessa a dream room makeover where she, Sarah and her friends can cherish the magnificent joys of youth together.  ","quote":"This alluring, spirited teenager is Vanessa.  Vanessa was born in Boston while her family was visiting from Haiti.  From the very start, her parents knew that she was special.  She was born with sickle cell anemia, also known as sickle cell disease.  This disease is characterized by abnormal hemoglo","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/vanessa/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/vanessa/hero/public","alt":"Vanessa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/sims/hero/public","alt":"Vanessa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-42/public","alt":"Vanessa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Vanessa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/caliyah/photo-29/public","alt":"Vanessa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/andrew/photo-43/public","alt":"Vanessa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Vanessa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/vanessa/photo-08/public","alt":"Vanessa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/vanessa/photo-09/public","alt":"Vanessa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/vanessa/photo-10/public","alt":"Vanessa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/vanessa/photo-11/public","alt":"Vanessa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/vanessa/photo-12/public","alt":"Vanessa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/vanessa/photo-13/public","alt":"Vanessa makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/vanessa/photo-14/public","alt":"Vanessa makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/1f805f2b-01b3-45fd-7103-d3a52adfe600/full","source":"wix-migration","wixNumber":66},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('zoe', 'Zoe', 2016, 'completed', 0, 1, 1, '{"name":"Zoe","slug":"zoe","year":2016,"status":"completed","bio":"We’d like to introduce Zoe. Zoe is a delightful preteen who brings smiles to the faces of all who encounter her.  This growing 11-year old is as happy as she is beautiful.  Zoe was only four weeks old when her parents were blindsided by the diagnosis of Cerebral Palsy.  Despite mourning the life which they had planned for her, her loving parents teamed up to provide her with the best life imaginable.  Unfortunately, Zoe lost her father to an unexpected heart attack in 2010 and Zoe’s mother continues to strive for all they dreamt of for her. Zoe is nonverbal, non-ambulatory and she requires intensive medical care and therapies.  In her short 11 years, she has endured two surgeries for hip dysplasia followed by full body casts and comprehensive full spinal fusion.  She is still recovering from the spinal fusion and is still managing through all of the post-surgical challenges.  In addition to medical management of her symptomology, Zoe also participates in physical, speech and occupational therapies to help her achieve developmental milestones and to improve her quality of life.  This includes wearing AFOs to reduce the potential of painful contractures and manage her tone.  To minimize her risk of aspiration yet provide her with the joy of experiencing an array of pleasurable flavors, Zoe relishes gourmet pureed meals prepared by her mother. Currently, her growing body presents unique challenges in being able to transfer her to and from the bed or bath as well as difficulty lifting her up the stairs to her bedroom and handicapped accessible bathroom.  Zoe also has smaller medical equipment such as nebulizer and suctioning machine as well as larger equipment including a customized wheelchair, therapeutic gait trainer, shower chairs and a large therapy ball to help her meet her daily needs and would benefit from extra space near her bedroom to allow easy access to these devices when needed. ","quote":"We’d like to introduce Zoe. Zoe is a delightful preteen who brings smiles to the faces of all who encounter her.  This growing 11-year old is as happy as she is beautiful.  Zoe was only four weeks old when her parents were blindsided by the diagnosis of Cerebral Palsy.  Despite mourning the life whi","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zoe/hero/public","roomTypes":[],"photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zoe/hero/public","alt":"Zoe makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/jack/hero/public","alt":"Zoe makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/braeden/hero/public","alt":"Zoe makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-46/public","alt":"Zoe makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/abby/photo-48/public","alt":"Zoe makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zoe/photo-06/public","alt":"Zoe makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zoe/photo-07/public","alt":"Zoe makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zoe/photo-08/public","alt":"Zoe makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/paige/photo-26/public","alt":"Zoe makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zoe/photo-10/public","alt":"Zoe makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zoe/photo-11/public","alt":"Zoe makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zoe/photo-12/public","alt":"Zoe makeover photo"},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zoe/photo-13/public","alt":"Zoe makeover photo"}],"age":null,"diagnosis":null,"_migration":{"cfHeroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/ccf79ea1-73b1-4aae-74b7-d03f7c565800/full","source":"wix-migration","wixNumber":44},"roomCount":1}');
INSERT OR REPLACE INTO kids (slug, name, year, status, featured, child_count, room_count, data) VALUES ('zyah', 'Zyah', 2017, 'completed', 0, 1, 2, '{"name":"Zyah","slug":"zyah","age":7,"diagnosis":"Spinal Muscular Atrophy","roomTypes":["Accessible Bathroom","Dream Bedroom"],"year":2017,"status":"completed","bio":"With the spunk of Wonder Woman and the strength of Super Girl, she is a super hero to those who know her well and uses her miraculous powers to defy all odds. She is her mother''s beautiful princess, the apple of her father''s eye and has her siblings wrapped around her dainty magical finger. Zyah has a beautiful, inspired soul who does not let her disability slow her down a bit.\n\nFor most one-year olds, they are not only celebrating a full year of precious life, but also celebrating milestones like standing alone or taking their first steps. At this age, Zyah seemed to be just progressing slower; not ready to stand up alone and not ready to walk yet. That is when the fevers started. After three months of recurring fevers and no explanation, Zyah ended up with pneumonia and was admitted to the hospital.  Shortly thereafter, she experienced a collapsed lung. Devastatingly, Zyah was then diagnosed with SMA, type 2. SMA or Spinal Muscular Atrophy Type 2, is a genetic neuromuscular disease that affects the voluntary muscle movement and lung muscles. It is rare, but is also the most common genetic cause of infant death. Doctors presented her parents with the unimaginable fact that this adored little girl may only live to 7, maybe 8 years old.\n\nSix years later, Zyah is now 7 and still going strong.  Her daily medications and treatments consist of a CF Vest, cough assistance, suctioning, Bi-PAP and a g-tube for feedings.  She can eat some things by mouth for pleasure or taste, but because she does aspirate which puts her at great risk for aspiration pneumonia her primary nutrition is received via the gastronomy tube.  Zyah also uses a stander several times per week and has physical therapy twice per week.\n\nShe has been hospitalized on countless occasions, spending more holidays at the hospital than at home.  What is a simple cold to others lands Zyah in the ICU, sometimes even requiring a ventilator.  Have no fear, though, Zyah is strong willed and continues to fight like a champ.  She doesn''t let her \\u201cdisability\\u201d stop her from doing what she desires.  She has been a cheerleader, gone roller skating, takes singing lessons and is a Girl Scout.  She has also been in beauty pageants, winning a few trophies.","quote":"\"With the spunk of Wonder Woman and the strength of\\u00a0Super Girl, she is a super hero to those who know her\\u00a0well and uses her miraculous powers to defy all odds.\"","heroImage":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zyah/hero/public","photos":[{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zyah/photo-01/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zyah/photo-02/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zyah/photo-03/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zyah/photo-04/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zyah/photo-05/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zyah/photo-06/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zyah/photo-07/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zyah/photo-08/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zyah/photo-09/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zyah/photo-10/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zyah/photo-11/public","alt":""},{"url":"https://imagedelivery.net/ROYFuPmfN2vPS6mt5sCkZQ/kids/zyah/photo-12/public","alt":""},{"url":"https://ima