INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('11alive-2025', 'A Room Built with Dignity: How Sunshine on a Ranney Day Transforms Homes and Lives', '2025-03-01', 'local-tv', 1, '{"outlet":"11Alive (NBC Atlanta)","outletLogo":"11alive","category":"local-tv","title":"A Room Built with Dignity: How Sunshine on a Ranney Day Transforms Homes and Lives","date":"2025-03-01","url":"https://www.11alive.com/article/news/community/a-room-built-with-dignity-how-sunshine-on-a-ranney-day-transforms-homes-and-lives/85-fa2ba37c-55af-49a2-8aa8-6e3c0b99ebd1","excerpt":"An in-depth feature on how SOARD eases the daily challenges families face by creating wheelchair-accessible bathrooms, custom bedrooms, and therapy spaces at no cost.","featured":true,"order":2}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('11alive-coy-bowles', 'Zac Brown Band''s Coy Bowles Reads Children''s Book Benefiting SOARD', '2016-04-25', 'local-tv', 0, '{"outlet":"11Alive (NBC Atlanta)","outletLogo":"11alive","category":"local-tv","title":"Zac Brown Band''s Coy Bowles Reads Children''s Book Benefiting SOARD","date":"2016-04-25","url":"https://www.11alive.com/article/news/local/spoiled-kid-read-this-new-book-from-zac-brown-band-member/159494728","excerpt":"11Alive studio appearance by Coy Bowles reading his children''s book ''Will Powers,'' with a portion of proceeds going to Sunshine on a Ranney Day.","featured":false,"order":17}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('11alive-devon-gales-2019a', 'Former Football Player Paralyzed After Hit at UGA Game to See New Home Specially Built for His Family', '2019-07-18', 'local-tv', 0, '{"outlet":"11Alive (NBC Atlanta)","outletLogo":"11alive","category":"local-tv","title":"Former Football Player Paralyzed After Hit at UGA Game to See New Home Specially Built for His Family","date":"2019-07-18","url":"https://www.11alive.com/article/news/former-football-player-paralyzed-after-hit-to-see-new-home-specially-built-for-his-family/85-f5a1485a-350d-4190-8c66-aac590b0a6dc","excerpt":"11Alive previewed the 5,000-square-foot accessible home in Jefferson being completed for Devon Gales, the Southern University football player paralyzed during a 2015 game against UGA, with help from SOARD.","featured":false,"order":38}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('11alive-devon-gales-2019b', '''I''m Home.'' Football Player Paralyzed During UGA Game Reacts to the House Built for His Family', '2019-07-25', 'local-tv', 1, '{"outlet":"11Alive (NBC Atlanta)","outletLogo":"11alive","category":"local-tv","title":"''I''m Home.'' Football Player Paralyzed During UGA Game Reacts to the House Built for His Family","date":"2019-07-25","url":"https://www.11alive.com/article/sports/im-home-football-player-paralyzed-during-uga-game-reacts-to-the-house-built-for-his-family/85-98b539dc-5159-44a7-950d-1dd1f56ac43e","excerpt":"Devon Gales and his family experienced the emotional reveal of their new accessible home in Jefferson, Georgia, completed with a makeover from SOARD to support his rehabilitation near the Shepherd Spinal Center.","featured":true,"order":39}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('13wmaz-haleigh-cox', 'Group Surprises Haleigh Cox with New Therapy Room', '2017-01-01', 'local-tv', 0, '{"outlet":"13WMAZ (CBS Macon)","outletLogo":"13wmaz","category":"local-tv","title":"Group Surprises Haleigh Cox with New Therapy Room","date":"2017-01-01","url":"https://www.13wmaz.com/video/life/group-surprises-haleigh-cox-with-new-therapy-room/93-2631589","excerpt":"13WMAZ covered SOARD''s surprise therapy room reveal for Haleigh Cox, featuring ladybugs and Colorado mountain imagery. The nonprofit spent an entire day and $5,000 creating the custom space.","featured":false,"order":75}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('41nbc-2023', 'Nonprofit Transforms Warner Robins Home for Child with Special Needs', '2023-08-02', 'local-tv', 0, '{"outlet":"41NBC (WMGT)","outletLogo":"41nbc","category":"local-tv","title":"Nonprofit Transforms Warner Robins Home for Child with Special Needs","date":"2023-08-02","url":"https://www.41nbc.com/nonprofit-transforms-warner-robins-home-for-child-with-special-needs/","excerpt":"Coverage of SOARD''s dream bedroom and wheelchair-accessible bathroom makeover for 4-year-old Ellie Graff, nominated by Coy Bowles of the Zac Brown Band.","featured":false,"order":4}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('accessible-living-2024', 'Universal Design Projects Earn Top Honors in 2024 NARI CotY Awards', '2024-04-12', 'print', 0, '{"outlet":"Accessible Living","outletLogo":"accessible-living","category":"print","title":"Universal Design Projects Earn Top Honors in 2024 NARI CotY Awards","date":"2024-04-12","url":"https://buildaccessible.com/2024/04/12/universal-design-projects-earn-top-honors-in-2024-nari-coty-awards/","excerpt":"Disability and accessibility industry site Accessible Living covered SOARD''s 2024 National CotY Award for Universal Design-Bathroom, recognizing their expertise in creating wheelchair-accessible spaces for children.","featured":false,"order":65}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('ajc-2020', 'Sunshine on a Ranney Day Expands', '2020-12-19', 'print', 0, '{"outlet":"Atlanta Journal-Constitution","outletLogo":"ajc","category":"print","title":"Sunshine on a Ranney Day Expands","date":"2020-12-19","url":"https://www.ajc.com/neighborhoods/sunshine-on-a-ranney-day-expands/57VDV5R7T5CCLOPWRVNR4WT6JE/","excerpt":"The AJC covered the launch of Sunny & Ranney, the nonprofit''s new furniture and home décor store in Roswell, which sells designer items with all proceeds funding home makeovers for children with special needs.","featured":false,"order":36}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('ajc-2022', 'Charity Brings Sunshine into Lives of Special-Needs Children', '2022-12-06', 'print', 0, '{"outlet":"Atlanta Journal-Constitution","outletLogo":"ajc","category":"print","title":"Charity Brings Sunshine into Lives of Special-Needs Children","date":"2022-12-06","url":"https://www.ajc.com/inspire/charity-brings-sunshine-into-lives-of-special-needs-children/UR3TTNTZ5NF23IKI5JXKY2TJXU/","excerpt":"AJC Inspire section feature on SOARD''s growth, including details on their six paid employees, the Sunny & Ranney funding model, and family reactions to the Gabby Shropshire makeover.","featured":false,"order":26}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('ajc-2024', 'Sunshine on a Ranney Day Helps Metro Atlanta Kids with Disabilities', '2024-01-06', 'print', 1, '{"outlet":"Atlanta Journal-Constitution","outletLogo":"ajc","category":"print","title":"Sunshine on a Ranney Day Helps Metro Atlanta Kids with Disabilities","date":"2024-01-06","url":"https://www.ajc.com/neighborhoods/sunshine-on-a-ranney-day-helps-metro-atlanta-kids-with-disabilities/BFLOYYT5I5DXHM5CNBE77GNVTM/","excerpt":"The AJC profiled SOARD''s growth, including their $40,000 Gas South grant and mission to expand their footprint across a larger geography.","featured":true,"order":6}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('ajc-credit-union', 'Sunshine on a Ranney Day Receives $10,000 from Credit Union', '2023-06-01', 'print', 0, '{"outlet":"Atlanta Journal-Constitution","outletLogo":"ajc","category":"print","title":"Sunshine on a Ranney Day Receives $10,000 from Credit Union","date":"2023-06-01","url":"https://www.ajc.com/neighborhoods/north-fulton/sunshine-on-a-ranney-day-receives-10000-from-credit-union/TFNC6KCMBRAM5OIIS5CICW3SEM/","excerpt":"The AJC''s North Fulton section covered Delta Community Credit Union''s $10,000 donation to SOARD to support home makeover projects for children with special needs.","featured":false,"order":73}');
