INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('wsb-tv-hawks-kalen-2016', 'Hawks, Local Charity Surprise Teen in Wheelchair with New Room', '2016-11-07', 'local-tv', 1, '{"outlet":"WSB-TV (ABC Atlanta)","outletLogo":"wsb-tv","category":"local-tv","title":"Hawks, Local Charity Surprise Teen in Wheelchair with New Room","date":"2016-11-07","url":"https://www.wsbtv.com/news/local/hawks-local-charity-surprise-teen-in-wheelchair-with-new-room/464818751/","excerpt":"WSB-TV covered SOARD''s reveal for Kalen Reese, 16, paralyzed in a 2008 car wreck. Atlanta Hawks legends Dominique Wilkins, Tim Hardaway Jr., Kris Humphries, and Malcolm Delaney surprised him with a Hawks-themed accessible bedroom and bathroom.","featured":true,"order":48}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('wsb-tv-hudson-2016', 'Group Surprises Local Boy with Rare Disease with In-Home Therapy Room', '2016-01-01', 'local-tv', 0, '{"outlet":"WSB-TV (ABC Atlanta)","outletLogo":"wsb-tv","category":"local-tv","title":"Group Surprises Local Boy with Rare Disease with In-Home Therapy Room","date":"2016-01-01","url":"https://www.wsbtv.com/news/local/group-surprises-local-boy-rare-disease-home-therap/152649251/","excerpt":"WSB-TV featured SOARD''s reveal for Hudson, age 6, of Ball Ground, GA, who has Tuberous Sclerosis Complex. The team built a horse-themed therapy gym with a swing and saddle for in-home therapy sessions.","featured":false,"order":49}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('wsb-tv-monica-2016', '6-Year-Old Girl Paralyzed in Crash Gets Special Room Makeover', '2016-06-01', 'local-tv', 0, '{"outlet":"WSB-TV (ABC Atlanta)","outletLogo":"wsb-tv","category":"local-tv","title":"6-Year-Old Girl Paralyzed in Crash Gets Special Room Makeover","date":"2016-06-01","url":"https://www.wsbtv.com/news/local/cherokee-county/6-year-old-girl-paralyzed-in-crash-gets-special-room-makeover/389409836/","excerpt":"WSB-TV covered SOARD''s room makeover for Monica Lunn of Canton, GA, a 6-year-old paralyzed from the neck down in a car crash. American Signature Furniture donated furnishings for the accessible bedroom.","featured":false,"order":50}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('wsb-tv-pandemic-2020', 'Sunshine on a Ranney Day Able to Restart Home Renovations Amid Pandemic', '2020-06-01', 'local-tv', 0, '{"outlet":"WSB-TV (ABC Atlanta)","outletLogo":"wsb-tv","category":"local-tv","title":"Sunshine on a Ranney Day Able to Restart Home Renovations Amid Pandemic","date":"2020-06-01","url":"https://www.wsbtv.com/community/people-2-people/sunshine-ranney-day-able-restart-home-renovations-amid-pandemic/Q3AQDUZTPHQDDMLKLAZPICUOFI/","excerpt":"WSB-TV''s People2People community segment covered SOARD''s return to operations after the COVID-19 shutdown, detailing how the nonprofit adapted to safely resume home renovations for children with special needs.","featured":false,"order":53}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('wsb-tv-sims-2015', 'Family of Children with Special Needs Gets Home Makeover', '2015-01-01', 'local-tv', 0, '{"outlet":"WSB-TV (ABC Atlanta)","outletLogo":"wsb-tv","category":"local-tv","title":"Family of Children with Special Needs Gets Home Makeover","date":"2015-01-01","url":"https://www.wsbtv.com/news/local/local-mothers-home-renovated-providing-more-space-/33468988","excerpt":"WSB-TV covered SOARD''s makeover for Estella Sims of Decatur, GA, whose home was renovated to better accommodate her adopted children with special needs.","featured":false,"order":51}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('wsb-tv-superhero-room', 'Sunshine on a Ranney Day Gives a Young Boy a Room Full of His Favorite Super Heroes', '2017-01-01', 'local-tv', 0, '{"outlet":"WSB-TV (ABC Atlanta)","outletLogo":"wsb-tv","category":"local-tv","title":"Sunshine on a Ranney Day Gives a Young Boy a Room Full of His Favorite Super Heroes","date":"2017-01-01","url":"https://www.wsbtv.com/community/people-2-people/sunshine-ranney-day-gives-young-boy-room-full-his-favorite-super-heroes/04d31638-1383-400b-8e4a-f550437ad84b/","excerpt":"WSB-TV''s People2People community segment featured SOARD''s superhero-themed dream bedroom reveal for a young boy with special needs.","featured":false,"order":56}');
INSERT OR REPLACE INTO press (slug, title, date, category, featured, data) VALUES ('wsb-tv-tripp-tribute-2018', 'Friends Reflect on the Life and Impact of Tripp Halstead', '2018-03-15', 'local-tv', 0, '{"outlet":"WSB-TV (ABC Atlanta)","outletLogo":"wsb-tv","category":"local-tv","title":"Friends Reflect on the Life and Impact of Tripp Halstead","date":"2018-03-15","url":"https://www.wsbtv.com/news/local/friends-reflect-on-the-life-and-impact-of-tripp-halstead/717625827/","excerpt":"Following Tripp Halstead''s passing at age 7, WSB-TV featured Holly Ranney reflecting on SOARD''s landmark 2013 home makeover for the Halstead family, which was live-streamed to 1.6 million viewers.","featured":false,"order":54}');
