INSERT OR REPLACE INTO community (slug, name, order_num, data) VALUES ('camp-twin-lakes', 'Camp Twin Lakes', 1, '{"name":"Camp Twin Lakes","slug":"camp-twin-lakes","impact":"10,000","impactLabel":"children impacted yearly","year":"2018","description":"Camp Twin Lakes provides life-changing camp experiences for children with serious illnesses, disabilities, and other challenges across Georgia. SOARD partnered to renovate camp facilities, creating sensory-friendly spaces and accessible areas where thousands of children can play, grow, and experience the magic of camp — many for the very first time.","color":"#2E7D32","imageId":"kids/camp-twin-lakes/hero","imageAlt":"Camp Twin Lakes facility renovated by SOARD","order":1}');
INSERT OR REPLACE INTO community (slug, name, order_num, data) VALUES ('childrens-development-academy', 'Children''s Development Academy', 6, '{"name":"Children''s Development Academy","slug":"childrens-development-academy","impact":"100+","impactLabel":"children enrolled","year":"2025","description":"Founded in 1967, the CDA in Roswell gives young children the best chance to read on grade level by third grade, graduate high school, and break the cycle of generational poverty. SOARD is part of the CDA''s Learn.Play.Serve campaign — creating a new toddler classroom and community room with architecture by Randall Paulson, design by Crosby Design Group, and construction by Trident Construction.","color":"#00838F","badge":"In Progress","imageId":"","imageAlt":"Children''s Development Academy building before renovation","order":6}');
INSERT OR REPLACE INTO community (slug, name, order_num, data) VALUES ('childrens-healthcare-of-atlanta', 'Children''s Healthcare of Atlanta', 3, '{"name":"Children''s Healthcare of Atlanta","slug":"childrens-healthcare-of-atlanta","impact":"2,500","impactLabel":"children impacted yearly","year":"2016","description":"SOARD renovated parent sleep rooms at Children''s Healthcare of Atlanta, giving families a comfortable retreat during their child''s hospital stay. This project was featured on NBC''s Today Show, shining a national spotlight on the power of thoughtful design in healthcare settings.","color":"#6A1B9A","imageId":"","imageAlt":"","order":3}');
INSERT OR REPLACE INTO community (slug, name, order_num, data) VALUES ('murphy-harpst', 'Murphy-Harpst Children''s Center', 5, '{"name":"Murphy-Harpst Children''s Center","slug":"murphy-harpst","impact":"101","impactLabel":"children served on campus","year":"2015","description":"Murphy-Harpst Children''s Center in Cedartown, Georgia provides residential treatment and foster care for some of the state''s most vulnerable children — youth who have experienced severe abuse, neglect, and trauma. SOARD renovated living spaces on their 160-acre campus, creating environments where children in state custody can feel safe, supported, and at home during their healing journey.","color":"#E65100","imageId":"kids/murphy-harpst/hero","imageAlt":"Murphy-Harpst Children''s Center campus renovation","order":5}');
INSERT OR REPLACE INTO community (slug, name, order_num, data) VALUES ('summit-counseling-center', 'The Summit Counseling Center', 2, '{"name":"The Summit Counseling Center","slug":"summit-counseling-center","impact":"4,800","impactLabel":"children impacted yearly","year":"2016","description":"The Summit Counseling Center provides professional counseling services to children and families across North Atlanta. SOARD renovated their child therapy spaces, transforming clinical environments into warm, welcoming rooms designed to help kids feel safe and supported during their most vulnerable moments.","color":"#1565C0","imageId":"kids/summit-counseling-center/hero","imageAlt":"The Summit Counseling Center renovation by SOARD","order":2}');
INSERT OR REPLACE INTO community (slug, name, order_num, data) VALUES ('the-drake-house', 'The Drake House', 4, '{"name":"The Drake House","slug":"the-drake-house","impact":"250","impactLabel":"families served","year":"2022","description":"The Drake House provides housing and education for single mothers and their children experiencing homelessness in North Metro Atlanta. SOARD renovated their main headquarters — redesigning classrooms, activity spaces, a community kitchen, and teen gathering rooms to create an environment where families can recover, learn, and rebuild with dignity.","color":"#C62828","imageId":"","imageAlt":"The Drake House headquarters renovated by SOARD","order":4}');
INSERT OR REPLACE INTO articles (slug, title, featured, order_num, data) VALUES ('accessible-home-design', 'Guide to Accessible Home Design for Children with Disabilities', 1, 1, '{"title":"Guide to Accessible Home Design for Children with Disabilities","slug":"accessible-home-design","description":"A comprehensive guide to making your home accessible for a child with physical disabilities — covering bathrooms, bedrooms, doorways, ramps, and funding resources.","tag":"Accessibility","datePublished":"2025-01-15","dateModified":"2026-03-01","heroImage":null,"heroLead":"A practical guide for families navigating home modifications — from wheelchair-accessible bathrooms to sensory-safe bedrooms — based on our experience building over 106 rooms for children with special needs.","aboutTopics":["accessible home design","wheelchair accessibility","home modifications for children with disabilities"],"body":"<h2>Why Accessible Home Design Matters</h2>\n<p>For families raising a child with physical disabilities, the home is more than a living space — it''s a clinical environment, a therapy center, and the place where independence is built or limited every single day. A doorway that''s two inches too narrow means a child can''t move freely between rooms. A standard bathtub means a parent must lift a growing child in and out multiple times a week, risking injury to both.</p>\n<p>At Sunshine on a Ranney Day, we''ve completed over 106 room renovations for children with special needs since 2012, and the pattern is consistent: thoughtful modifications to a home''s physical layout produce measurable improvements in a child''s independence, safety, and emotional wellbeing. This guide shares what we''ve learned.</p>\n\n<h2>The Accessible Bathroom: Where to Start</h2>\n<p>Of all the rooms in a home, the bathroom creates the most significant daily barriers for children with mobility challenges. It''s also where modifications have the most immediate impact. Here''s what an accessible bathroom renovation typically includes:</p>\n<p><strong>Roll-in shower with zero threshold.</strong> Eliminating the step into a shower is the single most impactful change. A curbless shower with a sloped floor allows wheelchair access and eliminates the need for lifting. Non-slip tile is essential — we use textured porcelain with a coefficient of friction (COF) of 0.60 or higher.</p>\n<p><strong>Grab bars at multiple heights.</strong> Install grab bars at the child''s current height, but also plan for growth. We typically install bars at 24 inches and 33 inches from the floor, with reinforced blocking behind the drywall so bars can be repositioned later without a major renovation.</p>\n<p><strong>Adjustable-height showerhead.</strong> A handheld showerhead on a vertical slide bar gives both the child and caregiver flexibility. Mount the slide bar so the showerhead can reach seated height (about 48 inches) as well as standing height.</p>\n<p><strong>Wider doorway (minimum 36 inches clear).</strong> Standard bathroom doors are 24–28 inches wide, which won''t accommodate a wheelchair. We widen to 36 inches minimum, and often install pocket doors or barn-style sliding doors to eliminate the swing space a traditional door requires.</p>\n<p><strong>Raised or wall-mounted toilet.</strong> A wall-mounted toilet allows the height to be set based on the child''s wheelchair seat height, making transfers much easier. If a wall-mounted unit isn''t feasible, a comfort-height toilet (17–19 inches) with a raised seat can work.</p>\n<p><strong>Roll-under vanity.</strong> A wall-mounted sink with an open cabinet below gives wheelchair access to the basin, mirror, and storage. Insulate hot water pipes under the sink to prevent burns.</p>\n\n<h2>Bedroom Modifications for Physical Accessibility</h2>\n<p>A child''s bedroom should be a place of autonomy and joy. When mobility is limited, the design of the space determines whether a child can reach their own belongings, get in and out of bed independently, and feel a sense of ownership over their room.</p>\n<p><strong>Floor space and turning radius.</strong> A wheelchair requires a 60-inch diameter turning circle. In a bedroom, this means careful furniture placement and often removing unnecessary pieces. We design room layouts in CAD before building to ensure clear pathways from the door to the bed, closet, and desk.</p>\n<p><strong>Bed height matching wheelchair seat.</strong> When the bed surface is at the same height as the wheelchair seat (typically 18–20 inches), a child can perform lateral transfers independently or with minimal assistance. Adjustable-height bed frames are ideal because they can grow with the child.</p>\n<p><strong>Accessible closet systems.</strong> Standard closet rods at 66 inches are unreachable from a wheelchair. We install double-hung rods with the lower rod at 40–44 inches, or pull-down closet rods that lower clothing to accessible heights. Drawers and shelving at 15–48 inches from the floor keep clothing and belongings within reach.</p>\n<p><strong>Smart home controls.</strong> Voice-activated lighting, motorized window shades, and smart plugs let children control their environment without reaching switches. A child who can say \"turn off the lights\" before sleep gains a small but meaningful measure of independence.</p>\n<p><strong>Flooring.</strong> Hard flooring (luxury vinyl plank or engineered hardwood) is essential for wheelchair maneuverability. Thick carpet creates resistance that makes self-propulsion exhausting. If area rugs are desired for comfort, use thin, flat-weave rugs secured with non-slip pads.</p>\n\n<h2>Entryways, Hallways, and Ramps</h2>\n<p>Getting into the home and moving between rooms are foundational to every other modification. Without accessible circulation paths, even a perfectly designed bathroom is useless if a child can''t reach it.</p>\n<p><strong>Exterior ramps.</strong> The ADA guideline of a 1:12 slope ratio (one inch of rise for every 12 inches of run) is the standard, but for children who self-propel their wheelchairs, a 1:16 or 1:20 slope is much more manageable. Ramps should include handrails on both sides at 20–28 inches for children. Materials matter — aluminum ramps are durable and low-maintenance, while wood ramps require annual sealing in the Georgia climate.</p>\n<p><strong>Door widening.</strong> The minimum clear width for wheelchair passage is 32 inches, but 36 inches is recommended and is what we use in all SOARD projects. For families on a budget, offset hinges can add 2 inches of clear width to an existing doorway without reframing.</p>\n<p><strong>Threshold elimination.</strong> Even a half-inch threshold can be a barrier for small wheelchairs or walkers. Transition strips should be beveled, and where possible, thresholds should be removed entirely.</p>\n<p><strong>Hallway width.</strong> A wheelchair needs 36 inches of clear width in a straight hallway, but 42–48 inches is better for daily use. Where two wheelchairs or a wheelchair and a walking person need to pass, 60 inches is ideal.</p>\n\n<h2>Funding Home Modifications</h2>\n<p>The cost of making a home accessible can be significant, but multiple funding sources exist for families who need help:</p>\n<p><strong>Nonprofit organizations.</strong> Organizations like Sunshine on a Ranney Day provide home modifications at no cost to qualifying families in the greater Atlanta area. <a href=\"/apply/\">Families can apply online</a>. Other national organizations include Habitat for Humanity (which has accessibility renovation programs), the Gary Sinise Foundation''s RISE program, and Rebuilding Together.</p>\n<p><strong>Medicaid HCBS waivers.</strong> Most states offer Home and Community-Based Services waivers through Medicaid that can fund home modifications. These waivers are designed to keep individuals with disabilities in their homes rather than institutional settings. Eligibility and covered modifications vary by state — in Georgia, the New Options Waiver (NOW) and Comprehensive Supports Waiver Program (COMP) can cover environmental modifications.</p>\n<p><strong>State and local programs.</strong> Georgia''s Department of Community Affairs offers housing rehabilitation programs, and many counties have Community Development Block Grant (CDBG) funds that can be used for accessibility modifications.</p>\n<p><strong>VA grants.</strong> For families of veterans, the VA''s Specially Adapted Housing (SAH) and Special Housing Adaptation (SHA) grants provide substantial funding for accessible home construction or modification.</p>\n<p><strong>Tax deductions.</strong> Medical-related home improvements that don''t increase property value may be deductible as medical expenses on federal taxes. Consult a tax professional for specifics.</p>\n\n<h2>Planning Your Project</h2>\n<p>Before beginning any modification, work with your child''s occupational therapist to create a functional assessment of the home. An OT can identify which barriers create the greatest daily limitations and help prioritize modifications based on your child''s specific needs and developmental trajectory.</p>\n<p>Consider your child''s future needs, not just current ones. A child who uses a walker today may need a wheelchair in five years. Building in flexibility now — wider doorways, reinforced walls for future grab bars, conduit for future smart-home wiring — saves significant cost and disruption later.</p>\n<p>If you''re in the greater Atlanta area and have a child with special needs, <a href=\"/apply/\">learn about applying for a SOARD room makeover</a>. We partner with professional designers and contractors to create spaces that are both beautiful and fully accessible — at no cost to your family.</p>","faqs":[{"question":"How much does it cost to make a home wheelchair accessible for a child?","answer":"Costs vary widely depending on the scope of modifications. A basic bathroom renovation with grab bars and a roll-in shower might cost $8,000–$15,000. A comprehensive home modification including widened doorways, ramps, and an accessible bathroom can range from $20,000–$50,000 or more. Organizations like Sunshine on a Ranney Day provide these modifications at no cost to qualifying families."},{"question":"What is the most important home modification for a child in a wheelchair?","answer":"An accessible bathroom is typically the highest-priority modification. The ability to bathe, use the toilet, and perform hygiene tasks independently (or with less caregiver strain) has the greatest impact on daily quality of life for both the child and their family."},{"question":"Can I get financial help to modify my home for my disabled child?","answer":"Yes. Several programs offer financial assistance for home modifications, including Medicaid Home and Community-Based Services (HCBS) waivers, state vocational rehabilitation agencies, VA Specially Adapted Housing grants (for veterans'' families), and nonprofits like Sunshine on a Ranney Day that provide modifications at no cost. Contact your state''s disability services office for local programs."},{"question":"What are the ADA requirements for residential homes?","answer":"The Americans with Disabilities Act (ADA) primarily applies to commercial and public buildings, not private residences. However, the Fair Housing Act requires that multifamily housing built after 1991 include certain accessibility features. For single-family homes, modifications are voluntary but can follow ADA guidelines as a best practice — including 36-inch minimum doorway widths, 60-inch turning radius in bathrooms, and lever-style door handles."}],"ctaHeading":"Need an accessible home for your child?","ctaText":"Sunshine on a Ranney Day builds accessible bathrooms, dream bedrooms, and therapy rooms for children with special needs — at no cost to families in the greater Atlanta area.","ctaPrimaryLink":"/apply/","ctaPrimaryLabel":"Apply for a Makeover","ctaSecondaryLink":"/donate/","ctaSecondaryLabel":"Support Our Mission","featured":true,"order":1}');
INSERT OR REPLACE INTO articles (slug, title, featured, order_num, data) VALUES ('sensory-friendly-bedroom', 'How to Create a Sensory-Friendly Bedroom for Your Child', 1, 2, '{"title":"How to Create a Sensory-Friendly Bedroom for Your Child","slug":"sensory-friendly-bedroom","description":"A practical guide to designing a bedroom that supports children with autism, sensory processing disorder, and other sensory sensitivities — covering lighting, color, sound, texture, and safety.","tag":"Sensory","datePublished":"2025-02-01","dateModified":"2026-03-01","heroImage":null,"heroLead":"A room-by-room guide to designing spaces that calm, support, and empower children with autism, sensory processing disorder, and other sensory sensitivities.","aboutTopics":["sensory-friendly design","autism","sensory processing disorder"],"body":"<h2>Understanding Sensory Needs in the Bedroom</h2>\n        <p>For children with sensory processing differences — including those with autism spectrum disorder, sensory processing disorder (SPD), ADHD, and many other conditions — the bedroom is much more than a place to sleep. It''s the space where they decompress after an overwhelming school day, the place they retreat when the world feels too loud or too bright, and ideally, a regulated environment that supports their nervous system.</p>\n        <p>Sensory processing works on a spectrum between hyper-sensitivity (over-responsive to stimuli) and hypo-sensitivity (under-responsive, often seeking intense input). Many children experience both — they might be hypersensitive to sound but hypo-sensitive to proprioceptive input (deep pressure). This is why a one-size-fits-all approach doesn''t work. The best sensory-friendly bedroom is designed around your specific child''s sensory profile.</p>\n        <p>At Sunshine on a Ranney Day, we''ve designed therapy rooms and sensory-friendly bedrooms for children across a wide range of diagnoses since 2012. Here''s what we''ve learned from over 45 therapy room builds.</p>\n\n        <h2>Lighting: The Most Underestimated Factor</h2>\n        <p>Lighting has more impact on a child''s sensory state than almost any other element in a room, yet it''s often the last thing parents think about. Fluorescent lights — common in overhead fixtures — flicker at a frequency that many neurotypical people don''t perceive but that can be intensely distressing for children with sensory sensitivities. The fix doesn''t have to be expensive.</p>\n        <p><strong>Dimmable warm LED lighting.</strong> Replace overhead fixtures with dimmable LEDs in the 2700K–3000K color temperature range (warm white). The ability to lower light levels throughout the evening supports the body''s natural melatonin production, which is often disrupted in children with autism. Smart bulbs that can be controlled by voice or a simple switch give the child agency over their own environment.</p>\n        <p><strong>Eliminate overhead-only lighting.</strong> A single bright overhead light creates harsh shadows and visual contrast. Instead, layer lighting: a gentle overhead fixture at low brightness, a table lamp for reading, and optional LED strip lights at baseboard level for nighttime navigation. Many children we work with benefit from a warm-toned night light that stays on throughout sleep.</p>\n        <p><strong>Blackout capability.</strong> For children who are light-sensitive, blackout curtains or roller shades are essential. Even small amounts of outside light — street lamps, car headlights, early morning sun — can disrupt sleep. We install blackout roller shades behind decorative curtains so the room can be fully darkened when needed and opened up during the day.</p>\n        <p><strong>Avoid blue-toned light after sunset.</strong> Blue-spectrum light suppresses melatonin and is particularly disruptive for children who already struggle with sleep regulation. After dinner, limit screen use and use warm-toned lighting exclusively. Some families install smart lighting that automatically shifts to warm tones in the evening.</p>\n\n        <h2>Sound: Creating an Acoustic Sanctuary</h2>\n        <p>Auditory sensitivity is one of the most common sensory challenges in children with autism and SPD. Sounds that are background noise to most people — a refrigerator humming, traffic outside, a sibling talking in the next room — can feel overwhelming and inescapable to a sound-sensitive child.</p>\n        <p><strong>Soft furnishings absorb sound.</strong> Hard surfaces reflect sound waves; soft surfaces absorb them. Upholstered furniture, thick curtains, carpet or rugs, acoustic panels behind decorative fabric, and even a well-stocked bookshelf all reduce the acoustic energy in a room. The goal is to make the bedroom noticeably quieter than the rest of the house.</p>\n        <p><strong>White noise or nature sounds.</strong> A consistent, predictable background sound can mask unpredictable noises that trigger anxiety. White noise machines, fan sounds, or nature sounds (rain, ocean waves) give the auditory system a steady baseline. Place the sound source between the child and the most common noise intrusions (a shared wall, a window facing a road).</p>\n        <p><strong>Sound insulation for shared walls.</strong> If budget allows, adding a layer of mass-loaded vinyl (MLV) behind drywall on shared walls significantly reduces sound transmission. A less expensive option is acoustic caulking around electrical outlets and door weatherstripping, which addresses the gaps where sound leaks through most easily.</p>\n        <p><strong>A noise-canceling headphone station.</strong> Designate a specific spot in the room — a hook, a shelf, a headphone stand — where noise-canceling headphones live. When the child knows exactly where to find them, the headphones become a reliable self-regulation tool rather than something they have to search for when already overwhelmed.</p>\n\n        <h2>Color and Visual Environment</h2>\n        <p>The visual environment of a bedroom encompasses far more than wall color. Pattern, contrast, clutter, and visual \"busyness\" all contribute to how calming or stimulating a space feels.</p>\n        <p><strong>Wall color.</strong> Muted tones in the blue-green family are consistently the most calming across research and our direct experience. Soft sage, dusty blue, warm gray, and pale lavender all work well. Flat or matte paint finishes eliminate glare that eggshell or satin finishes can produce. That said, some children are genuinely comforted by deeper, richer colors — a navy blue or forest green. Follow your child''s lead.</p>\n        <p><strong>Minimize visual clutter.</strong> This is one of the most impactful and least expensive changes a family can make. Open shelving filled with visible toys, books, and objects creates constant visual input that a sensory-sensitive brain must process. Closed storage — bins with lids, closet doors that close fully, drawers rather than shelves — reduces the visual load dramatically. The guideline we use: if you can see it, the brain is processing it.</p>\n        <p><strong>One focal wall, not four.</strong> If your child loves a specific theme (dinosaurs, space, ocean), consider putting the visual interest on one wall and keeping the other three walls neutral. This gives the child a point of engagement without surrounding them with stimulation from every direction.</p>\n        <p><strong>Avoid high-contrast patterns.</strong> Bold stripes, checkerboard patterns, and high-contrast geometric prints can create visual vibration that is distressing for some children. If patterns are desired, choose low-contrast, organic patterns (gentle watercolor textures, subtle tone-on-tone stripes).</p>\n\n        <h2>Texture and Tactile Comfort</h2>\n        <p>Tactile sensitivity profoundly affects how a child experiences their bedroom. Bedding, flooring, wall surfaces, and furniture materials all provide constant tactile input.</p>\n        <p><strong>Bedding choices.</strong> Many sensory-sensitive children are particular about fabric textures. Cotton jersey (T-shirt material) is a consistently well-tolerated choice for sheets. Avoid stiff, crispy percale sheets and scratchy tags. Weighted blankets (typically 10% of the child''s body weight) provide deep pressure input that helps many children with anxiety and sensory-seeking behaviors settle for sleep. Let your child touch fabric samples before purchasing.</p>\n        <p><strong>A compression or cozy corner.</strong> A designated space where a child can get deep pressure input is invaluable. This can be as simple as a large bean bag chair, a body-sock-style compression garment hung in a corner, a small pop-up tent filled with pillows, or a purpose-built reading nook with padded walls. The key is that the child can access it independently whenever they need it.</p>\n        <p><strong>Wall padding in regulation zones.</strong> For children who seek intense proprioceptive input — including those who may hit walls or bang their head during dysregulation — padded wall panels in a specific area of the room provide both safety and appropriate sensory input. These can be covered in attractive fabric to look intentional rather than clinical.</p>\n        <p><strong>Varied textures, thoughtfully placed.</strong> Rather than eliminating all texture variation (which can be under-stimulating for sensory seekers), offer a range of textures the child can choose to engage with: a fuzzy throw on the bed, a smooth wood desktop, a textured fidget wall panel. The important thing is that the child controls when and how they interact with these textures.</p>\n\n        <h2>Safety Considerations</h2>\n        <p>Children who experience sensory overload may engage in behaviors that require specific safety planning. The bedroom should be a place where a child can safely self-regulate without risk of injury.</p>\n        <p><strong>Secure furniture to walls.</strong> This is essential for children who climb, push, or pull on furniture during dysregulation. All bookshelves, dressers, and tall furniture should be anchored to wall studs with anti-tip brackets.</p>\n        <p><strong>Window safety.</strong> Window locks that prevent full opening, shatter-resistant film on glass, and cord-free window treatments are all important. Consider window guards for upper floors.</p>\n        <p><strong>Outlet covers and cord management.</strong> Use tamper-resistant outlets and run cords behind furniture or through cord covers so they aren''t accessible during moments of distress.</p>\n        <p><strong>Door alarms for elopement risk.</strong> For children who wander or elope, a simple door sensor that chimes when the bedroom door opens provides an alert system that doesn''t require locking the child in the room (which is never recommended and may violate fire safety codes).</p>\n\n        <h2>Getting Started</h2>\n        <p>You don''t need to renovate the entire room at once. Start with the modification that addresses your child''s most significant sensory challenge. For most families, that''s either lighting (replacing overhead fixtures with dimmable warm LEDs) or visual decluttering (switching to closed storage). Both can be done in a weekend for under $200 and often produce noticeable improvements in sleep and regulation.</p>\n        <p>Work with your child''s occupational therapist to understand their specific sensory profile. A formal sensory processing evaluation provides a roadmap for which modifications will have the greatest impact.</p>\n        <p>If you''re in the greater Atlanta area, <a href=\"/apply/\">Sunshine on a Ranney Day accepts applications</a> from families of children with special needs for no-cost room makeovers, including sensory-friendly bedrooms and therapy rooms. We partner with professional designers who specialize in therapeutic environments.</p>","faqs":[{"question":"What colors are best for a sensory-friendly bedroom?","answer":"Muted, cool tones tend to be most calming — soft blues, sage greens, warm grays, and lavender. Avoid high-contrast patterns, neon colors, and bright red or orange, which can be overstimulating. However, every child is different. Some children with sensory processing differences are actually calmed by deeper, saturated colors. Observe what environments your child gravitates toward and feels most settled in."},{"question":"How much does it cost to create a sensory room at home?","answer":"A basic sensory corner can be created for $200–$500 using items like a pop-up tent, weighted blanket, noise-canceling headphones, and fidget tools. A more comprehensive sensory bedroom renovation — including specialized lighting, sound insulation, padded walls, and swing hardware — typically costs $5,000–$15,000. Organizations like Sunshine on a Ranney Day provide sensory-friendly room makeovers at no cost to qualifying families."},{"question":"Is a sensory room the same as a therapy room?","answer":"Not exactly. A sensory room is designed primarily for self-regulation — a space where a child can calm down, decompress, or safely seek sensory input. A therapy room is designed for structured therapeutic activities guided by an occupational therapist, physical therapist, or speech therapist. Many families benefit from a room that serves both purposes, with a calming zone and an active zone within the same space."},{"question":"What is the best flooring for a sensory-friendly bedroom?","answer":"Cork flooring is often ideal — it is warm, quiet underfoot, slightly cushioned for safety, and doesn''t off-gas like some synthetic materials. Low-pile carpet provides warmth and sound absorption but can be harder to clean. Avoid hard tile (cold, loud) and high-pile shag (can be overstimulating for tactile-sensitive children). Foam puzzle mats work well as a temporary solution in specific zones."}],"ctaHeading":"We build sensory-friendly rooms at no cost","ctaText":"Sunshine on a Ranney Day has built over 45 therapy rooms and sensory-friendly bedrooms for children with special needs. If your child could benefit from a room designed around their needs, we''d love to hear from you.","ctaPrimaryLink":"/apply/","ctaPrimaryLabel":"Apply for a Makeover","ctaSecondaryLink":"/kids/","ctaSecondaryLabel":"See Our Kids'' Stories","featured":true,"order":2}');
INSERT OR REPLACE INTO articles (slug, title, featured, order_num, data) VALUES ('therapy-room-design', 'In-Home Therapy Room Design: A Complete Guide for Families', 1, 3, '{"title":"In-Home Therapy Room Design: A Complete Guide for Families","slug":"therapy-room-design","description":"How to design and build an in-home therapy room for a child with special needs — equipment, layout, safety, and funding options from experts who''ve built 45+ therapy rooms.","tag":"Therapy","datePublished":"2025-03-01","dateModified":"2026-03-01","heroImage":null,"heroLead":"Everything you need to know about creating a dedicated therapy space at home — from equipment and layout to safety and funding — based on 45+ therapy rooms built by Sunshine on a Ranney Day.","aboutTopics":["pediatric therapy room design","occupational therapy","physical therapy"],"body":"<h2>Why an In-Home Therapy Room Matters</h2>\n        <p>Children with special needs often receive occupational therapy, physical therapy, or speech therapy at a clinic once or twice a week. But the reality of neurological and physical development is that progress happens through repetition — the daily, consistent practice of movements, exercises, and sensory experiences between clinical sessions.</p>\n        <p>An in-home therapy room closes the gap between weekly clinic visits and daily therapeutic needs. When the right equipment is available at home, families can turn five minutes of waiting time into five minutes of therapeutic activity. A child who does 15 minutes of vestibular input (swinging) every morning before school may be more regulated throughout the entire school day. A child who can practice standing-frame exercises while watching a favorite show logs far more repetitions than clinical visits alone provide.</p>\n        <p>Since 2012, Sunshine on a Ranney Day has built over 45 dedicated therapy rooms in family homes across the greater Atlanta area. The feedback from families and therapists is consistent: children with access to home therapy equipment progress faster, maintain gains better between clinical sessions, and develop greater independence in using therapeutic tools for self-regulation.</p>\n\n        <h2>Working with Your Child''s Therapist</h2>\n        <p>Before purchasing any equipment or planning any layout, have a conversation with your child''s occupational therapist (OT), physical therapist (PT), or speech-language pathologist (SLP). They can tell you which specific activities and equipment will be most beneficial based on your child''s current goals and treatment plan.</p>\n        <p>Ask your therapist these questions: What are the top 3 therapeutic activities my child should be doing daily at home? What equipment do these activities require? What are the minimum space and safety requirements for that equipment? Are there activities we should avoid at home without supervision? Can you provide a written home exercise program (HEP) that we can build the room around?</p>\n        <p>This conversation ensures that every dollar you spend and every square foot you dedicate goes toward equipment and layout that directly supports your child''s therapeutic goals — not general-purpose gym equipment that looks impressive but doesn''t address their specific needs.</p>\n\n        <h2>Essential Equipment by Therapy Type</h2>\n\n        <h3>Occupational Therapy (OT) — Sensory Integration and Fine Motor</h3>\n        <p>Occupational therapy for children often focuses on sensory integration (helping the brain process sensory input effectively) and fine motor skills (hand strength, coordination, handwriting). A home OT space typically includes:</p>\n        <p><strong>Platform swing.</strong> The most versatile piece of equipment in a therapy room. A platform swing (also called a bolster swing or net swing) provides vestibular input in all planes of movement — forward/back, side to side, and rotational. It strengthens core muscles, improves balance, and has a profoundly calming effect on many children''s nervous systems. Requires a ceiling mount rated for dynamic loads and at least 6 feet of swing arc clearance in all directions.</p>\n        <p><strong>Crash pad or foam pit.</strong> A thick foam mat (typically 8–12 inches of dense foam covered in vinyl) that children can jump, dive, or roll onto. Provides intense proprioceptive input (deep pressure through joints) which helps regulate the nervous system. Place it at the base of a climbing wall or beside a swing landing zone.</p>\n        <p><strong>Climbing wall.</strong> Indoor climbing walls build upper body strength, bilateral coordination, motor planning, and confidence. Commercial therapy climbing walls come with T-nut systems for adjustable hand holds. For home use, a 4×8-foot section of climbing wall is sufficient for most children. Install over a crash pad for safety.</p>\n        <p><strong>Therapy ball and peanut ball.</strong> These large inflatable balls are used for core strengthening, balance training, and vestibular input. A peanut ball (shaped like a peanut shell) is more stable and better for children who need more support. Size the ball so the child''s hips and knees are at 90 degrees when seated.</p>\n        <p><strong>Fine motor station.</strong> A small table at the right height with storage for therapy putty, hand-strengthening tools, lacing cards, bead activities, and other fine motor materials. Good lighting is important here — position the table near a window or under a task light.</p>\n\n        <h3>Physical Therapy (PT) — Gross Motor and Mobility</h3>\n        <p>Physical therapy focuses on gross motor skills, strength, mobility, balance, and gait. A home PT space requires more floor area and may include larger equipment:</p>\n        <p><strong>Standing frame area.</strong> If your child uses a stander or standing frame, dedicate a specific area with a level, firm floor surface (not carpet) and enough room to position the stander with access to a table or screen for entertainment during standing time. Consistent daily standing time is critical for bone density, hip development, and pressure relief.</p>\n        <p><strong>Parallel bars or grab bar rail.</strong> For children working on walking, a section of parallel bars or a wall-mounted grab bar rail (about 6–8 feet long) provides support for gait training practice at home. Mount at your child''s specific hand height as recommended by their PT.</p>\n        <p><strong>Therapy mat.</strong> A firm, padded mat (2–4 inches thick, 4×6 feet or larger) for floor exercises, stretching, and transfers. This is different from a soft crash pad — therapy mats need to be firm enough to provide stable support during exercises but padded enough to be comfortable.</p>\n        <p><strong>Resistance equipment.</strong> TheraBands (resistance bands in graded levels), ankle weights, and hand weights appropriate for your child''s age and ability. Your PT can specify the exact resistance levels needed.</p>\n\n        <h3>Speech-Language Therapy (SLP)</h3>\n        <p>Speech therapy requires less physical equipment but benefits from a quiet, distraction-free space:</p>\n        <p><strong>Quiet corner or booth.</strong> Sound-absorbing panels, a small table with two chairs, good lighting, and a mirror (for visual feedback during articulation practice). The space should be away from household noise sources.</p>\n        <p><strong>AAC device station.</strong> If your child uses an augmentative and alternative communication (AAC) device, provide a dedicated charging station, a mounting system if needed, and a seating position where the device is always within reach.</p>\n\n        <h2>Room Layout and Safety</h2>\n        <p><strong>Zones, not chaos.</strong> The most effective therapy rooms are organized into distinct zones: an active zone (swings, climbing, crash pad), a calm zone (beanbag, weighted blankets, dim lighting), and a tabletop zone (fine motor activities, communication practice). Clear zones help the child and their therapist transition between activities and energy levels.</p>\n        <p><strong>Ceiling reinforcement.</strong> Swings, trapeze bars, and climbing ropes all require ceiling mounts anchored into structural framing. In a typical residential home, ceiling joists are 2×6 or 2×8 lumber at 16-inch centers. A single joist may not be sufficient for a dynamic load (a child swinging creates forces several times their body weight). We typically sister a second joist to the existing one, or install a beam across multiple joists with an engineer-specified mounting plate.</p>\n        <p><strong>Floor protection.</strong> Rubber interlocking floor tiles (½ to ¾ inch thick) protect flooring, reduce noise, provide cushioning for falls, and are easy to clean. EVA foam tiles work for lighter use but break down faster. For therapy rooms with heavy equipment, vulcanized rubber tiles rated for gym use are the best investment.</p>\n        <p><strong>Wall padding.</strong> Padded wall panels in the active zone prevent injuries during vigorous play. Cover at least the walls within the swing''s arc and any walls adjacent to the climbing area. Panels should be a minimum of 2 inches thick with a high-density foam core.</p>\n        <p><strong>Clear sight lines.</strong> A caregiver should be able to see the entire room from the doorway. Avoid placing tall equipment where it blocks visibility. If the room has a door, consider replacing it with a Dutch door (where the bottom half can close while the top stays open) so a caregiver can supervise while keeping smaller siblings out.</p>\n\n        <h2>Choosing the Right Room</h2>\n        <p>The ideal therapy room is a dedicated space — a spare bedroom, a finished basement section, or a converted garage. But many families don''t have a spare room. Here are alternatives that work:</p>\n        <p><strong>Shared bedroom with a therapy zone.</strong> When space is tight, carving out a corner of the child''s bedroom for therapy equipment is viable. Use visual cues (a different color rug, a curtain divider) to distinguish the therapy space from the sleeping space. A ceiling-mounted swing can be installed with a removable hook so it can be taken down when not in use.</p>\n        <p><strong>Garage conversion.</strong> An attached garage can be an excellent therapy room — the concrete floor handles heavy equipment, the ceiling is often high enough for swings, and the space is separate from the main living area (reducing noise concerns). Insulation and climate control are the main investments required.</p>\n        <p><strong>Outdoor covered space.</strong> In the Atlanta area''s mild climate, a covered patio or screened porch can serve as a therapy space for 8–9 months of the year. Equipment will need to be weather-resistant or brought inside when not in use.</p>\n\n        <h2>Budgeting and Funding</h2>\n        <p>A basic home therapy setup with a crash pad, therapy ball, and resistance equipment can cost as little as $300–$500. A comprehensive therapy room with a ceiling-mounted swing, climbing wall, floor protection, and wall padding typically ranges from $5,000–$15,000 depending on the space and equipment selected.</p>\n        <p>Several funding sources can help: Medicaid HCBS waivers may cover home modifications that support therapy goals. Private insurance sometimes covers specific equipment with a letter of medical necessity from your child''s physician or therapist. Nonprofit organizations, including Sunshine on a Ranney Day, provide therapy room construction at no cost for qualifying families. Some states also have assistive technology lending programs that let families try equipment before purchasing.</p>\n        <p>If your family is in the greater Atlanta area, <a href=\"/apply/\">we encourage you to apply for a SOARD therapy room makeover</a>. We work directly with your child''s therapy team to design a space that supports their specific treatment goals, and all design, materials, and labor are donated.</p>","faqs":[{"question":"How much space do I need for a home therapy room?","answer":"A functional therapy room can work in as little as 100 square feet (roughly 10×10 feet), which is about the size of a small bedroom. For rooms that include a platform swing, plan for at least 120–150 square feet with 8-foot ceiling clearance. If space is limited, a therapy corner within a bedroom or living area can still provide meaningful benefits — even a 6×6-foot area with a crash pad, a small bolster, and a few key tools can support daily therapy practice."},{"question":"Can I install a therapy swing in my home?","answer":"Yes, but proper installation is critical for safety. Therapy swings require a ceiling mount rated for dynamic loads — typically a heavy-duty eye bolt or swing plate anchored into a ceiling joist or beam capable of supporting at least 4x the child''s weight (to account for swinging forces). A structural engineer or experienced contractor should assess your ceiling framing before installation. Never mount a therapy swing into drywall alone."},{"question":"What equipment should I buy first for a home therapy room?","answer":"Start with your child''s therapist''s recommendations, as they know which activities matter most for your child''s goals. For most children in occupational therapy, the highest-impact first purchases are: a crash pad or foam pit (for safe jumping and proprioceptive input), a therapy ball or peanut ball (for core strengthening and vestibular input), and a set of resistance bands or TheraBands. These three items cost under $300 total and support a wide range of therapeutic activities."},{"question":"Should I design the therapy room myself or hire a professional?","answer":"If your child receives occupational or physical therapy, involve their therapist in the planning. Therapists can specify equipment, spacing requirements, and layout based on your child''s treatment goals. For the build itself, ceiling-mounted equipment like swings and climbing walls should be installed by a qualified contractor. Organizations like Sunshine on a Ranney Day provide professional design and construction at no cost for qualifying families."}],"ctaHeading":"Let us build a therapy room for your child","ctaText":"We''ve built over 45 therapy rooms in family homes across greater Atlanta — designed by professionals, built by volunteers, at no cost to families.","ctaPrimaryLink":"/apply/","ctaPrimaryLabel":"Apply for a Makeover","ctaSecondaryLink":"/donate/","ctaSecondaryLabel":"Fund a Therapy Room","featured":true,"order":3}');
INSERT OR REPLACE INTO site_config (key, data) VALUES ('settings', '{"name":"Sunshine on a Ranney Day","shortName":"SOARD","tagline":"Dreams Built Here","ein":"45-4773997","address":{"street":"250 Hembree Park Drive, Suite 106","city":"Roswell","state":"GA","zip":"30076"},"phone":"770.990.2434","email":"info@soardcharity.com","social":{"facebook":"https://www.facebook.com/sunshineonaranneyday","instagram":"https://www.instagram.com/sunshineonaranneyday","youtube":"https://www.youtube.com/@sunshineonaranneyday","tiktok":"https://www.tiktok.com/@sunshineonaranneyday"},"homeHero":{"eyebrow":"501(c)(3) Nonprofit · Atlanta, GA · Since 2012","headlineLine1":"Building <em>dreams</em>,","headlineLine2":"one room at a time","lead":"We create life-changing spaces for children with special needs — dream bedrooms, accessible bathrooms, and therapy rooms — all at <strong>no cost to families</strong>.","cta1Label":"Give Today","cta1Link":"/donate","cta2Label":"See Our Work ↓","cta2Link":"#stories"},"featuredKidSlug":"adrian","kidShowcase":[{"slug":"liam","cfId":"kids/liam/hero"},{"slug":"sophia","cfId":"kids/sophia/hero"},{"slug":"jackson","cfId":"kids/jackson/hero"},{"slug":"griffin","cfId":"kids/griffin/hero"},{"slug":"madison","cfId":"kids/madison/hero"},{"slug":"harper","cfId":"kids/harper/hero"},{"slug":"noah","cfId":"kids/noah/hero"},{"slug":"summer","cfId":"kids/summer/hero"}],"sectionPhotos":{"missionMain":"kids/eli/photo-01","missionAccent":"kids/georgia/photo-01","storyPhoto":"kids/zyah/hero","roomBedroom":"kids/griffin/hero","roomBath":"kids/zyah/hero","roomTherapy":"kids/jackson/hero"},"partnerLogos":[{"id":"partners/gas-south","name":"Gas South"},{"id":"partners/randall-paulson","name":"Randall Paulson"},{"name":"Kids R Kids Foundation","id":"partners/kids-r-kids"},{"id":"partners/cambria","name":"Cambria"},{"id":"partners/mohawk","name":"Mohawk"},{"id":"partners/jackson-healthcare","name":"Jackson Healthcare"},{"id":"partners/crosby-design-group","name":"Crosby Design Group"},{"name":"Msi","id":"partners/msi"},{"id":"partners/cr-construction","name":"CR Construction"},{"id":"partners/stag-partners","name":"Stag Partners"}]}');
INSERT OR REPLACE INTO site_config (key, data) VALUES ('our-story', '{"stats":{"totalKids":132,"totalRooms":106,"years":14,"communityKids":17000},"images":{"hero":"about/room-reveal-group","founder":"about/founders-reunion-2026","reveal":"kids/griffin/hero","community":"kids/jackson/hero","store":"about/sunny-ranney-storefront","gracie":"about/gracie","tripp":"about/tripp-family"},"hero":{"label":"Our Story","heading":"Changing lives, room by room, <em>since&nbsp;2012</em>.","lead":"Sunshine on a Ranney Day transforms the lives of children with special needs by creating dream spaces that bring comfort, joy, and independence — all at <strong>no cost to families</strong>."},"founders":{"label":"How It Began","heading":"A sermon, a calling, and a room that changed <em class=\"highlight\">everything</em>.","paragraphs":["In 2012, inspired by a church sermon, Peter and Holly Ranney felt a deep calling to use their God-given talents to serve others. With a vision rooted in love, purpose, and creativity, <strong>Sunshine on a Ranney Day</strong> was born — founded on the belief that every child deserves a space that reflects their personality, brings them joy, and supports their unique needs.","The very first makeover was for 11-year-old Mathew, who dreamed of spending his final days in a military-themed bunker bedroom. That room became more than just a space — it became a sanctuary. His story profoundly moved the Ranneys and solidified the impact that a thoughtfully designed room could have on a child''s life and family.","It was the beginning of something much bigger."]},"turningPoint":{"label":"A National Moment","heading":"Then the world met <em class=\"highlight\">Tripp</em>.","paragraphs":["Soon after, the world was introduced to Tripp Halstead, a young boy whose story captured hearts across the country after a traumatic brain injury. When Sunshine on a Ranney Day completed a whole-home makeover for Tripp, 1.6 million people tuned in to watch the reveal live on WSB-TV.","The national attention helped shine a light on the mission and expand the reach of the organization. Tripp''s joyful spirit and incredible resilience left a lasting legacy — and further inspired the work still being done today."]},"milestones":[{"year":"2012","title":"The First Room","desc":"Inspired by a church sermon, Peter and Holly Ranney build their first room — a military-themed bedroom for 11-year-old Mathew.","image":""},{"year":"2013","title":"Tripp Halstead","desc":"A whole-home makeover for Tripp captures 1.6 million viewers on a WSB-TV livestream, launching SOARD into the national spotlight.","image":""},{"year":"2016","title":"The Today Show","desc":"Peter and Holly appear on NBC''s Today Show for their renovation of parent sleep rooms at Children''s Healthcare of Atlanta.","image":""},{"year":"2018","title":"Braves Community Heroes","desc":"Holly and Peter are honored as Atlanta Braves Community Heroes at SunTrust Park alongside Dansby Swanson and Freddie Freeman.","image":""},{"year":"2020","title":"Sunny & Ranney Opens","desc":"SOARD opens a nonprofit home furnishings store in Roswell, with profits funding room makeovers for kids.","image":""},{"year":"2021","title":"Women Making a Mark","desc":"Atlanta Magazine honors Holly as one of their \"Women Making a Mark\" for her impact on the community.","image":""},{"year":"2024","title":"100+ Rooms","desc":"SOARD crosses the 100-room milestone, having served over 130 children and impacted 17,000+ through community projects.","image":""}],"ribbon":[{"value":"{totalRooms}+","label":"Room Makeovers"},{"value":"{totalKids}+","label":"Children Served"},{"value":"{communityKids}+","label":"Kids Impacted"},{"value":"100%","label":"Volunteer Run"}],"mascot":{"label":"Our Mascot","heading":"Meet <em class=\"highlight\">Gracie the Pig</em>, the heart and spirit of SOARD.","paragraphs":["Gracie was inspired by an unforgettable wedding gift — when Peter surprised Holly with a baby pot-bellied pig named Gracie. What started as a unique and heartfelt gesture has since grown into something magical.","Over the years, Gracie has transformed into our golden, high-flying mascot, soaring above the clouds in her signature cape, always on the lookout for children and families in need of a little extra sunshine.","With her trusty handsaw and a heart full of hope, Gracie leads her team of Sunshiners to build wheelchair-accessible bathrooms, dream bedrooms, and in-home therapy spaces — spaces that bring comfort, independence, and joy to children facing daily challenges."],"tagline":"She''s a reminder that with creativity, compassion, and a whole lot of heart, <strong>anything is possible with a little bit of Sunshine.</strong>"},"store":{"label":"Sustaining the Mission","heading":"Shopping that builds <em class=\"highlight\">dream rooms</em>.","paragraphs":["In 2020, Sunshine on a Ranney Day took a bold step to sustain its mission by opening <strong><a href=\"https://sunnyandranney.com\" target=\"_blank\" rel=\"noopener noreferrer\">Sunny & Ranney</a></strong>, a nonprofit home furnishings and décor store in Roswell, GA.","The shop features all brand-new, designer home goods and furniture, with profits going to fund custom renovations for children with special needs."]},"today":{"label":"Where We Are Today","heading":"What began as a simple idea has become a <em class=\"highlight\">movement</em>.","body":"Thanks to the unwavering support of donors, partners, and customers, Sunshine on a Ranney Day has grown into a community-driven force for good — touching the lives of more than 17,000 children and families across the greater Atlanta area. What started as a single room has become a beacon of hope, bringing comfort, dignity, independence, and joy to children who deserve nothing less than a space to thrive."},"finale":{"heading":"Be part of the <em>next</em> chapter.","body":"Every donation, every volunteer hour, every shared story builds another dream room for a child who needs it most."}}');
INSERT OR REPLACE INTO site_config (key, data) VALUES ('faq', '{"categories":[{"id":"donations","label":"Donations","showOnDonatePage":true},{"id":"about","label":"About SOARD","showOnDonatePage":false},{"id":"rooms","label":"Room Makeovers","showOnDonatePage":false},{"id":"families","label":"For Families","showOnDonatePage":false}],"items":[{"id":"tax-deductible","question":"Is my donation tax-deductible?","answer":"Yes. Sunshine on a Ranney Day is a registered 501(c)(3) nonprofit (EIN 45-4773997). You''ll receive a tax receipt from Zeffy immediately after donating.","category":"donations","order":1},{"id":"zeffy-fees","question":"Are there processing fees on my donation?","answer":"Zeffy is a free platform for nonprofits — they charge zero processing fees. Your donation goes directly to funding room materials, labor, and design for children''s spaces.","category":"donations","order":2},{"id":"monthly-donation","question":"Can I set up a monthly recurring donation?","answer":"Absolutely. In the donation form above, simply toggle to \"Monthly\" before selecting your amount. Monthly gifts help us plan future room makeovers with greater confidence.","category":"donations","order":3},{"id":"donate-materials","question":"Can I donate materials or services instead?","answer":"Yes! We partner with contractors, designers, and suppliers across Atlanta. Visit our <a href=\"/get-involved\">Get Involved</a> page to learn about partnership opportunities.","category":"donations","order":4},{"id":"room-cost","question":"How much does a typical room makeover cost?","answer":"Room costs vary based on scope — a dream bedroom averages $8,000–$12,000, while an accessible bathroom can run $10,000–$15,000. Every dollar donated goes toward these transformations.","category":"donations","order":5},{"id":"what-is-soard","question":"What is Sunshine on a Ranney Day?","answer":"Sunshine on a Ranney Day (SOARD) is a 501(c)(3) nonprofit that creates life-changing home makeovers — dream bedrooms, accessible bathrooms, and therapy rooms — for children with special needs in the greater Atlanta area, all at no cost to families.","category":"about","order":1},{"id":"how-long","question":"How long has SOARD been operating?","answer":"We''ve been building rooms and changing lives since 2012. To date, we''ve completed over 106 rooms for more than 132 children across metro Atlanta.","category":"about","order":2},{"id":"who-runs","question":"Who runs the organization?","answer":"SOARD was co-founded by Peter and Kristen Ranney. Our team includes dedicated volunteers, board members, and a network of construction and design partners. Visit our <a href=\"/about/leadership\">Leadership</a> page to meet the team.","category":"about","order":3},{"id":"room-types","question":"What types of rooms do you build?","answer":"We build three types of spaces: dream bedrooms designed around a child''s interests, accessible bathrooms that promote independence, and therapy rooms for at-home physical or occupational therapy.","category":"rooms","order":1},{"id":"how-long-room","question":"How long does a room makeover take?","answer":"Most rooms are completed in 1–3 days during a scheduled build weekend. The planning and design phase typically takes 4–6 weeks before the build.","category":"rooms","order":2},{"id":"who-builds","question":"Who actually builds the rooms?","answer":"Our rooms are built by a combination of licensed contractors, professional designers, and skilled volunteers. Every project is managed to ensure safety and quality.","category":"rooms","order":3},{"id":"how-apply","question":"How do families apply for a room makeover?","answer":"Families can apply through our <a href=\"/apply\">Application</a> page. We accept applications year-round and select children based on need and available resources.","category":"families","order":1},{"id":"who-qualifies","question":"Who qualifies for a room makeover?","answer":"We serve children with special needs (physical, developmental, or medical) in the greater Atlanta area. Families must demonstrate financial need and own or have permission to modify their home.","category":"families","order":2},{"id":"any-cost","question":"Is there any cost to the family?","answer":"None. Every room makeover is provided completely free of charge to the family. All materials, labor, and design are funded through donations and partnerships.","category":"families","order":3}]}');
INSERT OR REPLACE INTO site_config (key, data) VALUES ('media', '{"bio":{"orgName":"Sunshine on a Ranney Day","founded":"2012","founders":"Peter and Holly Ranney","location":"Roswell, GA","ein":"45-4773997","website":"sunshineonaranneyday.com","boilerplate":"Sunshine on a Ranney Day is a 501(c)(3) nonprofit founded in 2012 by Peter and Holly Ranney, based in Roswell, GA."},"mission":"Sunshine on a Ranney Day is a nonprofit organization that renovates homes for children with special needs using top of the line construction and design. Through partnerships and donors we provide no cost wheelchair accessible bathrooms, dream bedrooms and in-home therapy rooms.","who":"Sunshine on a Ranney Day was founded in early 2012 by Peter and Holly Ranney after being inspired by a church sermon to use their resources to help others. The first makeover was completed in July 2012 for a child named Mathew.","founderStory":"In 2012, inspired by a church sermon, Peter and Holly Ranney found their calling to use their God-given talents and resources to help others. Sunshine on a Ranney Day was created with the idea that every child should have their own unique space.\n\nSunshine on a Ranney Day''s first makeover was completed for 11-year-old Mathew, who wanted to spend his last days in his military-themed bunker bedroom. Mathew''s makeover and passing showed how impactful a makeover could be on a child''s life. This experience helped shape Sunshine on a Ranney Day into what it is today.","contactEmail":"info@soardcharity.com","socialLinks":{"facebook":"https://www.facebook.com/sunshineonaranneyday","instagram":"https://www.instagram.com/sunshineonaranneyday","youtube":"https://www.youtube.com/@sunshineonaranneyday"},"metaDescription":"Official media kit for Sunshine on a Ranney Day — bio, mission statement, founder''s story, logos, and brand assets for press and media use."}');
